('notice_latest', 'O:39:\"Illuminate\\Database\\Eloquent\\Collection\":2:{s:8:\"\0*\0items\";a:2:{i:0;O:17:\"App\\Models\\Notice\":33:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:7:\"notices\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:16:{s:2:\"id\";i:2;s:5:\"title\";s:164:\"ফ্রি প্রশিক্ষণ diploma In Marine, Mechanical Power, Automobile ইঞ্জিনিয়ারিং সম্পূর্ন করা ব\";s:4:\"slug\";s:45:\"diploma-in-marine-mechanical-power-automobile\";s:11:\"description\";s:1647:\"★ফ্রি প্রশিক্ষণ diploma In Marine, Mechanical Power, Automobile ইঞ্জিনিয়ারিং সম্পূর্ন করা বেকার তরুনদের কর্মসংস্থানের লক্ষে এশিয়ান ডেভেলপমেন্ট ব্যাংক এবং বাংলাদেশ সরকারের অর্থ-মন্ত্রণালয়ের সহযোগিতায় SICIP - AEOSIB - NIET এর পরিচালনায় আগামী মে ২০২৬ইং তারিখ থেকে ট্রেনিং কার্যক্রম ৫ম ব্যাচ শুরু হতে যাচ্ছে।\r\nআসন সংখ্যা - ২৫ জন করে। (মেয়াদ-৪মাস)\r\nকোর্সের শর্ত : প্রশিক্ষন শেষে প্রশিক্ষণার্থীর ১০০% চাকরীর মানসিকতা থাকতে হবে।\r\nযোগাযোগ: \r\nNational Institute of Engineering and Technology [NIET]\r\n⛔লোকেশন :কালিবাড়ি, দুপ্তরা, আড়াইহাজার, নারায়ণগঞ্জ।\r\nযোগাযোগ : +8801992077023\r\n\r\n#diploma #DiplomaEngineering #engineering #engineerjob #Polytechnic #marineengineering #mechanical #power #automobile #mechanicalengineering #Dhaka #Chittagong #Khulna #bdjobs #jobs #everyoneactive #everyone #everyoneシ゚ #everyonehighlightsfollowers #everyonehighlights #nonfollowersシ゚ #foryouシ #everyonefollowers #foryouシpage #foryoupage #foryoupageシ #Bangladesh\";s:5:\"image\";s:87:\"notices/assessmentbd-notice-diploma-in-marine-mechanical-power-automobile-20260524.webp\";s:8:\"category\";s:8:\"Training\";s:6:\"source\";s:48:\"National Institute of Engineering and Technology\";s:4:\"tags\";N;s:9:\"seo_title\";s:64:\"Free Diploma Engi