('settings_all', 'a:83:{s:15:\"announcement_bg\";s:7:\"#0b57d0\";s:20:\"announcement_enabled\";s:1:\"1\";s:18:\"announcement_speed\";s:6:\"normal\";s:17:\"announcement_text\";s:186:\"NSDA Assessment-এর প্রস্তুতির জন্য MCQ এবং Written প্রশ্ন ব্যাংক পেতে সাবস্ক্রাইব করুন\";s:16:\"basic_plan_price\";s:2:\"99\";s:12:\"bkash_number\";s:11:\"01778654560\";s:10:\"bkash_type\";s:10:\"Send Money\";s:13:\"contact_email\";s:24:\"assessmenttvet@gmail.com\";s:7:\"faq_1_a\";s:391:\"প্ল্যাটফর্মে রেজিস্ট্রেশন করা সম্পূর্ণ ফ্রি। তবে যেকোনো কোর্সের প্রশ্ন ব্যাংক এবং মক টেস্টে অংশ নিতে মাসে ১০০ টাকা ফি দিয়ে সাবস্ক্রাইব করতে হবে।\";s:7:\"faq_1_q\";s:51:\"রেজিস্ট্রেশন ফি কত?\";s:7:\"faq_2_a\";s:325:\"আপনার রেফার কোড দিয়ে কাউকে ইনভাইট করলে সে প্রথম কোর্স কেনার সময় ১০% ডিসকাউন্ট পাবে এবং আপনার অ্যাকাউন্টে ১০ টাকা যোগ হবে।\";s:7:\"faq_2_q\";s:83:\"রেফারেল সিস্টেম কিভাবে কাজ করে?\";s:7:\"faq_3_a\";s:156:\"হ্যাঁ, অবশ্যই! আমাদের প্ল্যাটফর্মটি ১০০% মোবাইল ফ্রেন্ডলি।\";s:7:\"faq_3_q\";s:100:\"আমি কি মোবাইল থেকে পরীক্ষা দিতে পারবো?\";s:18:\"footer_description\";s:270:\"NSDA লেভেল অ্যাসেসমেন্ট পরীক্ষার জন্য বাংলাদেশের সবচেয়ে আধুনিক এবং কার্যকরী প্র্যাকটিস প্ল্যাটফর্ম।\";s:15:\"gateway_sandbox\";s:1:\"0\";s:14:\"gemini_api_key\";s:39:\"AIzaSyB9eiaksnulNQUO6MK0lp_cENvQEqvz4gw\";s:10:\"hero_badge\";s:30:\"#1 NSDA Assessment Tools in BD\";s:12:\"hero_heading\";s:160:\"বাংলাদেশের এক    নম্বর NSDA অ্যাসেসমেন্ট প্রস্তুতি প্ল্যাটফর্ম\";s:18:\"hero_student_count\";s:3:\"+1k\";s:12:\"hero_subtext\";s:464:\"শুধু প্র্যাকটিক্যাল নয়, CS অনুযায়ী সম্পূর্ণ MCQ ও Written প্রশ্নব্যাংক প্র্যাকটিস করুন আপনার মোবাইলেই। নিজেকে আগে থেকেই যাচাই করে নিন এবং প্রথমবারেই \'Competent (C)\' সার্টিফিকেট অর্জন করুন।\";s:24:\"landing_comparison_image\";s:44:\"uploads/landing/comparison_6a2946482fe7c.jpg\";s:12:\"landing_faqs\";s:2153:\"[{\"q\":\"সব প্রশ্ন কি রিয়েল অ্যাসেসমেন্ট থেকে নেওয়া?\",\"a\":\"আমাদের প্রশ্নব্যাংক CS, UoC, অ্যাসেসমেন্ট প্যাটার্ন এবং এক্সপার্ট ট্রেইনারদের মতামতের ভিত্তিতে তৈরি। এগুলো শতভাগ রিয়েল না হলেও অ্যাসেসমেন্ট পাসের জন্য যথেষ্ট প্রস্তুতি দেয়।\"},{\"q\":\"এখানে কি প্র্যাকটিক্যাল ট্রেনিং করানো হয়?\",\"a\":\"না। AssessmentBD শুধুমাত্র Written ও MCQ প্রস্তুতির জন্য একটি ডিজিটাল প্ল্যাটফর্ম। কোনো প্র্যাকটিক্যাল ট্রেনিং প্রদান করা হয় না।\"},{\"q\":\"যেকোনো ডিভাইস থেকে ব্যবহার করা যাবে?\",\"a\":\"হ্যাঁ, যেকোনো স্মার্টফোন, ট্যাবলেট বা কম্পিউটার থেকে লগইন করে প্র্যাকটিস করা যাবে।\"},{\"q\":\"৫০% মানি-ব্যাক গ্যারান্টি কীভাবে কাজ করে?\",\"a\":\"Pro প্ল্যান নিয়ে ফাইনাল অ্যাসেসমেন্টে NYC হলে শর্তসাপেক্ষে ৫০% ক্যাশব্যাক পাবেন। বিস্তারিত আমাদের Refund Policy পেজে আছে।\"},{\"q\":\"পেমেন্ট করার পর কখন Access পাবো?\",\"a\":\"Online Gateway দিয়ে পেমেন্ট করলে সাথে সাথে। bKash\\/Nagad-এ করলে Admin Verify করার পর — সাধারণত ৩০ মিনিট থেকে কয়েক ঘণ্টার মধ্যে।\"}]\";s:16:\"landing_features\";s:975:\"[{\"title\":\"MCQ Question Bank\",\"desc\":\"CS ভিত্তিক পূর্ণাঙ্গ MCQ সেট — প্রতিটি Unit-এর জন্য\"},{\"title\":\"Written Question Bank\",\"desc\":\"গুরুত্বপূর্ণ লিখিত প্রশ্ন ও সাজেশন\"},{\"title\":\"উত্তর ও ব্যাখ্যা\",\"desc\":\"প্রতিটি প্রশ্নের সঠিক উত্তর ও বিস্তারিত ব্যাখ্যা\"},{\"title\":\"Model Assessment\",\"desc\":\"রিয়েল-টাইম মডেল পরীক্ষা — নিজেকে মূল্যায়ন করুন\"},{\"title\":\"Instant Result\",\"desc\":\"পরীক্ষা শেষে সাথে সাথেই স্বয়ংক্রিয় ফলাফল\"},{\"title\":\"Progress Dashboard\",\"desc\":\"দুর্বলতা চিহ্নিত করুন — উন্নতি ট্র্যাক করুন\"}]\";s:20:\"landing_hero_heading\";s:104:\"NSDA Assessment Preparation<br><span style=\"color:var(--blue-700);\">এখন আরও সহজ</span>\";s:18:\"landing_hero_image\";s:38:\"uploads/landing/hero_6a2a3c18b8148.png\";s:20:\"landing_hero_subtext\";s:314:\"MCQ Question Bank, Written Question, উত্তর, ব্যাখ্যা এবং Model Assessment —<br class=\"hidden sm:block\"> <strong style=\"color:#1e3a5f;\">সব এক জায়গায়।</strong> হাজারো TVET Trainee-র পছন্দের প্ল্যাটফর্ম।\";s:15:\"landing_reviews\";s:1056:\"[{\"name\":\"মো. রাহাত হোসেন\",\"role\":\"Level 3 Trainee — Computer Operation\",\"quote\":\"এখানে রেগুলার পরীক্ষা দিয়ে আমার কনফিডেন্স অনেক বেড়েছে। প্রশ্নগুলো সত্যিই স্ট্যান্ডার্ড।\"},{\"name\":\"তাসলিমা বেগম\",\"role\":\"Level 4 Trainee — Graphic Design\",\"quote\":\"ফাইনাল অ্যাসেসমেন্টের আগে মডেল টেস্ট দিয়ে নিজের ভুলগুলো ধরতে পেরেছিলাম। প্রথমবারেই পাস করলাম।\"},{\"name\":\"জুবায়ের আহমেদ\",\"role\":\"Level 3 Trainee — Electrical Installation\",\"quote\":\"লিখিত প্রশ্নের উত্তর ও ব্যাখ্যাগুলো খুব সুন্দর সাজানো। আমি প্রথমবারেই Competent হয়েছি।ok\"}]\";s:21:\"landing_slider_images\";s:185:\"[\"uploads\\/landing\\/landing_6a2a3c5bdb7f9.png\",\"uploads\\/landing\\/landing_6a2a3c62e1371.png\",\"uploads\\/landing\\/landing_6a2a3c6b85b70.png\",\"uploads\\/landing\\/landing_6a2a3c72c9637.png\"]\";s:11:\"mail_driver\";s:6:\"resend\";s:15:\"mail_encryption\";s:3:\"tls\";s:17:\"mail_from_address\";s:25:\"no-reply@assessmentbd.com\";s:14:\"mail_from_name\";s:12:\"AssessmentBD\";s:9:\"mail_host\";N;s:13:\"mail_password\";s:10:\"Admin@1234\";s:9:\"mail_port\";s:3:\"587\";s:13:\"mail_username\";s:19:\"jitsaiful@gmail.com\";s:12:\"nagad_number\";s:11:\"01778654560\";s:14:\"openai_api_key\";N;s:15:\"payment_gateway\";s:8:\"piprapay\";s:16:\"piprapay_api_key\";s:50:\"729ff93491eec5dd250b1a05e090eb93ec3bdce8b81faf6e16\";s:17:\"piprapay_base_url\";s:28:\"https://pay.assessmentbd.com\";s:14:\"pricing_amount\";s:9:\"১০০\";s:16:\"pricing_features\";s:228:\"সম্পূর্ণ প্রশ্ন ব্যাংকের অ্যাক্সেস\r\nআনলিমিটেড মক টেস্ট\r\nইনস্ট্যান্ট রেজাল্ট ও সলিউশন\";s:14:\"pricing_period\";s:59:\"প্রতি কোর্স / প্রতি মাস\";s:17:\"pricing_plan_name\";s:12:\"Premium Plan\";s:21:\"pricing_referral_text\";s:83:\"🎁 রেফার কোড থাকলে ১০% ডিসকাউন্ট!\";s:14:\"pro_plan_price\";s:3:\"299\";s:22:\"referral_discount_type\";s:7:\"percent\";s:23:\"referral_discount_value\";s:2:\"10\";s:16:\"referral_enabled\";s:1:\"1\";s:22:\"referral_reward_amount\";s:2:\"10\";s:26:\"referral_reward_usable_for\";s:6:\"course\";s:14:\"resend_api_key\";s:36:\"re_9NvMyaxU_3PpyYHuhuTTC6GAwhSvKHLM5\";s:19:\"resource_app_screen\";s:25:\"resources/app_screen.webp\";s:15:\"resource_banner\";s:29:\"uploads/resources/banner.webp\";s:14:\"resource_bkash\";s:19:\"resources/bkash.png\";s:16:\"resource_favicon\";s:21:\"resources/favicon.png\";s:22:\"resource_hero_avatar_1\";s:28:\"resources/hero_avatar_1.webp\";s:22:\"resource_hero_avatar_2\";s:28:\"resources/hero_avatar_2.webp\";s:22:\"resource_hero_avatar_3\";s:28:\"resources/hero_avatar_3.webp\";s:13:\"resource_logo\";s:18:\"resources/logo.png\";s:14:\"resource_nagad\";s:19:\"resources/nagad.png\";s:15:\"seo_description\";s:336:\"বাংলাদেশের সেরা NSDA Assessment Tools এবং Question Bank। রিয়েল-টাইম মক টেস্ট, অ্যান্টি-চিট সিস্টেম এবং ১০০% মোবাইল ফ্রেন্ডলি পরিবেশে প্রস্তুতি নিন।\";s:12:\"seo_keywords\";s:72:\"nsda, nsda tools, assessment question, nsda level course, online exam bd\";s:9:\"seo_title\";s:60:\"NSDA Exam Prep | NSDA Assessment Question & Tools Bangladesh\";s:12:\"site_address\";s:17:\"Dhaka, Bangladesh\";s:10:\"site_email\";s:24:\"assessmenttvet@gmail.com\";s:9:\"site_faqs\";s:3611:\"[{\"section\":\"Home\",\"q\":\"AssessmentBD কী?\",\"a\":\"AssessmentBD হলো NSDA লেভেল অ্যাসেসমেন্ট পরীক্ষার প্রস্তুতির জন্য বাংলাদেশের একটি প্রিমিয়াম অনলাইন প্ল্যাটফর্ম।\"},{\"section\":\"Home\",\"q\":\"আমি কীভাবে পরীক্ষা দেওয়া শুরু করব?\",\"a\":\"প্রথমে একটি ফ্রি অ্যাকাউন্ট তৈরি করুন, এরপর আপনার কাঙ্ক্ষিত Occupation নির্বাচন করে প্যাকেজ সাবস্ক্রাইব করুন।\"},{\"section\":\"Home\",\"q\":\"Basic এবং Pro Plan এর মধ্যে পার্থক্য কী?\",\"a\":\"Basic প্ল্যানে আপনি ১ মাসের অ্যাক্সেস পাবেন, আর Pro প্ল্যানে ৩ মাসের অ্যাক্সেস, এক্সপার্ট সাপোর্ট এবং রিফান্ড পলিসি পাবেন।\"},{\"section\":\"Pricing\",\"q\":\"Assessment-এ NYC (Not Yet Competent) হলে refund কীভাবে পাব?\",\"a\":\"আপনি যদি Pro subscriber হন এবং আমাদের মডেল টেস্টগুলোতে পাস করার পরও মূল পরীক্ষায় NYC হন, তাহলে অফিসিয়াল রেজাল্ট শিট দেখালে আমরা ৫০% রিফান্ড করে দেব।\"},{\"section\":\"Pricing\",\"q\":\"পেমেন্ট কীভাবে করব?\",\"a\":\"আপনি বিকাশ, নগদ অথবা যেকোনো মোবাইল ব্যাংকিং এর মাধ্যমে খুব সহজেই পেমেন্ট করতে পারবেন।\"},{\"section\":\"Pricing\",\"q\":\"এক সাবস্ক্রিপশনে কি সব কোর্সের অ্যাক্সেস পাব?\",\"a\":\"না, আপনাকে আপনার নির্দিষ্ট Occupation বা কোর্সের জন্য আলাদাভাবে সাবস্ক্রাইব করতে হবে।\"},{\"section\":\"About\",\"q\":\"AssessmentBD কি NSDA-এর অফিসিয়াল সাইট?\",\"a\":\"না। AssessmentBD সম্পূর্ণ একটি বেসরকারি শিক্ষামূলক প্ল্যাটফর্ম এবং NSDA বা বাংলাদেশ কারিগরি শিক্ষা বোর্ডের সাথে সরাসরি অধিভুক্ত নয়। আমরা শুধু প্রস্তুতিতে সাহায্য করি।\"},{\"section\":\"About\",\"q\":\"কোর্সের মেয়াদ কতদিন থাকে?\",\"a\":\"আপনার কেনা প্যাকেজের ওপর ভিত্তি করে মেয়াদ ১ থেকে ৩ মাস পর্যন্ত হতে পারে।\"},{\"section\":\"About\",\"q\":\"আমি কি মোবাইল থেকে পরীক্ষা দিতে পারব?\",\"a\":\"হ্যাঁ! আমাদের প্ল্যাটফর্মটি ১০০% মোবাইল-বান্ধব, আপনি যেকোনো ডিভাইস (মোবাইল, ট্যাবলেট বা পিসি) থেকে খুব সহজেই পরীক্ষা দিতে পারবেন।\"}]\";s:9:\"site_logo\";s:18:\"resources/logo.png\";s:10:\"site_phone\";s:14:\"+8801603409757\";s:16:\"site_phone_hours\";s:58:\"সকাল ১০টা থেকে রাত ৮টা\";s:13:\"site_whatsapp\";s:11:\"01603409757\";s:11:\"skills_list\";s:0:\"\";s:11:\"sms_api_key\";s:20:\"Q2jJFse1LdMKGLd7EI1d\";s:13:\"sms_sender_id\";s:13:\"8809617618687\";s:15:\"social_facebook\";s:38:\"https://www.facebook.com/assessmentbd/\";s:15:\"social_linkedin\";N;s:14:\"social_youtube\";N;s:12:\"tawk_enabled\";s:1:\"1\";s:16:\"tawk_property_id\";s:24:\"6a127b56fb330b1c3281023e\";s:15:\"tawk_raw_script\";s:446:\"<!--Start of Tawk.to Script-->\r\n<script type=\"text/javascript\">\r\nvar Tawk_API=Tawk_API||{}, Tawk_LoadStart=new Date();\r\n(function(){\r\nvar s1=document.createElement(\"script\"),s0=document.getElementsByTagName(\"script\")[0];\r\ns1.async=true;\r\ns1.src=\'https://embed.tawk.to/6a127b56fb330b1c3281023e/1jpc33jfe\';\r\ns1.charset=\'UTF-8\';\r\ns1.setAttribute(\'crossorigin\',\'*\');\r\ns0.parentNode.insertBefore(s1,s0);\r\n})();\r\n</script>\r\n<!--End of Tawk.to Script-->\";s:14:\"tawk_widget_id\";s:9:\"1jpc33jfe\";}', 2096554452);
