INSERT INTO `courses` (`id`, `title`, `level`, `category`, `sector`, `occupation`, `slug`, `description`, `seo_title`, `seo_description`, `seo_keywords`, `thumbnail`, `is_active`, `is_featured`, `featured_label`, `sort_order`, `created_at`, `updated_at`) VALUES
(1, '2D & 3D CAD Level 3', 'Level 3', 'Construction', 'Construction', '2D & 3D CAD', '2d-3d-cad-level-3', 'Unlock your potential in advanced 2D and 3D CAD design with AssessmentBD\'s comprehensive Level 3 course. This program is meticulously crafted to equip you with expert-level proficiency in complex modeling, assembly design, drafting, and advanced surfacing techniques. You will master industry-standard CAD software features, understand intricate design principles, and develop the practical skills necessary to create sophisticated engineering drawings and models for real-world applications.\r\n\r\nOur course specifically prepares you to confidently ace the NSDA 2D & 3D CAD Level 3 CBT&A assessment. Through targeted modules, you\'ll gain extensive practice with various question formats, including challenging written questions and critical MCQ questions, utilizing our specialized practice tools and simulated NSDA question environment. We break down the syllabus into easy-to-understand sections, ensuring you\'re not just learning CAD, but strategically preparing to excel in the NSDA exam, securing your certification and opening doors to enhanced career opportunities in Bangladesh.', '2D & 3D CAD Level 3 Mastery | Pass NSDA Exam with Confidence', 'Master advanced 2D & 3D CAD Level 3 with AssessmentBD. Our course provides comprehensive training, essential tools, and practice for NSDA CBT&A exams, including written & MCQ questions. Ensure your success!', '2D CAD Level 3, 3D CAD Level 3, NSDA CAD exam, CBT&A CAD training, CAD design tools, CAD written questions, CAD MCQ questions, NSDA question bank, CAD assessment platform, skill development Bangladesh', NULL, 1, 0, NULL, 1, '2026-05-20 02:44:11', '2026-05-22 11:01:14'),
(2, '2D Animation Asset Creating For Freelancing Level 2', 'Level 2', 'Information And Communication Technology', 'Information And Communication Technology', '2D Animation Asset Creating For Freelancing', '2d-animation-asset-creating-for-freelancing-level-2', 'এই 2D Animation Asset Creating for Freelancing Level 2 কোর্সে আপনি শিখবেন কিভাবে প্রফেশনাল 2D অ্যানিমেশন অ্যাসেট তৈরি করতে হয়। বিভিন্ন industry-standard tools ব্যবহার করে আপনি character design, background art, props সহ প্রয়োজনীয় সব asset তৈরি করা শিখবেন যা আপনার ফ্রিল্যান্সিং ক্যারিয়ারে অনেক হেল্প করবে।\r\n\r\nThis course আপনাকে NSDA CBT&A exam এর জন্য পুরোপুরি প্রস্তুত করবে। এখানে আপনি শুধু practical skills-ই শিখবেন না, বরং NSDA written question, MCQ question এবং practical exam-এর জন্য essential concepts গুলোও ভালোভাবে বুঝতে পারবেন। সফলভাবে NSDA অ্যাসেসমেন্ট পাশ করে আপনার সার্টিফিকেশন নিশ্চিত করুন!', '2D Animation Assets: Freelancing Level 2 (NSDA Exam Prep)', 'Master 2D animation asset creation for freelancing! Learn industry tools & techniques to build your portfolio. Prepare for NSDA written & MCQ questions. Enroll now!', '2D animation asset creation, freelancing tools, NSDA exam preparation, CBT&A assessment Bangladesh, 2D animation jobs, written question practice, MCQ question bank, NSDA question pattern, digital art skills, animation course Bangladesh', NULL, 1, 0, NULL, 2, '2026-05-20 02:44:11', '2026-05-24 15:40:36'),
(3, '2D Animation For Freelancing Level 4', 'Level 4', 'Information And Communication Technology', 'Information And Communication Technology', '2D Animation For Freelancing', '2d-animation-for-freelancing-level-4', '2D Animation For Freelancing Level 4 কোর্স-এ আপনি শিখবেন কিভাবে প্রফেশনাল 2D অ্যানিমেশন তৈরি করতে হয়, যা আপনাকে ফ্রিল্যান্সিং করে আয় করার সুযোগ করে দেবে। এখানে আপনি অ্যানিমেশনের fundamental concepts, character design, background art এবং cutting-edge animation tools ব্যবহার করা শিখবেন। এই কোর্সটি আপনার ক্রিয়েটিভিটি বাড়াবে এবং আপনাকে গ্লোবাল ফ্রিল্যান্সিং মার্কেটে কাজ করার জন্য প্রস্তুত করবে।\r\n\r\nআমাদের এই কোর্সের মাধ্যমে আপনি NSDA (National Skills Development Authority) Level 4 পরীক্ষার জন্য সম্পূর্ণভাবে প্রস্তুত হবেন। আমরা আপনাকে written question, MCQ question এবং practical assessment-এর জন্য প্রয়োজনীয় সব টিপস ও ট্রিকস দেবো, যা আপনাকে NSDA certification পেতে সাহায্য করবে এবং আপনার ক্যারিয়ারে নতুন দিগন্ত উন্মোচন করবে।', '2D Animation L4: Freelancing & NSDA Exam Success', 'Master 2D Animation for Freelancing Level 4! Learn essential tools, techniques & prepare for your NSDA exam to launch a rewarding animation career. Enroll now!', '2D Animation Freelancing Level 4, NSDA 2D Animation Exam, CBT&A animation course, Animation tools & techniques, 2D animation written question, 2D animation MCQ question, NSDA question animation, Freelance animation career, Digital animation Bangladesh', NULL, 1, 0, NULL, 3, '2026-05-20 02:44:11', '2026-05-24 15:41:31'),
(4, '3D Animation Asset Creating For Freelancing Level 2', 'Level 2', 'Information And Communication Technology', 'Information And Communication Technology', '3D Animation Asset Creating For Freelancing', '3d-animation-asset-creating-for-freelancing-level-2', 'আপনি কি 3D অ্যানিমেশন ভালোবাসেন এবং ফ্রিল্যান্সিং করতে চান? আমাদের \'3D Animation Asset Creating For Freelancing Level 2\' কোর্সটি আপনার জন্য! এখানে আপনি অ্যাডভান্সড লেভেলের 3D মডেলিং, টেক্সচারিং এবং প্রপস তৈরি করা শিখবেন, যা গেম বা মুভিতে ব্যবহার হয়। এই কোর্সে industry-standard tools ব্যবহার করে বাস্তবসম্মত 3D অ্যাসেট বানানো শেখানো হবে, যা ফ্রিল্যান্সিং মার্কেটে আপনার চাহিদা বাড়াবে।\r\n\r\nএই কোর্সটি শুধু ফ্রিল্যান্সিংয়ের জন্যই নয়, NSDA (National Skills Development Authority) Level 2 CBT&A (Competency Based Training & Assessment) পরীক্ষার জন্যও আপনাকে প্রস্তুত করবে। আপনি শিখবেন কিভাবে NSDA-এর written question এবং MCQ question-এর জন্য প্রস্তুতি নিতে হয়। বাস্তব প্রজেক্টের মাধ্যমে আপনার দক্ষতা যাচাই করা হবে, যা আপনাকে সফলভাবে NSDA পরীক্ষায় পাশ করতে এবং একটি উজ্জ্বল ক্যারিয়ার গড়তে সাহায্য করবে।', '3D Animation Asset Creation: Freelance & NSDA Success L2', 'Unlock freelance potential! Master 3D animation asset creation (Level 2) for NSDA exam success. Learn practical tools & techniques with AssessmentBD.', '3D animation asset creation, freelance 3D animation, NSDA 3D animation, CBT&A 3D animation, 3D animation tools, NSDA written question, NSDA MCQ question, NSDA question, skill development Bangladesh', NULL, 1, 0, NULL, 4, '2026-05-20 02:44:11', '2026-05-24 15:42:29'),
(5, '3D Animation Characters Modelling For Freelancing Level 3', 'Level 3', 'Information And Communication Technology', 'Information And Communication Technology', '3D Animation Characters Modelling For Freelancing', '3d-animation-characters-modelling-for-freelancing-level-3', 'এই কোর্সটি আপনাকে 3D Animation Characters Modelling এর expert করে তুলবে। আপনি Blender, ZBrush সহ industry-standard modelling tools ব্যবহার করে realistic এবং stylized 3D characters বানানো শিখবেন। Freelancing marketplace-এ আপনার কাজ showcase করার জন্য portfolio তৈরি করতেও আমরা সাহায্য করব। Graphics, gaming, film industry-তে নিজের ক্যারিয়ার গড়তে এটিই আপনার প্রথম ধাপ।\r\n\r\nNSDA Level 3 CBT&A certification পেতে এটি আপনাকে ১০০% প্রস্তুত করবে। আমরা আপনাকে NSDA exam-এর জন্য essential concepts, practical skills এবং বিগত বছরের written question, MCQ question patterns নিয়ে বিস্তারিত আলোচনা করব। CBT&A-এর জন্য যে knowledge দরকার, তা হাতে-কলমে শেখানো হবে, যাতে আপনি confidence-এর সাথে পরীক্ষা দিতে পারেন এবং সহজেই পাস করেন।', 'Master 3D Character Modelling: Freelance & NSDA Level 3 Cert.', 'Learn 3D character modelling for freelancing. Master industry tools & techniques to create stunning models. Prepare for NSDA Level 3 CBT&A exam with our expert guidance. Start your animation career!', '3D Character Modelling, 3D Animation Freelancing, NSDA Level 3 CBT&A, Character Modelling Tools, NSDA Exam Questions, CBT&A Preparation, Written Question Practice NSDA, MCQ Question Bank NSDA, Blender 3D Course, Freelance 3D Artist Bangladesh', NULL, 1, 0, NULL, 5, '2026-05-20 02:44:11', '2026-05-23 21:01:52'),
(6, '3D Animation Product Visualization For Freelancing Level 3', 'Level 3', 'Information And Communication Technology', 'Information And Communication Technology', '3D Animation Product Visualization For Freelancing', '3d-animation-product-visualization-for-freelancing-level-3', 'আপনি কি 3D অ্যানিমেশন এবং প্রোডাক্ট ভিজ্যুয়ালাইজেশনে ক্যারিয়ার গড়তে চান? এই Level 3 কোর্সে শিখবেন কিভাবে stunning 3D product renders তৈরি করতে হয়। Blender, Maya বা Cinema 4D-এর মতো জনপ্রিয় 3D software-এর basic থেকে advanced techniques জানবেন। Product modeling, texturing, lighting, এবং rendering-এর practical skills অর্জন করবেন যা ফ্রিল্যান্সিং মার্কেটে আপনাকে এগিয়ে রাখবে।\r\n\r\nএই কোর্স আপনাকে শুধুমাত্র ফ্রিল্যান্সিং করে ভালো ইনকাম করতে সাহায্য করবে না, বরং আপনার 3D অ্যানিমেশন জ্ঞানকে NSDA (National Skill Development Authority) এর CBT&A (Competency Based Training & Assessment) স্ট্যান্ডার্ড অনুযায়ী প্রস্তুত করবে। আপনার অর্জিত দক্ষতা যাতে দেশের স্বীকৃত মানদণ্ডে যাচাই করা যায় এবং আপনি সফলভাবে NSDA পরীক্ষায় উত্তীর্ণ হয়ে আপনার ক্যারিয়ারকে আরও এক ধাপ এগিয়ে নিয়ে যেতে পারেন, তার জন্য এই কোর্সের প্রতিটি module ডিজাইন করা হয়েছে। Successful completion-এর পর আপনি আত্মবিশ্বাসের সাথে দেশী ও বিদেশী ক্লায়েন্টদের জন্য কাজ করতে পারবেন।', 'Master 3D Animation Product Visualization for Freelancing | Level 3', 'Unlock your freelance potential! Learn 3D Animation Product Visualization Level 3. Create stunning visuals, boost your portfolio, and launch a global career with AssessmentBD.', '3D animation freelancing, product visualization course, 3D design tools, NSDA skill assessment, CBT&A exam prep, MCQ questions 3D, written exam guide, 3D product rendering, level 3 certification', NULL, 1, 0, NULL, 6, '2026-05-20 02:44:11', '2026-05-27 07:04:12'),
(7, '3D Characters Animation For Freelancing Level 4', 'Level 4', 'Information And Communication Technology', 'Information And Communication Technology', '3D Characters Animation For Freelancing', '3d-characters-animation-for-freelancing-level-4', 'আপনি কি 3D Character Animation শিখে ফ্রিল্যান্সিং করতে চান? AssessmentBD-এর এই Level 4 কোর্সটি আপনার জন্য! এখানে আপনি Maya, Blender-এর মতো industry-standard tools ব্যবহার করে কিভাবে stunning 3D characters animate করতে হয় তা শিখবেন। Rigging থেকে rendering পর্যন্ত, প্রতিটি essential skill হাতে-কলমে শেখানো হবে, যা আপনাকে global freelance marketplace-এ competitive করে তুলবে।\r\n\r\nএই কোর্সটি বিশেষভাবে NSDA Level 4 পরীক্ষার জন্য ডিজাইন করা হয়েছে। আপনি শুধু animation skills-ই শিখবেন না, বরং NSDA CBT&A (Competency Based Training & Assessment) guidelines অনুযায়ী written questions, MCQ questions এবং practical tasks-এর জন্য নিজেকে প্রস্তুত করতে পারবেন। আমাদের expert trainers আপনাকে সঠিক guidance দেবেন যাতে আপনি সফলভাবে NSDA exam পাশ করে আপনার স্বপ্নের animation career শুরু করতে পারেন।', 'Master 3D Character Animation for Freelance & NSDA Level 4', 'Unlock your potential in 3D character animation! Master industry tools, create stunning animations, and launch a freelance career. Prepare for NSDA Level 4 certification with AssessmentBD.', '3D character animation, freelance animation, NSDA Level 4 animation, 3D animation tools, CBT&A animation training, NSDA exam preparation, MCQ question practice, written question techniques, animation career Bangladesh', NULL, 1, 0, NULL, 7, '2026-05-20 02:44:11', '2026-05-24 15:44:33'),
(8, 'Academic Content Writing For Freelancing Level 4', 'Level 4', 'Information And Communication Technology', 'Information And Communication Technology', 'Academic Content Writing For Freelancing', 'academic-content-writing-for-freelancing-level-4', 'আমাদের \'Academic Content Writing For Freelancing Level 4\' কোর্সটি আপনাকে প্রফেশনাল Academic writing শিখতে সাহায্য করবে। এখানে আপনি Advanced Research, সঠিক Referencing, Argument Development এবং Complex Topic সহজ করে লেখার কৌশল শিখবেন। Freelancing marketplace-এ client-দের জন্য High-quality ও impactful content তৈরি করতে এই দক্ষতাগুলো খুবই জরুরি, যা আপনাকে আপনার Writing career-এ এগিয়ে রাখবে।\r\n\r\nএই কোর্সটি শুধু freelancing এর জন্য নয়, NSDA (National Skills Development Authority) certification এর জন্যও আপনাকে প্রস্তুত করবে। CBT&A (Competency Based Training & Assessment) পদ্ধতিতে আপনি কিভাবে লিখিত প্রশ্ন (written question) ও MCQ প্রশ্ন (mcq question) সঠিকভাবে analyze ও answer করবেন, সেই ধারণাও পাবেন। আমাদের শেখানো বিভিন্ন Writing tools ব্যবহার করে আপনি আপনার লেখা আরও উন্নত করতে পারবেন, যা আপনার NSDA exam-এর সফলতার সম্ভাবনা অনেক বাড়িয়ে দেবে।', 'Academic Content Writing L4: Freelancing & NSDA Exam Prep', 'Master Academic Content Writing Level 4 for freelancing success. Learn advanced techniques, research, and structure. Excel in client projects & prepare for NSDA exams with confidence!', 'academic content writing, freelancing content writing, level 4 content writing, NSDA exam preparation, CBT&A assessment tips, academic writing tools, written question techniques, MCQ question strategies, NSDA question formats, content creation skills', NULL, 1, 0, NULL, 8, '2026-05-20 02:44:11', '2026-05-24 15:46:02'),
(9, 'Academic Content Writing For Freelancing Level 5', 'Level 5', 'Information And Communication Technology', 'Information And Communication Technology', 'Academic Content Writing For Freelancing', 'academic-content-writing-for-freelancing-level-5', 'এই \'Academic Content Writing For Freelancing Level 5\' কোর্সে আপনি শিখবেন কিভাবে প্রফেশনাল একাডেমিক কন্টেন্ট তৈরি করতে হয়। Freelancing জগতে সফল হতে হলে রিসার্চ পেপার, অ্যাসাইনমেন্ট, রিপোর্ট এবং অন্যান্য অ্যাকাডেমিক লেখা কিভাবে লিখতে হয়, তার বিস্তারিত ধারণা দেওয়া হবে। আপনি শিখবেন সঠিক রিসার্চ টেকনিক, বিভিন্ন citation style (যেমন APA, MLA), plagiarism avoidance এবং কিছু useful writing tools ব্যবহার করা। এই দক্ষতাগুলো আপনাকে গ্লোবাল ক্লায়েন্টদের জন্য হাই-কোয়ালিটি কন্টেন্ট লিখতে সাহায্য করবে।\r\n\r\nএই কোর্সটি আপনাকে NSDA (National Skills Development Authority) Level 5 সার্টিফিকেশন পরীক্ষার জন্য পুরোপুরি প্রস্তুত করবে। আমরা focus করব CBT&A (Competency-Based Training & Assessment) guidelines মেনে কিভাবে written question, MCQ question এবং practical assessments এ ভালো করা যায়। এই কোর্স completion এর পর আপনি আত্মবিশ্বাসের সাথে NSDA পরীক্ষা দিতে পারবেন এবং একজন সফল Academic Content Writer হিসেবে আপনার freelancing career শুরু করতে পারবেন।', 'Master Academic Content Writing for Freelancing | Level 5', 'Master Academic Content Writing Level 5 for freelancing success. Learn expert research, writing tools, and citation techniques. Prepare for NSDA CBT&A written & MCQ questions. Enroll now!', 'academic content writing, freelancing level 5, NSDA exam prep, CBT&A assessment, academic writing tools, NSDA written question, NSDA MCQ question, professional content creation', NULL, 1, 0, NULL, 9, '2026-05-20 02:44:11', '2026-05-23 20:41:53'),
(10, 'Accounting For Freelancing Level 4', 'Level 4', 'Information And Communication Technology', 'Information And Communication Technology', 'Accounting For Freelancing', 'accounting-for-freelancing-level-4', 'Freelancing-এ successful হতে হলে সঠিক Financial Management জানাটা খুবই জরুরি। আমাদের Accounting For Freelancing Level 4 কোর্সে আপনি শিখবেন কিভাবে আপনার আয়-ব্যয় (income-expense) track করবেন, profit calculation করবেন এবং আপনার Freelance business-এর আর্থিক দিকগুলি efficiently manage করবেন। এটা আপনার Income increase করতে এবং financial stability আনতে সাহায্য করবে.\r\n\r\nএই কোর্সটি বিশেষভাবে ডিজাইন করা হয়েছে যেন আপনি NSDA Level 4 Accounting exam-এর জন্য পুরোপুরি প্রস্তুত হতে পারেন। এখানে আপনি NSDA question pattern, written question এবং MCQ questions এর উপর comprehensive training পাবেন। ফলে আপনি confidently exam দিয়ে ভালো রেজাল্ট করতে পারবেন এবং আপনার career-কে আরও এগিয়ে নিতে পারবেন।', 'Freelance Accounting Level 4: Master NSDA & Grow Your Business', 'Master Accounting for Freelancing Level 4! Learn essential financial tools, prepare for NSDA written & MCQ questions, and boost your freelance career in Bangladesh.', 'freelance accounting level 4, accounting tools for freelancers, nsda accounting questions, CBT&A exam prep, written question practice, mcq question techniques, bangladesh freelancer finance, freelance bookkeeping', NULL, 1, 0, NULL, 10, '2026-05-20 02:44:11', '2026-05-23 19:17:42'),
(11, 'Accounting For Freelancing Level 5', 'Level 5', 'Information And Communication Technology', 'Information And Communication Technology', 'Accounting For Freelancing', 'accounting-for-freelancing-level-5', 'আপনি কি ফ্রিল্যান্সার? আপনার ব্যবসার সঠিক হিসাব রাখা অনেক জরুরি! এই \'Accounting For Freelancing Level 5\' কোর্সে আপনি শিখবেন কিভাবে আপনার Freelance earnings এবং expenses efficiently manage করতে হয়। Invoicing, payment tracking, financial reporting – এই সব practical skills পাবেন যা আপনার accounting process কে অনেক সহজ করে দেবে। কোন tools ব্যবহার করবেন, কিভাবে সঠিক records রাখবেন – সব হাতে কলমে শেখানো হবে।\r\n\r\nএই কোর্সটি আপনাকে NSDA Level 5 Certification পরীক্ষার জন্য বিশেষভাবে প্রস্তুত করবে। Written question, MCQ question বা practical CBT&A assessment যাই আসুক না কেন, আপনি confidentially answer করতে পারবেন। NSDA\'র specific curriculum অনুযায়ী তৈরি করা হয়েছে, তাই exam passing এর জন্য যা দরকার, তার সবই এখানে পাবেন। Prepare yourself for a successful freelancing career and NSDA certification!', 'Freelance Accounting L5: Master Books & Pass NSDA Exam', 'Master Freelance Accounting Level 5! Gain practical skills, understand income/expense tracking, invoicing & tax. Prepare for NSDA written, MCQ, and CBT&A exams with expert tools. Enroll & succeed!', 'freelance accounting, level 5 accounting, NSDA exam prep, accounting tools, written question preparation, mcq question accounting, nsda exam questions, CBT&A assessment prep, freelancer bookkeeping, income expense tracking', NULL, 1, 0, NULL, 11, '2026-05-20 02:44:11', '2026-05-23 20:59:42'),
(12, 'Advanced Customer Service In Contact Center Level 5', 'Level 5', 'Information And Communication Technology', 'Information And Communication Technology', 'Advanced Customer Service In Contact Center', 'advanced-customer-service-in-contact-center-level-5', 'আপনি কি কন্টাক্ট সেন্টারে আপনার কাস্টমার সার্ভিস স্কিলসকে নেক্সট লেভেলে নিয়ে যেতে চান? আমাদের Advanced Customer Service in Contact Center Level 5 কোর্সটি আপনার জন্য! এই কোর্স আপনাকে জটিল কাস্টমার সিচুয়েশন হ্যান্ডেল করা, প্রো-অ্যাক্টিভ সার্ভিস দেওয়া, এবং প্রফেশনালি কাস্টমারদের সাথে ইন্টারঅ্যাক্ট করার জন্য অত্যাধুনিক টেকনিক শেখাবে। এখানে আপনি শিখবেন কিভাবে কাস্টমারদের এক্সপেক্টেশন পূরণ করে তাদের সন্তুষ্টি বাড়ানো যায়।\r\n\r\nNSDA Level 5 CBT&A এক্সামের জন্য নিজেকে প্রস্তুত করুন। আমাদের ট্রেনিং আপনাকে শুধু থিওরি শেখাবে না, বরং Practical Customer Service Tools ব্যবহার এবং NSDA-এর Written Question ও MCQ Question গুলো সহজে সলভ করার জন্য প্রস্তুত করবে। এই কোর্স শেষে আপনি আত্মবিশ্বাসের সাথে NSDA অ্যাসেসমেন্টে অংশগ্রহণ করতে পারবেন এবং কন্টাক্ট সেন্টার ইন্ডাস্ট্রিতে সফলভাবে ক্যারিয়ার গড়তে পারবেন।', 'NSDA Level 5 Advanced Customer Service | Contact Center Training', 'Unlock expert customer service skills for contact centers. Prepare for NSDA Level 5 CBT&A exams with our advanced course. Master tools, handle complex scenarios, and ace written/MCQ questions. Enroll now!', 'Advanced Customer Service Training, Contact Center Skills, NSDA Level 5 Certification, CBT&A Exam Prep, Customer Service Tools, Written Exam Questions, MCQ Practice Questions, NSDA Question Bank, Contact Center Advanced Skills, Customer Support Professional', NULL, 1, 0, NULL, 12, '2026-05-20 02:44:11', '2026-05-23 20:42:11'),
(13, 'Advanced Sewing Machine Operation (Multi Skills) Level 3', 'Level 3', 'RMG & Textile', 'RMG & Textile', 'Advanced Sewing Machine Operation (Multi Skills)', 'advanced-sewing-machine-operation-multi-skills-level-3', 'আমাদের এই \'Advanced Sewing Machine Operation (Multi Skills) Level 3\' কোর্সে আপনি সেলাই মেশিনের সবচেয়ে অ্যাডভান্সড টেকনিকগুলো শিখবেন। কীভাবে জটিল কাপড় handle করতে হয়, বিভিন্ন ধরনের সেলাই মেশিন ব্যবহার করতে হয় এবং প্রোডাকশন লেভেলের কাজগুলো efficiently করতে হয়, তার সব কিছু হাতে কলমে শেখানো হবে। এই মাল্টি স্কিলস আপনাকে ইন্ডাস্ট্রিতে একজন expert হিসেবে তৈরি করবে।\r\n\r\nএই কোর্সটি বিশেষভাবে ডিজাইন করা হয়েছে যাতে আপনি NSDA এর CBT&A পরীক্ষা confidently পাশ করতে পারেন। NSDA পরীক্ষায় যে ধরণের written question, MCQ question এবং practical assessment আসে, তার সবকিছুর জন্য আপনাকে প্রস্তুত করা হবে। সঠিক tools ব্যবহার থেকে শুরু করে প্রতিটি প্রশ্নের উত্তর কিভাবে দিতে হয়, আমরা ধাপে ধাপে শিখিয়ে দেব। এই কোর্স করে আপনি NSDA certification পেয়ে আপনার career-এ অনেক এগিয়ে যাবেন।', 'Master Advanced Sewing Machine L3 | NSDA CBT&A Prep', 'Become an expert in Advanced Sewing Machine Operation (Multi Skills) Level 3. Prepare for your NSDA CBT&A exam with our comprehensive course. Master tools, techniques & questions to ensure success!', 'Advanced Sewing Machine Operation L3, Multi Skills Sewing Certification, NSDA Exam Prep Bangladesh, CBT&A Sewing Training, Sewing Machine Tools & Techniques, NSDA Written Questions, Sewing MCQ Questions, NSDA Practical Exam, Sewing Skill Development, Garment Industry Skills', NULL, 1, 0, NULL, 13, '2026-05-20 02:44:11', '2026-05-23 20:57:42'),
(14, 'Advance Garments Pattern Making With CAD Level 4', 'Level 4', 'RMG & Textile', 'RMG & Textile', 'Advance Garments Pattern Making With CAD', 'advance-garments-pattern-making-with-cad-level-4', 'এই অ্যাডভান্সড কোর্সটি আপনাকে CAD সফটওয়্যার ব্যবহার করে গার্মেন্টস প্যাটার্ন মেকিং এর Level 4 এর সকল খুঁটিনাটি শিখতে সাহায্য করবে। আপনি শিখবেন অ্যাডভান্সড প্যাটার্ন অ্যাডজাস্টমেন্ট, গ্রেডিং, এবং মার্কার মেকিং এর টেকনিক। এটি আপনার প্রোডাক্টিভিটি বাড়াবে এবং ইন্ডাস্ট্রিতে আপনার দক্ষতাকে এক অন্য লেভেলে নিয়ে যাবে।\r\n\r\nএই কোর্সটি বিশেষভাবে ডিজাইন করা হয়েছে যাতে আপনি NSDA Level 4 CBT&A এক্সাম সহজেই পাশ করতে পারেন। আমরা MCQ, লিখিত প্রশ্ন, এবং প্র্যাকটিক্যাল অংশের জন্য সম্পূর্ণ প্রস্তুতি নিশ্চিত করব। আমাদের সাথে শিখে আপনি আপনার NSDA সার্টিফিকেট অর্জন করে গার্মেন্টস সেক্টরে একটি সফল ক্যারিয়ার গড়তে পারবেন।', 'Advance CAD Garments Pattern Making L4 | NSDA Exam Prep', 'Master Advance Garments Pattern Making with CAD Level 4. Prepare for NSDA exam with expert tools & practice. Boost your career in RMG. Enroll now!', 'garments pattern making CAD, advance pattern making, CAD pattern making software, NSDA exam preparation, CBT&A assessment, pattern making tools, written question preparation, MCQ question practice, NSDA question bank, CBT&A exam Bangladesh', NULL, 1, 0, NULL, 14, '2026-05-20 02:44:11', '2026-05-23 20:57:25'),
(15, 'Advance Leather Sewing Machine Operations Level 3', 'Level 3', 'Leather & Leather Goods', 'Leather & Leather Goods', 'Advance Leather Sewing Machine Operations', 'advance-leather-sewing-machine-operations-level-3', 'এই \'Advance Leather Sewing Machine Operations Level 3\' কোর্সে আপনি Leather-এর কাজ করার জন্য অত্যাধুনিক সেলাই মেশিন চালানোর A to Z শিখবেন। High-quality finish এবং production efficiency কিভাবে বাড়াতে হয়, সেই সব advanced techniques প্র্যাক্টিক্যাল ওয়েতে দেখানো হবে। Cutting, stitching, finishing সহ leather product তৈরির বিভিন্ন জটিল স্টেপস সহজে আয়ত্ত করবেন।\r\n\r\nএই কোর্সটি বিশেষভাবে NSDA CBT&A পরীক্ষার জন্য ডিজাইন করা হয়েছে। এখানে আপনি শুধু মেশিন চালানোই নয়, written question, MCQ question এবং practical assessment-এর জন্য প্রস্তুত হবেন। NSDA exam-এ ভালো পারফর্ম করে আপনার স্কিলকে Next Level-এ নিয়ে যেতে এখনই এনরোল করুন!', 'Advance Leather Sewing L3: Master Machines & Pass NSDA Exam', 'Master Advance Leather Sewing Machine Operations Level 3. Get expert training for NSDA CBT&A exams, including written, MCQ & practical questions. Boost your career!', 'Advance Leather Sewing Machine Operations L3, NSDA CBT&A Exam Prep, leather sewing tools, written question practice, MCQ question bank, NSDA question patterns, CBT&A assessment, advanced leather skills', NULL, 1, 0, NULL, 15, '2026-05-20 02:44:11', '2026-05-23 19:19:35'),
(16, 'AI In Immersive Technology Level 6', 'Level 6', 'Information And Communication Technology', 'Information And Communication Technology', 'AI In Immersive Technology', 'ai-in-immersive-technology-level-6', 'আমাদের AI In Immersive Technology Level 6 কোর্স আপনাকে next-gen AI এবং immersive technology-র দুনিয়ায় নিয়ে যাবে। AR/VR, mixed reality এবং AI integration কিভাবে কাজ করে, তা আপনি হাতে-কলমে শিখবেন। এই কোর্সে অত্যাধুনিক tools ব্যবহার করে practical skills develop করা হয়, যা আপনাকে industry-ready করবে। NSDA পরীক্ষার জন্য প্রয়োজনীয় সব concepts এখানে ক্লিয়ার করা হবে।\r\n\r\nআপনি NSDA CBT&A পরীক্ষার জন্য সম্পূর্ণ প্রস্তুত হবেন। এখানে written questions, MCQ questions এবং practical assessment techniques শেখানো হবে যা NSDA exam-এ ভালো স্কোর করতে সাহায্য করবে। আমাদের এক্সপার্টরা আপনাকে step-by-step guidance দেবেন যাতে আপনি confidently NSDA certification পেতে পারেন। এখনই enroll করুন এবং আপনার ভবিষ্যৎ ক্যারিয়ারের জন্য একটি solid foundation তৈরি করুন!', 'AI & Immersive Tech Level 6: NSDA Exam Mastery | AssessmentBD', 'Unlock AI & Immersive Technology Level 6! Prepare for NSDA CBT&A exams with our expert-led course. Master tools, written & MCQ questions. Enroll now!', 'AI Immersive Technology Level 6, NSDA CBT&A, immersive tech tools, written questions, MCQ questions, NSDA exam questions, CBT&A assessment, AI VR AR training, Level 6 certification', NULL, 1, 0, NULL, 16, '2026-05-20 02:44:11', '2026-05-24 15:52:40'),
