(248, 'Plumbing Level 1', 'Level 1', 'Construction', 'Construction', 'Plumbing', 'plumbing-level-1', NULL, NULL, NULL, NULL, NULL, 1, 0, NULL, 248, '2026-05-20 02:44:11', '2026-05-20 02:44:11'),
(249, 'Plumbing Level 2', 'Level 2', 'Construction', 'Construction', 'Plumbing', 'plumbing-level-2', 'আমাদের এই Plumbing Level 2 কোর্সটি আপনার জন্য তৈরি করা হয়েছে যেন আপনি একজন দক্ষ প্লাম্বার হতে পারেন। এখানে আপনি পানির লাইন স্থাপন, রিপেয়ার করা, পাইপ ফিটিং এবং বিভিন্ন অত্যাবশ্যকীয় প্লাম্বিং টুলস (plumbing tools) ব্যবহারের প্র্যাকটিক্যাল জ্ঞান পাবেন। প্রতিটি মডিউল এমনভাবে ডিজাইন করা হয়েছে যাতে আপনি বাস্তব জীবনের চ্যালেঞ্জ মোকাবেলা করতে পারেন।\r\n\r\nএই কোর্সটি আপনাকে NSDA এর CBT&A Plumbing Level 2 পরীক্ষায় সফল হতে বিশেষভাবে সাহায্য করবে। আমরা আপনাকে লিখিত প্রশ্ন (written question), MCQ প্রশ্ন (MCQ question) এবং প্র্যাকটিক্যাল অংশের জন্য সম্পূর্ণ প্রস্তুত করব। NSDA question bank থেকে প্রশ্ন সমাধান এবং সঠিক কৌশল শেখার মাধ্যমে আপনি আত্মবিশ্বাসের সাথে পরীক্ষায় বসতে পারবেন এবং আপনার দক্ষতা প্রমাণ করতে পারবেন।', 'Master Plumbing Level 2: NSDA Exam Prep & Practical Skills', 'Unlock your plumbing career! Our Plumbing Level 2 course covers essential skills, tools, and provides NSDA exam practice. Pass written questions, MCQs, and practical assessments with confidence. Enroll now!', 'Plumbing Level 2, NSDA Plumbing Exam, plumbing tools, written question plumbing, MCQ question plumbing, CBT&A assessment, NSDA question bank, plumbing skills, vocational training Bangladesh', 'courses/thumb_6a169b5663f32.webp', 1, 1, NULL, 249, '2026-05-20 02:44:11', '2026-05-27 07:20:54'),
