INSERT INTO `pages` (`id`, `slug`, `title`, `content`, `is_active`, `created_at`, `updated_at`) VALUES
(1, 'terms', 'ব্যবহারের শর্তাবলী (Terms & Conditions)', '\n                    <p>AssessmentBD প্ল্যাটফর্মে আপনাকে স্বাগতম। এই প্ল্যাটফর্মটি ব্যবহার করার জন্য আপনাকে নিচের শর্তাবলী মেনে চলতে হবে:</p>\n                    <h3>১. সাধারণ ঘোষণা</h3>\n                    <p>এটি একটি সম্পূর্ণ স্বাধীন শিক্ষামূলক প্রস্তুতি প্ল্যাটফর্ম। এই প্ল্যাটফর্মের সাথে কোনো সরকারি সংস্থা বা জাতীয় দক্ষতা উন্নয়ন কর্তৃপক্ষ (NSDA) এর কোনো সরাসরি সম্পর্ক নেই। এখানে প্রদত্ত প্রশ্ন ও টেস্টসমূহ ক্যান্ডিডেটদের স্ব-মূল্যায়ন ও প্রস্তুতির সুবিধার জন্য তৈরি করা হয়েছে।</p>\n                    <h3>২. মেধা সম্পত্তি ও কপিরাইট</h3>\n                    <p>প্ল্যাটফর্মে প্রদর্শিত সকল কন্টেন্ট, প্রশ্ন ব্যাংক, মক টেস্ট ডিজাইন, ইমেজ এবং সোর্স কোড মেধা সম্পত্তি আইনের আওতাধীন। পরীক্ষার কন্টেন্ট কপি করা, ডাউনলোড করা বা বাণিজ্যিক উদ্দেশ্যে ব্যবহার করা সম্পূর্ণ নিষিদ্ধ।</p>\n                    <h3>৩. অ্যাকাউন্ট ও নিরাপত্তা</h3>\n                    <p>আপনাকে একটি বৈধ মোবাইল নম্বর দিয়ে নিবন্ধন করতে হবে। এক জনের অ্যাকাউন্ট অন্য কেউ ব্যবহার করা বা অপব্যবহার করা আইনত দণ্ডনীয়। অ্যান্টি-চিট সিস্টেম অমান্য করলে অ্যাকাউন্ট চিরতরে বাতিল হতে পারে।</p>\n                ', 1, '2026-05-19 20:59:58', '2026-05-19 20:59:58'),
(2, 'privacy', 'প্রাইভেসি পলিসি (Privacy Policy)', '\n                    <p>AssessmentBD-তে আমরা আপনার প্রাইভেসির সর্বোচ্চ সুরক্ষা নিশ্চিত করি। আমাদের পলিসির মূল বিষয়সমূহ নিচে দেওয়া হলো:</p>\n                    <h3>১. সংগৃহীত তথ্য</h3>\n                    <p>রেজিস্ট্রেশনের সময় আমরা আপনার নাম, ইমেইল, মোবাইল নম্বর এবং ঠিকানা সংগ্রহ করে থাকি। এছাড়াও পেমেন্ট ভেরিফিকেশনের জন্য ট্রানজ্যাকশন আইডি ও পেমেন্ট নম্বর ব্যবহৃত হয়।</p>\n                    <h3>২. তথ্যের ব্যবহার</h3>\n                    <p>আপনার মোবাইল নম্বর শুধুমাত্র ওটিপি (OTP) যাচাইকরণ ও নোটিফিকেশনের কাজে ব্যবহার করা হয়। আমরা কখনোই আপনার ব্যক্তিগত তথ্য কোনো তৃতীয় পক্ষের কাছে বিক্রি বা শেয়ার করি না।</p>\n                    <h3>৩. কুকিজ ও নিরাপত্তা</h3>\n                    <p>আপনার সেশন ট্র্যাক করার জন্য এবং ব্রাউজিং অভিজ্ঞতা উন্নত করার জন্য আমরা কুকিজ ব্যবহার করি। আমাদের অ্যান্টি-চিট সিস্টেম আপনার ব্রাউজার ট্যাব পরিবর্তনের তথ্য শুধুমাত্র পরীক্ষার নিরাপত্তা রক্ষার্থে যাচাই করে।</p>\n                ', 1, '2026-05-19 20:59:58', '2026-05-19 20:59:58'),
(3, 'refund', 'রিফান্ড পলিসি (Refund Policy)', '\n                    <p>আমাদের প্ল্যাটফর্মের পেমেন্ট ও রিফান্ড নীতিসমূহ নিম্নরূপ:</p>\n                    <h3>১. সাবস্ক্রিপশন ফি অফেরতযোগ্য</h3>\n                    <p>যেকোনো কোর্সে সাবস্ক্রিপশন নেওয়ার পর তা সাধারণত অফেরতযোগ্য (Non-refundable)। সাবস্ক্রিপশন অ্যাক্টিভ করার আগে অনুগ্রহ করে কোর্সের বিবরণ এবং ফিচারসমূহ ভালোমত দেখে নিন।</p>\n                    <h3>২. ভুল পেমেন্ট বা ডাবল চার্জ</h3>\n                    <p>যদি আপনার অ্যাকাউন্ট থেকে একাধিকবার টাকা কেটে নেওয়া হয় কিন্তু সাবস্ক্রিপশন অ্যাক্টিভ না হয়, তবে আমাদের সাপোর্ট নম্বরে যোগাযোগ করুন। প্রয়োজনীয় প্রমাণ সাপেক্ষে ৩ থেকে ৫ কার্যদিবসের মধ্যে ভুল পেমেন্টের টাকা রিফান্ড করা হবে।</p>\n                ', 1, '2026-05-19 20:59:58', '2026-05-19 20:59:58');
