(850, 27, 68, 'A trainer identifies personal technical weaknesses after workplace observation. What is the MOST professional response?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-25 23:51:07', '2026-05-25 23:51:07'),
(851, 27, 68, 'Why is industry consultation important for TVET trainers?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-25 23:51:07', '2026-05-25 23:51:07'),
(852, 27, 68, 'What is the MAIN goal of maintaining professional and technical competency in CBT&A?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-25 23:51:07', '2026-05-25 23:51:07'),
(853, 22, 68, 'Explain why competency standards are important in the TVET sector.', 'written', 1, 'They ensure training and assessment remain aligned with industry expectations.', NULL, 'Competency standards define the workplace skills, knowledge, and performance required for competency achievement.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(854, 22, 68, 'Describe how trainers should respond when quality assurance procedures are updated.', 'written', 1, 'Ignoring updated quality procedures may create non-compliance and assessment inconsistency.', NULL, 'Trainers should review the updated requirements, align practices with the new procedures, and maintain proper documentation.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(855, 22, 68, 'Explain the role of evidence in competency-based assessment.', 'written', 1, 'Competency decisions must be based on valid, sufficient, authentic, and current evidence.', NULL, 'Evidence is used to confirm whether a learner can perform according to competency standards.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(856, 22, 68, 'A learner requests recognition for previous workplace experience. Explain what should happen.', 'written', 1, 'RPL allows existing competency to be formally recognized when sufficient evidence is available.', NULL, 'The learner’s previous skills and experience should be assessed through Recognition of Prior Learning (RPL) procedures.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(857, 22, 68, 'Explain why ethical behavior is important in the TVET sector.', 'written', 1, 'Unethical decisions may damage learner confidence and assessment credibility.', NULL, 'Ethical behavior supports fairness, trust, professionalism, and assessment integrity within training and assessment systems.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(858, 22, 68, 'Describe how trainers can support learner participation in CBT&A environments.', 'written', 1, 'Effective support improves participation and competency development.', NULL, 'Trainers can identify learner barriers, provide guidance, communicate clearly, and create supportive learning conditions.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(859, 22, 68, 'Explain the importance of maintaining accurate training and assessment records.', 'written', 1, 'Poor documentation may create assessment disputes and compliance problems.', NULL, 'Accurate records support quality assurance, accountability, evidence tracking, and organizational compliance.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(860, 22, 68, 'Describe the purpose of validation activities in TVET assessment systems.', 'written', 1, 'Validation activities improve assessment quality and consistency.', NULL, 'Validation checks whether assessment tools and assessment decisions remain appropriate and aligned with competency standards.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(861, 22, 68, 'Explain why fairness is important in competency-based assessment.', 'written', 1, 'Assessment processes should not disadvantage learners unfairly.', NULL, 'Fairness ensures learners receive equal opportunity and appropriate support during assessment.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(862, 22, 68, 'Describe the responsibilities of trainers and assessors within the TVET sector.', 'written', 1, 'Their role is to support accurate competency development and assessment.', NULL, 'Trainers and assessors must follow competency standards, organizational procedures, ethical practices, and quality assurance requirements.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(863, 23, 68, 'Explain why OSH is important in CBT&A training environments.', 'written', 1, 'A safe environment is necessary for effective competency development and practical learning.', NULL, 'OSH is important because it protects learners and trainers from hazards, injuries, and unsafe workplace conditions while training is taking place.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(864, 23, 68, 'Describe what should be done when a hazard is identified in the workshop.', 'written', 1, 'Hazards should never be ignored because they can lead to accidents and injuries.', NULL, 'The hazard should be controlled if possible, reported according to procedure, and the area made safe before continuing work.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(865, 23, 68, 'A learner refuses to wear PPE during practical work. Explain how the trainer should respond.', 'written', 1, 'PPE helps reduce exposure to hazards and must be used where required.', NULL, 'The trainer should stop the unsafe activity, explain the safety requirement, and ensure PPE is used before work continues.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(866, 23, 68, 'Explain the importance of housekeeping in OSH management.', 'written', 1, 'Good housekeeping is one of the simplest ways to prevent accidents.', NULL, 'Housekeeping keeps the workplace clean, organized, and free from hazards such as slips, trips, blocked exits, and tool clutter.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(867, 23, 68, 'Describe the correct response when a learner is injured during practical training.', 'written', 1, 'Quick response helps protect the learner and ensures the incident is handled properly.', NULL, 'The trainer should provide first aid, report the incident, and follow organizational emergency or accident procedures.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(868, 23, 68, 'Explain the role of hazard reporting in a training environment.', 'written', 1, 'Reporting is part of a safe and responsible workplace culture.', NULL, 'Hazard reporting helps identify unsafe conditions early so that corrective action can be taken before an accident occurs.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(869, 23, 68, 'A fire alarm sounds during a session. What should the trainer do?', 'written', 1, 'Emergency response must be quick, orderly, and based on workplace procedures.', NULL, 'The trainer should stop the activity and follow the emergency evacuation procedure immediately.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(870, 23, 68, 'Explain why damaged equipment should not be used in training.', 'written', 1, 'Unsafe equipment should be removed or repaired before being used again.', NULL, 'Damaged equipment can fail suddenly, cause accidents, and expose learners to unnecessary risk.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(871, 23, 68, 'Describe the main purpose of workplace safety signs.', 'written', 1, 'They are an important part of accident prevention and emergency preparedness.', NULL, 'Safety signs warn people about hazards and guide them toward safe behaviour and emergency routes.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(872, 23, 68, 'Explain how regular inspection supports OSH practice.', 'written', 1, 'Ongoing checks are needed to keep the workshop safe throughout the session.', NULL, 'Regular inspection helps identify hazards, damaged equipment, and unsafe conditions before they become serious problems.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(873, 24, 68, 'Explain why ICT is important in training and assessment activities.', 'written', 1, 'It helps trainers work more efficiently and improves access to learning resources.', NULL, 'ICT supports teaching, learning, document preparation, communication, record keeping, and presentation of information.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(874, 24, 68, 'Describe the correct steps to create and save a document using word processing software.', 'written', 1, 'Saving properly helps protect work from loss and makes the file easier to find later.', NULL, 'Open the software, create the document, type the content, format it if needed, and save it in the correct folder with a clear name.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(875, 24, 68, 'Explain the purpose of using spreadsheet software in a training environment.', 'written', 1, 'It is useful for marks, schedules, lists, and other numerical records.', NULL, 'Spreadsheet software is used to organize data, calculate values, and present information in tables or charts.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(876, 24, 68, 'Describe how a trainer should prepare a presentation for a lesson.', 'written', 1, 'Good preparation makes the lesson clearer and more effective.', NULL, 'The trainer should plan the content, create slides, add suitable text and visuals, save the file, and check the presentation before delivery.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(877, 24, 68, 'Explain the importance of file management in ICT work.', 'written', 1, 'A good folder structure reduces confusion and data loss.', NULL, 'File management helps users store, organize, and retrieve documents quickly and accurately.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(878, 24, 68, 'Describe the safe practices that should be followed when using computer equipment.', 'written', 1, 'Safe practices reduce injury and equipment damage.', NULL, 'Users should maintain correct posture, keep cables safe, avoid wet hands, use devices carefully, and follow organizational procedures.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(879, 24, 68, 'Explain why antivirus software is important in ICT-based learning.', 'written', 1, 'Security measures are necessary when using devices for training and assessment.', NULL, 'Antivirus software protects computers from malware, suspicious files, and system damage.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(880, 24, 68, 'A trainer wants to print a document. Explain what should be checked first.', 'written', 1, 'This prevents wasted paper and printing errors.', NULL, 'The trainer should check the page setup, layout, and print preview before sending the file to the printer.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(881, 24, 68, 'Describe how ICT can support assessment record management.', 'written', 1, 'Digital storage improves accuracy and efficiency in assessment work.', NULL, 'ICT can help store records securely, organize evidence, retrieve files quickly, and support reporting and documentation.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(882, 24, 68, 'Explain how presentation software can help learners understand a topic.', 'written', 1, 'Clear visuals help learners focus and understand the lesson better.', NULL, 'Presentation software can combine text, images, and design features to make content easier to follow.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(883, 25, 68, 'Explain why inclusivity is important in competency-based training environments.', 'written', 1, 'Inclusive environments improve learner confidence, participation, and competency development.', NULL, 'Inclusivity ensures all learners receive fair opportunities to participate, learn, and demonstrate competency regardless of background or ability.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(884, 25, 68, 'Describe how trainers should respond when learners face communication barriers.', 'written', 1, 'Clear communication helps learners participate effectively without changing competency standards.', NULL, 'Trainers should identify the communication issue, adjust communication methods, provide suitable support, and confirm learner understanding.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(885, 25, 68, 'A learner requests oral questioning because of literacy barriers. Explain how the trainer should respond.', 'written', 1, 'Reasonable adjustment improves access but does not reduce competency outcomes.', NULL, 'The trainer should apply reasonable adjustment according to organizational procedures while maintaining competency requirements.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(886, 25, 68, 'Explain the importance of respectful communication in CBT&A environments.', 'written', 1, 'Poor communication practices may reduce participation and create discrimination concerns.', NULL, 'Respectful communication helps learners feel safe, valued, and confident during training and assessment.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(887, 25, 68, 'Describe how trainers can support learners from different cultural backgrounds.', 'written', 1, 'Cultural inclusivity improves learner engagement and supports positive learning environments.', NULL, 'Trainers can use inclusive examples, avoid stereotypes, encourage respectful interaction, and adapt communication methods appropriately.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(888, 25, 68, 'Explain why competency standards must remain unchanged during learner support activities.', 'written', 1, 'Changing standards would compromise fairness and assessment integrity.', NULL, 'Support strategies should improve learner access and participation without lowering the required competency outcomes.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(889, 25, 68, 'Describe the role of reasonable adjustment in competency-based assessment.', 'written', 1, 'It supports inclusivity without reducing assessment quality.', NULL, 'Reasonable adjustment allows learners with additional needs to participate fairly while maintaining assessment validity and competency standards.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(890, 25, 68, 'Explain how discrimination can affect learner participation and performance.', 'written', 1, 'Inclusive training environments are necessary for effective learning.', NULL, 'Discrimination may reduce learner confidence, motivation, participation, and competency achievement.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(891, 25, 68, 'Describe the steps trainers should follow after identifying barriers to learner participation.', 'written', 1, 'Early support helps reduce participation barriers and improve learning outcomes.', NULL, 'Trainers should identify the issue, apply suitable support strategies, communicate clearly, monitor progress, and review effectiveness.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(892, 25, 68, 'Explain the importance of equal opportunity in competency-based training and assessment.', 'written', 1, 'Fair systems improve trust, participation, and competency achievement.', NULL, 'Equal opportunity ensures all learners receive fair access to learning, support, and assessment regardless of personal differences.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(893, 26, 68, 'Explain why regular inspection is important in a training workshop.', 'written', 1, 'Inspection is a preventive action that keeps the workshop safe and functional.', NULL, 'Regular inspection helps identify hazards, damaged equipment, and maintenance needs before they cause accidents or training disruption.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(894, 26, 68, 'Describe what should be done when unsafe equipment is identified.', 'written', 1, 'Unsafe equipment should never remain available for training use.', NULL, 'The equipment should be removed from use, reported, tagged if needed, and repaired or replaced according to procedure.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(895, 26, 68, 'Explain the importance of housekeeping in CBT&A workshops.', 'written', 1, 'Good housekeeping supports both safety and effective training delivery.', NULL, 'Housekeeping keeps the environment clean, organized, and safe by reducing slips, trips, blocked exits, and clutter.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(896, 26, 68, 'Describe how trainers should manage maintenance records.', 'written', 1, 'Accurate records help track safety and maintenance needs over time.', NULL, 'Trainers should document inspections, faults, repairs, and follow-up actions according to organizational procedure.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(897, 26, 68, 'Explain why tools and equipment should be stored properly after use.', 'written', 1, 'When tools are stored correctly, they are easier to find and safer to use.', NULL, 'Proper storage prevents damage, loss, and unsafe use, and it keeps the workshop organized.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(898, 26, 68, 'A learner is about to use a damaged projector for an important lesson. Explain the trainer’s response.', 'written', 1, 'Safety and equipment reliability must come before convenience.', NULL, 'The trainer should not use the faulty projector and should arrange a safe alternative or repair the equipment first.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(899, 26, 68, 'Explain the role of a housekeeping checklist in workshop management.', 'written', 1, 'Checklists help trainers maintain standards and avoid missing important tasks.', NULL, 'A housekeeping checklist ensures cleaning, organization, and safety tasks are completed regularly and consistently.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(900, 26, 68, 'Describe the correct response when a spill is found on the floor.', 'written', 1, 'Spills can cause slips and falls if not handled quickly.', NULL, 'The spill should be cleaned or isolated immediately, and others should be warned if necessary.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(901, 26, 68, 'Explain why maintenance planning is important in training facilities.', 'written', 1, 'Good planning prevents breakdowns and reduces disruption.', NULL, 'Maintenance planning helps match resources, job requirements, and schedules so that equipment and facilities remain safe and usable.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(902, 26, 68, 'Describe how continuous improvement can be applied to training facilities.', 'written', 1, 'Continuous improvement keeps facilities safe and effective for training.', NULL, 'Trainers can inspect regularly, record issues, correct faults, and review the results to improve the workshop environment.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19');
INSERT INTO `questions` (`id`, `exam_id`, `course_id`, `question_text`, `question_type`, `marks`, `explanation`, `model_answer`, `answer`, `sort_order`, `created_at`, `updated_at`) VALUES
(903, 27, 68, 'Explain why maintaining technical competency is important for trainers in the TVET sector.', 'written', 1, 'Outdated technical knowledge can reduce training quality and workplace relevance.', NULL, 'Maintaining technical competency helps trainers deliver accurate, current, and industry-relevant training and assessment.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(904, 27, 68, 'Describe what trainers should do when industry standards change.', 'written', 1, 'Training and assessment must stay aligned with workplace expectations.', NULL, 'Trainers should review updated standards, identify competency gaps, and improve their skills and resources to match current requirements.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(905, 27, 68, 'Explain the role of continuous professional development in CBT&A environments.', 'written', 1, 'Professional development supports long-term competency and training quality.', NULL, 'Continuous professional development helps trainers maintain and improve technical knowledge, teaching skills, and industry awareness.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(906, 27, 68, 'A trainer discovers that practical demonstrations no longer match workplace practice. Explain the correct response.', 'written', 1, 'Learners should be trained using methods that match real workplace conditions.', NULL, 'The trainer should review workplace requirements, update technical skills, and improve demonstrations to reflect current industry practice.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(907, 27, 68, 'Explain why competency standards are important for technical competency development.', 'written', 1, 'They guide trainers in maintaining industry-aligned competency.', NULL, 'Competency standards define the required workplace skills, knowledge, and performance expected in the occupation.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(908, 27, 68, 'Describe how self-assessment supports professional competency improvement.', 'written', 1, 'It supports continuous improvement and professional growth.', NULL, 'Self-assessment helps trainers identify strengths, weaknesses, and areas that require further development.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(909, 27, 68, 'Explain why industry consultation is important for TVET trainers.', 'written', 1, 'Regular consultation keeps training relevant and updated.', NULL, 'Industry consultation helps trainers understand current workplace practices, technology, and employer expectations.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(910, 27, 68, 'Describe the correct response when a trainer identifies personal technical competency gaps.', 'written', 1, 'Ignoring competency gaps may reduce training quality and credibility.', NULL, 'The trainer should seek training, workplace practice, mentoring, or other development opportunities to improve the identified gaps.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(911, 27, 68, 'Explain how lifelong learning supports technical competency.', 'written', 1, 'Continuous learning is necessary in modern technical occupations.', NULL, 'Lifelong learning allows trainers to adapt to changing industry systems, technology, and competency requirements.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(912, 27, 68, 'Describe the relationship between technical competency and quality training delivery.', 'written', 1, 'Professional competency directly affects learner confidence and competency development.', NULL, 'When trainers maintain strong technical competency, training becomes more accurate, relevant, and effective for learners.', 0, '2026-05-25 23:51:19', '2026-05-25 23:51:19'),
(913, 28, 68, 'What is the main purpose of an Information Sheet in a CBLM?', 'written', 1, 'Without this knowledge, a learner cannot achieve the expected competency.', NULL, 'It provides the underpinning knowledge required to perform a task effectively.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(914, 28, 68, 'Explain why a Self-Check is included in a CBLM.', 'written', 1, 'It provides immediate feedback on their understanding of the Information Sheet.', NULL, 'A Self-Check allows learners to verify if they have achieved the cognitive learning objectives before moving to practical tasks.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(915, 28, 68, 'Describe the role of a Job Sheet in competency-based training.', 'written', 1, 'It guides the learner in applying their theoretical knowledge to actual workplace skills.', NULL, 'A Job Sheet provides a set of step-by-step instructions for completing a specific practical task or operation.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(916, 28, 68, 'Explain the importance of a Specification Sheet in a CBLM.', 'written', 1, 'It ensures learners practice under realistic and standardized workplace conditions.', NULL, 'It outlines the specific conditions, required tools, equipment, materials, and working drawings needed to perform a job.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(917, 28, 68, 'Why is piloting necessary before finalizing a new learning material?', 'written', 1, 'It helps save time and resources by fixing issues before wide-scale implementation.', NULL, 'Piloting tests the material with a small group of learners to identify errors and ensure it is effective.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(918, 28, 68, 'Describe what must be considered regarding copyright when adapting existing resources.', 'written', 1, 'Using materials without permission violates copyright laws and ethical standards.', NULL, 'Developers must acknowledge original authors and obtain necessary permissions before using third-party content.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(919, 28, 68, 'Explain the relationship between learning outcomes and competency standard elements.', 'written', 1, 'This ensures the training and assessment meet industry-specified requirements.', NULL, 'Learning outcomes define what a learner will be able to do, directly aligning with the elements of the competency standard.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(920, 28, 68, 'Describe the purpose of incorporating case studies into learning materials.', 'written', 1, 'They bridge the gap between theoretical knowledge and practical decision-making.', NULL, 'Case studies present real-world problems that allow learners to apply their knowledge to solve workplace scenarios.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(921, 28, 68, 'Explain why reviewing learning materials with industry experts is important.', 'written', 1, 'Feedback from experts prevents the use of outdated or incorrect training information.', NULL, 'Expert review ensures the content remains accurate, relevant, and aligned with current workplace practices.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(922, 28, 68, 'What should a developer do if learning materials contain culturally insensitive content?', 'written', 1, 'Inclusive materials ensure fair and equal learning opportunities for all trainees.', NULL, 'The developer must revise the content to be inclusive and ensure it does not disrespect any culture or group.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(923, 29, 68, 'Explain the importance of reviewing a Trainee Characteristics Assessment Form before developing a session plan.', 'written', 1, 'Ignoring trainee backgrounds leads to generic session plans that fail to support adult learners or address individual learning barriers.', NULL, 'Reviewing trainee characteristics helps the trainer identify literacy levels, learning styles, and previous experience to customize the training delivery.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(924, 29, 68, 'A trainer prepares a session plan but assigns 90% of the duration to theoretical lectures. Explain the competency judgement on this plan.', 'written', 1, 'Excessive lecturing violates adult learning principles and fails to provide learners with sufficient time to develop physical workplace competencies.', NULL, 'The session plan is unacceptable because CBT&A requires a practical, hands-on focus where the majority of time is allocated to skill demonstration and independent practice.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(925, 29, 68, 'Describe the relationship between a Competency Standard (CS) and a Session Plan.', 'written', 1, 'A CS defines \'what\' must be achieved, while the session plan outlines exactly \'how\' and \'when\' the trainer will facilitate that achievement.', NULL, 'The session plan translates the elements and performance criteria of the CS into a structured, timed, and resourced roadmap for actual training delivery.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(926, 29, 68, 'During the organization of a training session', 'written', 1, 'The trainer must immediately adjust the session plan to teach a different learning outcome or reschedule the practical task in consultation with stakeholders.', NULL, 'a trainer discovers the requested specialized equipment is booked by another department. What is the FIRST action?', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(927, 29, 68, 'Explain why a trainer must assess \'Current Competencies\' before organizing the training schedule.', 'written', 1, 'Organizing a session without this step wastes time on already-mastered skills and demotivates experienced learners.', NULL, 'Assessing current competencies helps identify specific training gaps and allows for the application of Recognition of Prior Learning (RPL).', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(928, 29, 68, 'A trainer finalizes a session plan but fails to include an OSH risk assessment or list required PPE for a welding activity. Why is this a critical failure?', 'written', 1, 'Failure to document and organize safety requirements constitutes a severe breach of OSH compliance in the CBT&A environment.', NULL, 'Organizing training resources includes ensuring a safe learning environment; omitting OSH exposes learners to unmitigated hazards.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(929, 29, 68, 'Describe how Adult Learning Principles (Andragogy) should influence the organization of a training session.', 'written', 1, 'Adults learn best when training is relevant and self-directed rather than passive and strictly lecture-based.', NULL, 'Session plans must organize activities that involve problem-solving, active participation, and opportunities for learners to apply their prior experience.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(930, 29, 68, 'Explain the importance of integrating \'Formative Assessment\' within a Session Plan.', 'written', 1, 'Without planned formative checks, a trainer cannot adjust delivery if learners are failing to understand the material.', NULL, 'Formative assessments, such as self-checks or direct observation, must be planned to provide continuous feedback and gauge learner progress before the final assessment.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(931, 29, 68, 'A trainer organizes a workstation for 20 learners but only secures consumable materials for 10', 'written', 1, 'Each learner must have sufficient resources to practice and demonstrate competency independently according to the session plan.', NULL, 'expecting learners to share. Explain the flaw in this logic.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(932, 29, 68, 'When determining training requirements', 'written', 1, 'The resulting training plan may severely misalign with the learners\' actual language, literacy, learning styles, or existing skill gaps.', NULL, 'a trainer relies solely on a manager\'s opinion rather than the learners\' self-assessment. What is the risk?', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(933, 30, 68, 'A trainer strictly forces all learners to move to \'Task 2\' on Wednesday, even though three learners have not yet achieved competency in \'Task 1\'. Explain the competency judgement of this action.', 'written', 1, 'In CBT, learners must move at their own pace. Forcing a time-bound, group-based progression is a traditional training approach, not competency-based, and it guarantees skill gaps.', NULL, 'This is unacceptable because it violates the core CBT principle of \'self-paced learning\'.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(934, 30, 68, 'During a practical session, a trainer demonstrates a complex welding task at normal industry speed and immediately tells the learners, \'Now you do it.\' Describe why this demonstration is fundamentally flawed.', 'written', 1, 'According to the 4-step demonstration method, merely showing a task at normal speed is insufficient for skill acquisition. Learners need breakdown, explanation, and guided practice to safely absorb psychomotor skills.', NULL, 'The trainer skipped critical pedagogical steps: showing it slowly with explanation, and doing it together with the learners before independent practice.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(935, 30, 68, 'A learner with a documented reading difficulty is given a 50-page printed manual to self-study. The trainer refuses to provide a video alternative, stating \'everyone gets the same materials.\' Explain the compliance failure here.', 'written', 1, 'CBT requires trainers to adapt delivery methods and resources to accommodate individual learning needs without compromising the competency standard. Refusing alternatives violates inclusivity.', NULL, 'The trainer failed to implement \'Reasonable Adjustments\' (SORA) and ignored the learner\'s specific learning style/barrier.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(936, 30, 68, 'You observe a trainer starting a session by immediately distributing Job Sheets and saying \'Get to work.\' Using the GLOSS model, explain what critical phase is missing and its impact.', 'written', 1, 'Without the GLOSS components, adult learners lack context, motivation, and a clear understanding of what is expected, leading to confusion and unsafe practices in the workshop.', NULL, 'The trainer completely skipped the Introduction phase, failing to Gain attention, Link to previous knowledge, state Outcomes, and Stimulate motivation.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(937, 30, 68, 'An assessor provides feedback to a trainee by saying, \'Your measurements are completely wrong, you failed.\' in front of the entire class. Explain why this violates CBT feedback principles.', 'written', 1, 'Effective feedback must use the \'Feedback Sandwich\' approach (Positive-Negative-Positive), be given privately, and focus on constructive ways to correct the behavior, not just announcing failure.', NULL, 'The feedback is not individualized (given in public), focuses only on the negative, and fails to offer an improvement strategy.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(938, 30, 68, 'A training center places the \'Learning Resource Area\' (library and computers) directly inside the noisy, poorly-lit practical workshop to save space. Explain the instructional risk.', 'written', 1, 'The Learning Resource Area requires a quiet, well-lit environment for reading and research. Placing it in an active practical zone exposes learners to distractions and potential OSH hazards.', NULL, 'This layout disrupts cognitive learning and violates the principle of providing a safe, supportive, and appropriately designed learning environment.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(939, 30, 68, 'A trainer notices a learner constantly interrupting others and dominating the group discussion. The trainer immediately kicks the learner out of the room. What is the BEST alternative approach based on behavior management?', 'written', 1, 'Inappropriate behavior management requires a systematic approach (identify, hypothesize cause, select replacement behavior) rather than immediate punitive expulsion, which destroys the positive learning environment.', NULL, 'The trainer should have identified the cause, implemented ground rules, and privately discussed a replacement behavior with the learner.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(940, 30, 68, 'In a CBT program, a trainer completely fills out the \'Competency Progress Chart\' for all 30 learners at the end of the month just before an audit. Why is this a critical CBT failure?', 'written', 1, 'Progress charts must be updated continuously (often by the learners themselves) to track individual self-paced achievements and identify immediate training gaps. Retrospective filling is falsification.', NULL, 'It proves the trainer is not actively monitoring, managing, or recording learner progress on a continuous, real-time basis.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(941, 30, 68, 'To evaluate the effectiveness of a newly delivered training session, a trainer only looks at the final exam pass rate. Explain why this evaluation is incomplete.', 'written', 1, 'Effective training evaluation requires tools like peer reviews, learner feedback forms, and self-reflection (e.g., video taping) to improve future delivery methods, not just learner grades.', NULL, 'Relying solely on quantitative pass rates ignores qualitative feedback regarding the trainer\'s delivery, material effectiveness, and learner engagement.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(942, 30, 68, 'A session\'s learning outcome requires the learner to \'Troubleshoot a live engine.\' The trainer decides to only assess them using a written test on engine parts to save time. Explain the competency judgement.', 'written', 1, 'Competency requires demonstrating actual skills in realistic conditions. Theoretical knowledge (Cognitive) does not prove the physical ability to perform the task (Psychomotor).', NULL, 'The judgement is Not Yet Competent (NYC) because a written test only measures the Cognitive domain, ignoring the required Psychomotor domain.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(943, 31, 68, 'During a recognition of prior learning (RPL) assessment, a candidate submits a perfectly maintained portfolio of work completed 8 years ago. The assessor rejects it. Explain the competency judgement based on the Rules of Evidence.', 'written', 1, 'Evidence must reflect the candidate\'s current ability to perform to contemporary industry standards. Work completed 8 years ago violates the \'Recent\' rule (usually must be within 5 years) and fails to prove current competency.', NULL, 'The assessor is correct to reject it based on the rule of \'Recent\' and \'Current\' evidence.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(944, 31, 68, 'An assessment designer creates a written multiple-choice test to assess a candidate\'s ability to \'Operate a Lathe Machine\'. Explain why this assessment design is critically flawed.', 'written', 1, 'Validity requires that the assessment method matches the required performance. Operating a machine requires a practical \'Demonstration\' method using an \'Observation Checklist\' (direct evidence), not a theoretical test.', NULL, 'It violates the \'Validity\' principle of assessment and relies on indirect evidence for a psychomotor skill.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(945, 31, 68, 'A candidate correctly identifies a system failure and safely shuts down the machine, preventing a fire. Which specific \'Dimension of Competency\' has the candidate successfully demonstrated?', 'written', 1, 'Contingency Management Skills involve the ability to respond to irregularities, breakdowns, and unexpected emergencies in the workplace routine safely and effectively.', NULL, 'The candidate has demonstrated \'Contingency Management Skills\'.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(946, 31, 68, 'An assessor decides to test a candidate using a completely different, highly advanced machine that is not listed in the Specification Sheet, claiming it will \'test their true limits\'. Explain why this is unacceptable in CBT&A.', 'written', 1, 'Competency-based assessment is not a surprise test. Candidates must be assessed exactly against the conditions, tools, and variables explicitly stated in the Competency Standard. Changing the equipment unfairly alters the standard.', NULL, 'This violates the principles of \'Fairness\' and \'Validity\' in assessment.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(947, 31, 68, 'During the tool development phase, a developer refuses to create an \'Assessment Matrix\'. Describe the critical risk this poses to the assessment process.', 'written', 1, 'The matrix is the blueprint that maps the CS requirements to the specific assessment methods (Written, Oral, Practical). Omitting it risks \'Insufficient\' evidence gathering, rendering the assessment invalid.', NULL, 'Without an Assessment Matrix, there is no guarantee that all Elements and Performance Criteria of the Competency Standard are actually covered by the assessment tools.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(948, 31, 68, 'A candidate with a severe writing disability requests to take the mandatory written exam verbally. The assessor refuses, stating \'the rules cannot change\'. Explain the CBT&A compliance failure.', 'written', 1, 'The \'Flexible\' principle requires assessors to adapt the assessment method to accommodate a candidate\'s needs (e.g., changing written to oral) as long as it does not compromise the integrity of the Competency Standard.', NULL, 'The assessor failed to apply \'Reasonable Adjustment\' and violated the principle of \'Flexibility\'.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(949, 31, 68, 'An assessor marks a candidate \'Competent\' based entirely on a glowing recommendation letter from the candidate\'s supervisor, without observing any practical work. Evaluate this decision based on evidence rules.', 'written', 1, 'While third-party reports are useful supplementary evidence, they are indirect. For a definitive competency judgement, an assessor must gather direct evidence through observation to ensure the evidence is Authentic and Valid.', NULL, 'The decision is flawed because it relies solely on \'Indirect Evidence\' (Third-party report) and lacks \'Sufficiency\'.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(950, 31, 68, 'A newly developed Observation Checklist is immediately used in a national summative assessment without undergoing a \'Pilot Test\' or \'Validation\'. What is the primary instructional risk?', 'written', 1, 'Validation and pilot testing with peer assessors and industry experts are mandatory quality assurance steps to catch errors and ensure the tool is reliable and fair before official use.', NULL, 'The tool may contain ambiguous instructions, incorrect tolerances, or fail to align with the current CS, leading to inaccurate competency judgements.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(951, 31, 68, 'After an assessment, the assessor marks the candidate \'Not Yet Competent\' (NYC) but refuses to explain which specific performance criteria were failed, stating \'the result is final\'. Is this ethical? Explain.', 'written', 1, 'Candidates have a fundamental right to receive clear, constructive feedback on their specific skill gaps and must be informed of their right to appeal or seek reassessment.', NULL, 'No, this is highly unethical and violates the standard assessment guidelines regarding feedback and appeals.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(952, 31, 68, 'A candidate successfully wires an electrical board (Task Skill) but leaves exposed wires on the floor and ignores safety signs. The assessor marks them \'Competent\'. Explain the assessor\'s error using CBT&A logic.', 'written', 1, 'Competency is multi-dimensional. Successfully completing the technical task (Task Skill) does not equal competency if the candidate demonstrates unsafe behavior, failing the Job/Role Environment dimension.', NULL, 'The assessor incorrectly ignored the \'Job/Role Environment Skills\', which dictate compliance with workplace safety and OSH expectations.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(953, 32, 68, 'During a practical assessment, a candidate attempts to operate a grinder without attaching the safety guard. What is the assessor\'s FIRST mandatory action, and what is the resulting competency judgment?', 'written', 1, 'Safety is a critical \'Job/Role Environment Skill\'. The assessor must intervene to prevent physical harm. Bypassing mandatory safety protocols is a critical failure, resulting in an automatic NYC.', NULL, 'The assessor must immediately stop the assessment to prevent injury and mark the candidate Not Yet Competent (NYC).', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(954, 32, 68, 'An assessor notices a candidate struggling to calibrate a machine and gives them a \"small hint\" so they can finish within the time limit. Explain why this invalidates the assessment.', 'written', 1, 'Competency requires the candidate to perform to industry standards without assistance. By providing a hint, the assessor acted as a trainer, which completely invalidates the summative assessment decision.', NULL, 'This action destroys the \'Authenticity\' of the evidence because the candidate did not demonstrate the skill independently.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(955, 32, 68, 'A candidate with clinically diagnosed dyslexia requests 20 extra minutes for the written knowledge test. The assessor refuses, stating \"it must be exactly the same time for everyone to be fair.\" Evaluate this decision.', 'written', 1, 'Fairness in CBT&A means providing equitable opportunities to prove competency. Adjusting the time limit for a dyslexic candidate (without changing the actual technical standard) is a mandatory Reasonable Adjustment.', NULL, 'The assessor failed to apply \'Reasonable Adjustment\' and violated the principle of \'Flexibility\'.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(956, 32, 68, 'The nominal time for a practical task is 2 hours. A candidate performs all steps flawlessly, producing a perfect product, but takes 3.5 hours. What is the correct competency decision and why?', 'written', 1, 'Competency is not just about doing the job; it is about doing it to commercial industry standards. Taking significantly longer than the nominal time proves the candidate is not yet workplace-ready.', NULL, 'The candidate is Not Yet Competent (NYC) because they failed to meet the industry standard for time efficiency.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(957, 32, 68, 'After an assessment, the assessor simply tells the candidate \"Your measurements were wrong, you failed,\" and walks away. Describe the critical CBT&A feedback violations here.', 'written', 1, 'Feedback must be constructive, private, and informative. The assessor is obligated to explain exactly which performance criteria were missed to help the candidate prepare for reassessment, and must inform them of their right to appeal.', NULL, 'The assessor failed to use the \'Feedback Sandwich\' method, did not provide specific constructive guidance, and failed to explain the appeals process.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(958, 32, 68, 'A candidate vehemently disagrees with an NYC decision, becomes angry, and refuses to sign the Assessment Summary Sheet. What is the assessor\'s correct procedural response?', 'written', 1, 'An assessor cannot force a signature or engage in an argument. Professionalism requires documenting the incident and ensuring the candidate knows they have the right to challenge the decision through the official QA grievance process.', NULL, 'The assessor must stay calm, document the candidate\'s refusal to sign on the form, and clearly explain the formal appeals process.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(959, 32, 68, 'You arrive at the assessment venue and find that the main exhaust ventilation system is broken, creating a toxic fume hazard for the welding assessment. What MUST you do?', 'written', 1, 'The assessor is legally and ethically responsible for ensuring a safe assessment environment. Assessing in a hazardous environment violates OSH laws and compromises the assessment.', NULL, 'You must immediately suspend or postpone the practical assessment and report the facility deficiency to the center manager.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(960, 32, 68, 'The Competency Standard requires the candidate to demonstrate \"welding in vertical AND overhead positions.\" The candidate only performs the vertical weld perfectly. The assessor marks them Competent. What is the error?', 'written', 1, 'The assessor violated the Rule of Evidence requiring Sufficiency. The candidate must demonstrate competency across all variables explicitly listed in the standard (both positions) to be deemed Competent.', NULL, 'The evidence gathered is not \'Sufficient\' to meet the requirements of the Competency Standard.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(961, 32, 68, 'On the morning of the assessment, the assigned assessor looks at the attendance sheet and realizes one of the candidates is their own nephew. What is the ONLY acceptable action?', 'written', 1, 'To maintain the integrity, validity, and fairness of the national certification system, an assessor is strictly prohibited from assessing family members or anyone where bias could reasonably be suspected.', NULL, 'The assessor must immediately declare a Conflict of Interest and request a replacement assessor for that specific candidate.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(962, 32, 68, 'During a practical task, a candidate makes a non-hazardous mistake that will clearly result in a ruined final product. Should the assessor stop them immediately? Explain your reasoning.', 'written', 1, 'In a summative assessment, stopping a candidate for a quality error is a form of coaching. The assessor must let the scenario play out to gather valid evidence of the candidate\'s actual competency (or lack thereof), which results in an NYC.', NULL, 'No, the assessor should NOT stop them unless it is an OSH hazard. The candidate must be allowed to finish or recognize their own mistake.', 0, '2026-05-26 00:25:10', '2026-05-26 00:25:10'),
(963, 28, 68, 'Which document provides the step-by-step procedure for a practical task in a CBLM?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-26 00:49:29', '2026-05-26 00:49:29'),
(964, 28, 68, 'What is the MAIN purpose of the Specification Sheet?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-26 00:49:29', '2026-05-26 00:49:29'),
(965, 28, 68, 'According to the CBLM guide, what must an Information Sheet contain?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-26 00:49:29', '2026-05-26 00:49:29'),
(966, 28, 68, 'A learner wants to check their understanding of a topic immediately. Which CBLM component is used?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-26 00:49:29', '2026-05-26 00:49:29'),
(967, 28, 68, 'What should a trainer do FIRST when adapting an existing learning resource?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-26 00:49:29', '2026-05-26 00:49:29'),
(968, 28, 68, 'Which review method involves testing the material with a small target group?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-26 00:49:29', '2026-05-26 00:49:29'),
(969, 28, 68, 'When developing a CBLM, what should the text style and language be?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-26 00:49:29', '2026-05-26 00:49:29'),
(970, 28, 68, 'A trainer includes a real-world problem for learners to solve. What is this instructional method called?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-26 00:49:29', '2026-05-26 00:49:29'),
(971, 28, 68, 'What must be considered to avoid legal issues when using third-party images in a CBLM?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-26 00:49:29', '2026-05-26 00:49:29'),
(972, 28, 68, 'Which of the following is considered a consumable resource in training?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-26 00:49:29', '2026-05-26 00:49:29'),
(973, 28, 68, 'What is the purpose of Gagne\'s first step \'Gaining attention\' in learning design?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-26 00:49:29', '2026-05-26 00:49:29'),
(974, 28, 68, 'A trainer is writing Performance Criteria. How should they be structured?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-05-26 00:49:29', '2026-05-26 00:49:29'),
