(1350, 58, 74, 'What is communication etiquette?', 'written', 1, 'Communication etiquette বলতে যোগাযোগের সময় ভদ্র ও পেশাদার আচরণ বজায় রাখাকে বোঝায়।', NULL, 'Communication etiquette means maintaining polite and professional behavior during communication.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1351, 58, 74, 'Why is active listening important in client communication?', 'written', 1, 'Active listening করলে ক্লায়েন্টের চাহিদা সঠিকভাবে বোঝা যায়।', NULL, 'Active listening helps understand client requirements correctly.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1352, 58, 74, 'What is non-verbal communication?', 'written', 1, 'Non-verbal communication এ অঙ্গভঙ্গি, facial expression এবং body language ব্যবহার করা হয়।', NULL, 'Non-verbal communication uses gestures, facial expressions, and body language.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1353, 58, 74, 'Why should confidential client information be protected?', 'written', 1, 'Client এর confidential তথ্য সুরক্ষিত রাখলে trust ও privacy বজায় থাকে।', NULL, 'Protecting confidentiality maintains trust and privacy.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1354, 58, 74, 'What is the purpose of a task proposal?', 'written', 1, 'Task proposal এ কাজের পরিকল্পনা ও উদ্দেশ্য উল্লেখ করা হয়।', NULL, 'A task proposal explains planned work activities and objectives.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1355, 58, 74, 'How can communication misunderstandings be reduced?', 'written', 1, 'পরিষ্কার যোগাযোগ এবং active listening এর মাধ্যমে misunderstanding কমানো যায়।', NULL, 'Misunderstandings can be reduced through clear communication and active listening.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1356, 58, 74, 'Why should documents be validated before submission?', 'written', 1, 'Document validation করলে তথ্যের সঠিকতা ও সত্যতা নিশ্চিত হয়।', NULL, 'Validation ensures document accuracy and authenticity.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1357, 58, 74, 'What is the importance of professional communication?', 'written', 1, 'Professional communication workplace relationship ও client satisfaction বৃদ্ধি করে।', NULL, 'Professional communication improves workplace relationships and client satisfaction.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1358, 58, 74, 'How should routine client questions be answered?', 'written', 1, 'Routine client question এর উত্তর ভদ্রভাবে এবং পরিষ্কারভাবে দিতে হয়।', NULL, 'Routine client questions should be answered politely and clearly.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1359, 58, 74, 'Why are online communication platforms important?', 'written', 1, 'Online communication platform দ্রুত ও কার্যকর যোগাযোগে সহায়তা করে।', NULL, 'Online platforms support fast and effective communication.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1360, 59, 74, 'What is Occupational Safety and Health (OSH)?', 'written', 1, 'কর্মক্ষেত্রে নিরাপত্তা ও স্বাস্থ্য সুরক্ষা নিশ্চিত করার নিয়ম ও পদ্ধতিকে OSH বলা হয়।', NULL, 'OSH refers to policies and practices that ensure workplace safety and health.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1361, 59, 74, 'Why is ergonomics important in ICT workplaces?', 'written', 1, 'Ergonomics সঠিকভাবে অনুসরণ করলে শরীরের চাপ কমে এবং কাজের দক্ষতা বৃদ্ধি পায়।', NULL, 'Ergonomics helps reduce physical strain and improves work efficiency.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1362, 59, 74, 'Mention two common hazards in ICT workplaces.', 'written', 1, 'ঢিলা ক্যাবল এবং বৈদ্যুতিক ঝুঁকি ICT কর্মক্ষেত্রে সাধারণ hazard হিসেবে দেখা যায়।', NULL, 'Loose cables and electrical hazards are common ICT workplace hazards.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1363, 59, 74, 'What is the purpose of Personal Protective Equipment (PPE)?', 'written', 1, 'PPE কর্মীদের বিভিন্ন ঝুঁকি ও দুর্ঘটনা থেকে সুরক্ষা প্রদান করে।', NULL, 'PPE protects workers from workplace injuries and hazards.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1364, 59, 74, 'Why should workplace incidents be reported?', 'written', 1, 'ঘটনা রিপোর্ট করলে ভবিষ্যতে দুর্ঘটনা প্রতিরোধ করা সহজ হয় এবং নিরাপত্তা বজায় থাকে।', NULL, 'Incident reporting helps prevent future accidents and maintain safety standards.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1365, 59, 74, 'What is an electrical hazard?', 'written', 1, 'ত্রুটিপূর্ণ বৈদ্যুতিক যন্ত্র বা তার থেকে সৃষ্ট ঝুঁকিকে electrical hazard বলা হয়।', NULL, 'An electrical hazard is a risk caused by faulty electrical equipment or wiring.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1366, 59, 74, 'How can eye strain be reduced during computer operation?', 'written', 1, 'সঠিক আলো ব্যবহার এবং নিয়মিত বিরতি নিলে চোখের চাপ কমে যায়।', NULL, 'Eye strain can be reduced by proper lighting and regular breaks.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1367, 59, 74, 'Why is cleanliness important in ICT workplaces?', 'written', 1, 'পরিচ্ছন্নতা বজায় রাখলে দুর্ঘটনার ঝুঁকি কমে এবং যন্ত্রপাতি নিরাপদ থাকে।', NULL, 'Cleanliness reduces risks and protects equipment from damage.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1368, 59, 74, 'Mention two workplace emergency procedures.', 'written', 1, 'Evacuation plan এবং first aid procedure জরুরি পরিস্থিতিতে ব্যবহৃত হয়।', NULL, 'Evacuation plans and first aid procedures are workplace emergency procedures.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1369, 59, 74, 'Why should social media addiction be minimized at work?', 'written', 1, 'অতিরিক্ত social media ব্যবহার কমালে কাজে মনোযোগ বৃদ্ধি পায় এবং নিরাপত্তা বজায় থাকে।', NULL, 'Reducing social media addiction improves focus and workplace safety.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1370, 60, 74, 'What is confidentiality in ICT workplace?', 'written', 1, 'Confidentiality বলতে ক্লায়েন্ট ও প্রতিষ্ঠানের তথ্য অনুমতি ছাড়া অন্য কারও কাছে প্রকাশ না করাকে বোঝায়।', NULL, 'Confidentiality means protecting client and workplace information from unauthorized access.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1371, 60, 74, 'Why is workplace code of conduct important?', 'written', 1, 'Workplace code of conduct কর্মক্ষেত্রে সঠিক ও পেশাদার আচরণ বজায় রাখতে সহায়তা করে।', NULL, 'It guides professional and acceptable behavior in the workplace.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1372, 60, 74, 'What is a conflict of interest?', 'written', 1, 'ব্যক্তিগত স্বার্থ পেশাগত দায়িত্বকে প্রভাবিত করলে তাকে conflict of interest বলা হয়।', NULL, 'A conflict of interest occurs when personal interest affects professional responsibility.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1373, 60, 74, 'Why should realistic time estimation be provided to clients?', 'written', 1, 'সঠিক সময় ও খরচের ধারণা দিলে ক্লায়েন্টের আস্থা বৃদ্ধি পায় এবং পরিকল্পনা সহজ হয়।', NULL, 'Realistic estimation builds trust and helps proper project planning.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1374, 60, 74, 'What is meant by quality process?', 'written', 1, 'পণ্য ও সেবার মান বজায় রাখার জন্য ব্যবহৃত নিয়ম ও ধাপকে quality process বলা হয়।', NULL, 'Quality process refers to procedures used to maintain product and service standards.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1375, 60, 74, 'Why should proprietary rights be respected?', 'written', 1, 'Proprietary rights সম্মান করলে মালিকানা ও আইনি অধিকার সুরক্ষিত থাকে।', NULL, 'Respecting proprietary rights protects ownership and legal rights.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1376, 60, 74, 'How can professionalism be maintained in ICT workplace?', 'written', 1, 'সততা, সময়ানুবর্তিতা এবং নৈতিক আচরণের মাধ্যমে professionalism বজায় রাখা যায়।', NULL, 'Professionalism can be maintained through honesty, punctuality, and workplace ethics.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1377, 60, 74, 'What is unbiased information?', 'written', 1, 'ব্যক্তিগত পক্ষপাত ছাড়া সঠিক তথ্য প্রদান করাকে unbiased information বলা হয়।', NULL, 'Unbiased information is accurate information without personal preference.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1378, 60, 74, 'Why should workplace policies be followed?', 'written', 1, 'Workplace policy অনুসরণ করলে শৃঙ্খলা, নিরাপত্তা এবং কাজের মান বজায় থাকে।', NULL, 'Policies help maintain discipline, security, and work quality.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1379, 60, 74, 'What is the importance of ethical standards in ICT?', 'written', 1, 'Ethical standard অনুসরণ করলে আস্থা, professionalism এবং সেবার মান বৃদ্ধি পায়।', NULL, 'Ethical standards improve trust, professionalism, and service quality.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1380, 61, 74, 'What is ergonomics in computer operation?', 'written', 1, 'Ergonomics বলতে নিরাপদ ও আরামদায়কভাবে কম্পিউটার ব্যবহারের জন্য workstation ও যন্ত্রপাতি সঠিকভাবে সাজানোকে বোঝায়।', NULL, 'Ergonomics means arranging workstation and equipment for comfortable and safe computer use.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1381, 61, 74, 'Why should user accounts be managed properly?', 'written', 1, 'সঠিকভাবে user account পরিচালনা করলে সিস্টেম নিরাপদ থাকে এবং ব্যবহারকারীর access নিয়ন্ত্রণ করা যায়।', NULL, 'Proper account management protects system security and controls user access.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1382, 61, 74, 'What is the purpose of file organization?', 'written', 1, 'File organization করলে ফাইল সংরক্ষণ ও খুঁজে পাওয়া সহজ হয়।', NULL, 'File organization helps store and locate files efficiently.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1383, 61, 74, 'Mention two common Windows applications.', 'written', 1, 'Paint এবং Calculator Windows এর সাধারণ application।', NULL, 'Paint and Calculator are common Windows applications.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1384, 61, 74, 'Why are software updates important?', 'written', 1, 'Software update করলে নিরাপত্তা বৃদ্ধি পায় এবং system problem সমাধান হয়।', NULL, 'Software updates improve security and fix system problems.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1385, 61, 74, 'What is a Microsoft account?', 'written', 1, 'Microsoft account হলো Microsoft এর online service এর সাথে সংযুক্ত user account।', NULL, 'A Microsoft account is an online user account connected with Microsoft services.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1386, 61, 74, 'How can files be restored after deletion?', 'written', 1, 'Delete হওয়া file Recycle Bin থেকে restore করা যায়।', NULL, 'Deleted files can be restored from the Recycle Bin.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1387, 61, 74, 'What is the function of antivirus software?', 'written', 1, 'Antivirus software ক্ষতিকর program শনাক্ত ও remove করতে সাহায্য করে।', NULL, 'Antivirus software detects and removes harmful programs.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1388, 61, 74, 'Why should proper posture be maintained during computer operation?', 'written', 1, 'সঠিক posture বজায় রাখলে শরীরের চাপ কমে এবং আরামদায়কভাবে কাজ করা যায়।', NULL, 'Proper posture reduces physical strain and improves comfort.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1389, 61, 74, 'What should be done after identifying hardware malfunction?', 'written', 1, 'Hardware malfunction শনাক্ত করার পরে সমস্যা record করে সমাধান প্রয়োগ করতে হয়।', NULL, 'The problem should be recorded and proper solution should be applied.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1390, 62, 74, 'What is the purpose of Format Painter?', 'written', 1, 'Format Painter এক টেক্সটের formatting অন্য টেক্সটে কপি করতে ব্যবহৃত হয়।', NULL, 'Format Painter copies formatting from one text to another.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1391, 62, 74, 'What is Mail Merge in MS Word?', 'written', 1, 'Mail Merge ব্যবহার করে main document ও data source একত্র করা হয়।', NULL, 'Mail Merge combines a main document with a data source.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1392, 62, 74, 'Why is Track Change important in Word?', 'written', 1, 'Track Change document এ করা পরিবর্তন পর্যবেক্ষণ করতে সাহায্য করে।', NULL, 'Track Change helps review and monitor document edits.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1393, 62, 74, 'What is the function of Header and Footer?', 'written', 1, 'Header ও Footer প্রতিটি page এ একই তথ্য প্রদর্শন করে।', NULL, 'Header and Footer display repeated information on document pages.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1394, 62, 74, 'What is the purpose of AutoCorrect?', 'written', 1, 'AutoCorrect ভুল বানান স্বয়ংক্রিয়ভাবে ঠিক করে।', NULL, 'AutoCorrect automatically corrects misspelled words.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1395, 62, 74, 'Why should documents be reviewed before printing?', 'written', 1, 'Printing এর আগে review করলে formatting ও ভুল ঠিক আছে কিনা নিশ্চিত করা যায়।', NULL, 'Reviewing ensures proper formatting and error correction.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1396, 62, 74, 'What is WordArt used for?', 'written', 1, 'WordArt ব্যবহার করে আকর্ষণীয় text style তৈরি করা যায়।', NULL, 'WordArt creates decorative text styles.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1397, 62, 74, 'How can a document be protected from unauthorized access?', 'written', 1, 'Password protection ব্যবহার করে document নিরাপদ রাখা যায়।', NULL, 'Documents can be protected using password protection.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1398, 62, 74, 'What is the use of Bookmark in Word?', 'written', 1, 'Bookmark document এর নির্দিষ্ট স্থানে দ্রুত যেতে সাহায্য করে।', NULL, 'Bookmark helps quickly navigate to specific document locations.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1399, 62, 74, 'Why is spelling and grammar checking important?', 'written', 1, 'Spelling ও grammar check করলে document আরও professional ও নির্ভুল হয়।', NULL, 'It improves document accuracy and professionalism.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1400, 63, 74, 'What is a workbook in Excel?', 'written', 1, 'Workbook মানে একটি Excel file যার মধ্যে একাধিক worksheet থাকতে পারে।', NULL, 'A workbook is an Excel file that contains one or more worksheets.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1401, 63, 74, 'What is the purpose of the PMT function?', 'written', 1, 'PMT function দিয়ে loan বা mortgage এর নির্দিষ্ট সময়ের কিস্তি বের করা হয়।', NULL, 'PMT calculates the periodic payment for a loan or mortgage.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1402, 63, 74, 'Why is Wrap Text used in a worksheet?', 'written', 1, 'Wrap Text ব্যবহার করলে লম্বা text cell এর ভিতরে ভেঙে একাধিক লাইনে দেখা যায়।', NULL, 'Wrap Text makes long text visible within a cell by placing it on multiple lines.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1403, 63, 74, 'What is the use of Merge and Center?', 'written', 1, 'Merge and Center দিয়ে একাধিক cell একত্র করা হয় এবং text মাঝখানে রাখা হয়।', NULL, 'Merge and Center joins selected cells and centers the content in the merged cell.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1404, 63, 74, 'Why are formulas important in spreadsheets?', 'written', 1, 'Formula ব্যবহার করলে হিসাব স্বয়ংক্রিয় হয় এবং manual ভুল কমে।', NULL, 'Formulas calculate values automatically and reduce manual work.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1405, 63, 74, 'What is the function of VLOOKUP?', 'written', 1, 'VLOOKUP table-এর প্রথম column থেকে মান খুঁজে একই row-এর সম্পর্কিত data ফেরত আনে।', NULL, 'VLOOKUP searches for a value in the first column of a table and returns related data from the same row.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1406, 63, 74, 'Why should a workbook be protected with a password?', 'written', 1, 'Password protection workbook-এর data অননুমোদিত পরিবর্তন থেকে সুরক্ষিত রাখে।', NULL, 'Password protection helps keep spreadsheet data secure from unauthorized changes.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1407, 63, 74, 'What is the purpose of filtering in Excel?', 'written', 1, 'Filtering করলে নির্দিষ্ট criteria পূরণ করা data-ই দেখা যায়।', NULL, 'Filtering shows only the records that match the selected criteria.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1408, 63, 74, 'Why is a chart used in a spreadsheet?', 'written', 1, 'Chart data-কে visualভাবে দেখায়, ফলে তুলনা করা সহজ হয়।', NULL, 'A chart presents data visually and makes comparison easier.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1409, 63, 74, 'What is the use of Find and Replace?', 'written', 1, 'Find and Replace ব্যবহার করে worksheet বা workbook-এর data দ্রুত খুঁজে পরিবর্তন করা যায়।', NULL, 'Find and Replace helps quickly locate data and change it across a sheet or workbook.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1410, 64, 74, 'What is Slide Master in PowerPoint?', 'written', 1, 'Slide Master ব্যবহার করে পুরো presentation এর slide design ও formatting নিয়ন্ত্রণ করা যায়।', NULL, 'Slide Master controls the overall design and formatting of slides.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1411, 64, 74, 'What is the purpose of slide transition?', 'written', 1, 'এক slide থেকে অন্য slide এ যাওয়ার সময় visual effect যোগ করাকে slide transition বলা হয়।', NULL, 'Slide transition adds visual effects when moving between slides.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1412, 64, 74, 'Why are animations used in presentations?', 'written', 1, 'Animation ব্যবহার করলে presentation আরও আকর্ষণীয় হয় এবং বিষয় সহজে বোঝানো যায়।', NULL, 'Animations attract attention and explain content visually.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1413, 64, 74, 'What is the use of Slide Sorter view?', 'written', 1, 'Slide Sorter view ব্যবহার করে slide দ্রুত সাজানো ও rearrange করা যায়।', NULL, 'Slide Sorter view helps organize and rearrange slides quickly.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1414, 64, 74, 'Why should presentations be reviewed before presenting?', 'written', 1, 'Presentation review করলে ভুল খুঁজে ঠিক করা যায় এবং quality উন্নত হয়।', NULL, 'Reviewing helps identify mistakes and improve presentation quality.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1415, 64, 74, 'What is Presenter View?', 'written', 1, 'Presenter View slideshow চলাকালে presenter এর জন্য notes ও control দেখায়।', NULL, 'Presenter View shows notes and presentation controls during slideshow.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1416, 64, 74, 'What is SmartArt used for?', 'written', 1, 'SmartArt ব্যবহার করে process ও relationship visualভাবে উপস্থাপন করা যায়।', NULL, 'SmartArt visually represents processes and relationships.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1417, 64, 74, 'Why is consistent formatting important in presentations?', 'written', 1, 'Consistent formatting presentation কে professional ও readable করে তোলে।', NULL, 'Consistent formatting improves professionalism and readability.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1418, 64, 74, 'How can multimedia improve a presentation?', 'written', 1, 'Multimedia ব্যবহার করলে presentation আরও আকর্ষণীয় ও interactive হয়।', NULL, 'Multimedia makes presentations more interactive and engaging.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1419, 64, 74, 'Why is rehearsal important before final presentation?', 'written', 1, 'Rehearsal করলে confidence বৃদ্ধি পায় এবং presentation ভালোভাবে উপস্থাপন করা যায়।', NULL, 'Rehearsal improves confidence and delivery quality.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1420, 65, 74, 'What is cloud storage?', 'written', 1, 'Cloud storage হলো internet-এর মাধ্যমে file সংরক্ষণ ও access করার online service।', NULL, 'Cloud storage is an online service used to store and access files through the internet.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1421, 65, 74, 'Why are online forms used?', 'written', 1, 'Online form ব্যবহার করে দ্রুত ও সহজে তথ্য সংগ্রহ করা যায়।', NULL, 'Online forms are used to collect information and responses efficiently.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1422, 65, 74, 'What is the purpose of screen sharing during online meetings?', 'written', 1, 'Screen sharing ব্যবহার করে অন্যদের presentation বা কাজ দেখানো যায়।', NULL, 'Screen sharing allows participants to view presentations or work directly.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1423, 65, 74, 'Why should strong passwords be used for online accounts?', 'written', 1, 'Strong password ব্যবহার করলে account নিরাপদ থাকে এবং unauthorized access কমে।', NULL, 'Strong passwords help protect accounts from unauthorized access.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1424, 65, 74, 'What is real-time collaboration?', 'written', 1, 'Real-time collaboration এর মাধ্যমে একাধিক user একই সময়ে online এ কাজ করতে পারে।', NULL, 'Real-time collaboration allows multiple users to work together simultaneously online.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1425, 65, 74, 'Why is stable internet important for online meetings?', 'written', 1, 'Stable internet থাকলে online meeting smoothভাবে পরিচালনা করা যায়।', NULL, 'Stable internet ensures smooth communication and reduces interruptions.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1426, 65, 74, 'How can cloud files be shared securely?', 'written', 1, 'Permission এবং secure link ব্যবহার করে cloud file নিরাপদভাবে share করা যায়।', NULL, 'Cloud files can be shared using permissions and protected links.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1427, 65, 74, 'What is the use of folders in cloud storage?', 'written', 1, 'Folder ব্যবহার করলে file সহজে organize ও manage করা যায়।', NULL, 'Folders help organize files for easy access and management.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1428, 65, 74, 'Why should online meeting records be saved?', 'written', 1, 'Meeting record save করলে ভবিষ্যতে reference ও documentation এর জন্য ব্যবহার করা যায়।', NULL, 'Saving records helps future reference and documentation.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
(1429, 65, 74, 'What is the advantage of cloud synchronization?', 'written', 1, 'Cloud synchronization এর মাধ্যমে একাধিক device এ file automatically update থাকে।', NULL, 'Cloud synchronization keeps files updated across multiple devices.', 0, '2026-05-26 11:14:08', '2026-05-26 11:14:08'),
