(2161, 466, 102, '৫ টি ফিটিংস এর নাম লিখ ?', 'written', 1, NULL, NULL, 'এনার্জি মিটার,এসডিবি,মেইন সুইচ,সুইচ বোর্ড,কলিং বেল।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2162, 467, 102, 'ওয়্যারিং শেষে কি কি পরীক্ষা করতে হয় ?', 'written', 1, NULL, NULL, 'ওয়্যারিং শেষে কন্টিনিউটি টেস্ট,ইনসুলেশান টেস্ট,পোলারিটি টেস্ট আর্থিং টেস্ট করতে হয়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
