(2166, 469, 102, 'এম.সি.সি.বি ও এম.সি.বি মধ্যে পার্থক্য কি কি ?', 'written', 1, NULL, NULL, 'এম.সি.সি.বি বড় কিন্তু এম.সি.বি ছোট।এম.সি.সি.বি বেশী কারেন্টের জন্য কিন্তু এ.সি.বি কম কারেন্টের জন্য।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2167, 468, 102, 'এস.ডি.বি কেন ব্যবহার করা হয় ?', 'written', 1, NULL, NULL, 'এস.ডি.বি ব্যবহার করা হয় বিভিন্ন রুমে লাইন ভাগ করার জন্য।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2168, 468, 102, 'এম.ডি.বি কেন ব্যবহার করা হয় ?', 'written', 1, NULL, NULL, 'এম.ডি.বি. ব্যবহার করা হয় মেইন লাইন ভাগ করার জন্য।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2169, 467, 102, 'একটি সাব- সার্কিট কত ওয়াট লোড ব্যবহার করা হয় ?', 'written', 1, NULL, NULL, 'একটি সাব- সাকির্টে ১০০০ ওয়াট লোড ব্যবহার করা হয়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
