(2172, 470, 102, 'এইচ.পি,কে.ডব্লি,এম.ডব্লিও,আর.পি.এম.,কে.ভি ও এইচ.ভি,কি ?', 'written', 1, NULL, NULL, 'এইচ.পি = হর্স পাওয়ার, কে.ডব্লিও = কিলো ওয়াট,এম.ডব্লিও মেগা ওয়াট,আর.পি.এম = রেভিলেশান পার মিনিট, কে,ভি = কিলো ভোল্ট,এইচ.ভি = হাই ভোল্টেজ।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2173, 468, 102, 'কলিং বেলের সাথে সিরিজে বাতি ব্যবহার করা হয় কেন ?', 'written', 1, NULL, NULL, 'কলিং বেলের সাথে সিরিজে বাতি ব্যবহার করা হয় বেলের শব্দ কম/ বেশী করার জন্য এবং নির্দেশক করার জন্য। তাছাড়া বেলের স্থায়িত্ব বাড়ানো জন্য।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
