(2191, 470, 102, 'সিলিং ফ্যান কি কি সাইজের হয়ে থাকে ?', 'written', 1, NULL, NULL, '৩৬ সুইপ,৪৮ সুইপ ও ৫৬ সুইপ।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2192, 470, 102, 'টিউব লাইটের অংশ গুলি কি কি ?', 'written', 1, NULL, NULL, 'টিউব লাইটের অংশ গুলি হল টিউব লাইট,চোক কয়েল, র্স্টাটার,হোল্ডার,ক্যাবল।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2193, 466, 102, 'পিভিসি তার ব্যবহার সুবিধা কি কি ?', 'written', 1, NULL, NULL, 'সহজে বাকানো যায়, তাপ মাত্রায় সহজে গলে যায় না।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
