(2198, 468, 102, 'সুইচ ফেজ তারে লাগাতে হয় কেন ?', 'written', 1, NULL, NULL, 'পোরারিটি সটিক রাখার জন্য সুইচ ফেজ তারে লাগাতে হয়।না হলে মেরামত কারীর বিপদ হবে অথ্যাৎ সুইচ অফ থাকলেও লোডে ফেজ থাকবে।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2199, 468, 102, 'ডিবি ও এস ডিবির মধ্যে পার্থক্য কি কি ?', 'written', 1, NULL, NULL, 'ডিবি = ডিস্টিউিশান বোর্ড,এসডিবি = সাব ডিস্টিউিশান বোড।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2200, 470, 102, 'পিভিসি কেন ব্যবহার করা হয় ?', 'written', 1, NULL, NULL, 'ইনসুলেশান এর টান সহন ক্ষমতা বেশী,তাপে সহজে গলে যা না,দাম কম,সহজে পাওয়া যায়,ওজনে হালকা।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2201, 469, 102, 'খেই যুক্ত তার কেন ব্যবহার করা হয় ?', 'written', 1, NULL, NULL, 'সহজে বাকানো যায়, সহজে ভেঙ্গে যায় না, এবং কমল হয়ে থাকে যার ফলে সংযোগ করতে সুবিধা হয়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2202, 465, 102, 'ভোল্টেজ গ্রেডিং বলতে কি বুঝ ?', 'written', 1, NULL, NULL, 'কোন ক্যাবলের ইনসুলেশান নিরাপদে যত ভোল্টেজ বহন করতে সক্ষম,সেই ভোল্টেজ কে ক্যাবলের ভোল্টেজ গ্রেডিং বলে।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2203, 467, 102, 'সারফেস কল্ডুইট ওয়্যারিং কোথায় ব্যবহার হয় ?', 'written', 1, NULL, NULL, 'শিল্প কারখানায় ও ওয়ার্কসপে সারফেস কল্ডুইট ওয়্যারিং কোথায় ব্যবহার হয়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
