(2240, 468, 102, 'পোলারিটি টেস্ট কী?', 'written', 1, NULL, NULL, 'পোলারিটি টেস্টে ফেজ (L), নিউট্রাল (N) ও আর্থ (E) তার সঠিক টার্মিনালে সংযুক্ত কিনা পরীক্ষা করা হয়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2241, 468, 102, '১৩A সকেটে কত সাইজের তার?', 'written', 1, NULL, NULL, '১৩A সকেটে ২.৫ বর্গ মিমি সাইজের তার ব্যবহার করা হয়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2242, 468, 102, 'সিলিং রোজ কী কাজে লাগে?', 'written', 1, NULL, NULL, 'সিলিং রোজ ছাদ থেকে পেনডেন্ট লাইটের তার সংযোগের ফিটিং হিসেবে ব্যবহার হয়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2243, 468, 102, 'বাংলাদেশে বাসায় সরবরাহ ভোল্টেজ কত?', 'written', 1, NULL, NULL, 'বাংলাদেশে বাসা-বাড়িতে সাধারণ সরবরাহ ভোল্টেজ ২২০V AC।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2244, 468, 102, 'সকেট ইন্সটলের আগে সাপ্লাই বিচ্ছিন্ন কীভাবে?', 'written', 1, NULL, NULL, 'MCB/ELCB ট্রিপ করে লক আউট করতে হবে এবং নিশ্চিত করতে হবে সাপ্লাই নেই।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2245, 468, 102, 'সকেটের ফেসপ্লেট ভাঙা থাকলে কী করবেন?', 'written', 1, NULL, NULL, 'সাথে সাথে সাপ্লাই বিচ্ছিন্ন করে নতুন সকেট প্রতিস্থাপন করতে হবে।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2246, 470, 102, 'ফ্যান ঘুরছে না কিন্তু গুনগুন শব্দ — কারণ কী?', 'written', 1, NULL, NULL, 'সাধারণত ক্যাপাসিটর নষ্ট হলে মোটর টর্ক পায় না, ফলে গুনগুন শব্দ হয় কিন্তু ঘোরে না।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2247, 470, 102, 'ইলেকট্রিক ইস্ত্রির তাপ উৎপাদনকারী উপাদান কী?', 'written', 1, NULL, NULL, 'ইস্ত্রিতে হিটিং এলিমেন্ট (Nichrome কয়েল) তাপ উৎপন্ন করে।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2248, 470, 102, 'MCB কখন ট্রিপ করে?', 'written', 1, NULL, NULL, 'ওভার কারেন্ট বা শর্ট সার্কিটের কারণে MCB ট্রিপ করে সার্কিট সুরক্ষা দেয়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2249, 470, 102, 'ফ্যানের মোটর কয়েল পুড়ে গেলে কী করতে হয়?', 'written', 1, NULL, NULL, 'মোটর রিওয়্যান্ড (পুনরায় কয়েল বসানো) করতে হয়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2250, 470, 102, 'মেগার দিয়ে কী পরিমাপ করা হয়?', 'written', 1, NULL, NULL, 'মেগার দিয়ে ইন্সুলেশন রেজিস্ট্যান্স পরিমাপ করা হয়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2251, 470, 102, 'বৈদ্যুতিক যন্ত্র মেরামতের আগে প্রথম কাজ কী?', 'written', 1, NULL, NULL, 'মেরামতের আগে সাপ্লাই বিচ্ছিন্ন করে লক আউট/ট্যাগ আউট নিশ্চিত করতে হবে।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2252, 463, 102, 'টিমে কাজ করার সুবিধা কি কি?', 'written', 1, NULL, NULL, 'টিমে কাজ করলে দক্ষতা বৃদ্ধি পায়, কাজ দ্রুত হয়, সৃজনশীলতা বাড়ে এবং সমস্যা সহজে সমাধান করা যায়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2253, 463, 102, 'একজন ভালো টিম মেম্বারের গুণাবলি কী কী?', 'written', 1, NULL, NULL, 'সহযোগিতা করা, অন্যের মতামত শোনা, সময়মতো কাজ করা, দায়িত্বশীল থাকা এবং ইতিবাচক মনোভাব রাখা।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2254, 463, 102, '5S কী? 5S-এর নামগুলো লেখো।', 'written', 1, NULL, NULL, '5S হলো কর্মক্ষেত্র সংগঠনের একটি পদ্ধতি। নামগুলো: Sort (বাছাই), Set in Order (সাজানো), Shine (পরিষ্কার), Standardise (মানদণ্ড), Sustain (বজায় রাখা)।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2255, 463, 102, 'SOP মানে কী? কেন ব্যবহার করা হয়?', 'written', 1, NULL, NULL, 'SOP মানে Standard Operating Procedures। সঠিক ও নিরাপদ পদ্ধতিতে কাজ করার নির্দেশিকা হিসেবে ব্যবহার করা হয়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2256, 463, 102, 'দলীয় কাজে নেতার ভূমিকা কী?', 'written', 1, NULL, NULL, 'নেতা কাজ পরিকল্পনা করেন, দলের সদস্যদের নির্দেশনা দেন, সমন্বয় রক্ষা করেন এবং সমস্যা সমাধানে সহায়তা করেন।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2257, 464, 102, 'কর্মক্ষেত্রে কমিউনিকেশনের গুরুত্ব কী?', 'written', 1, NULL, NULL, 'সঠিক যোগাযোগ ভুল বোঝাবুঝি কমায়, কাজের গতি বাড়ায়, সহকর্মীদের মধ্যে সম্পর্ক উন্নত করে এবং কর্মদক্ষতা বৃদ্ধি করে।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2258, 464, 102, 'অনলাইন কমিউনিকেশনের পাঁচটি উদাহরণ লেখো।', 'written', 1, NULL, NULL, 'ইমেইল, ভিডিও কল (Zoom/Teams), হোয়াটসঅ্যাপ বার্তা, অনলাইন মিটিং প্ল্যাটফর্ম এবং প্রজেক্ট ম্যানেজমেন্ট সফটওয়্যার।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2259, 464, 102, 'কর্মক্ষেত্রে পেশাদার আচরণ বলতে কী বোঝায়?', 'written', 1, NULL, NULL, 'সময়মতো উপস্থিত থাকা, সম্মানের সাথে কথা বলা, কাজে মনোযোগী থাকা, গোপনীয়তা রক্ষা করা এবং নিয়ম মেনে চলাকে পেশাদার আচরণ বলে।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2260, 464, 102, 'কর্মক্ষেত্রে মিটিংয়ের উদ্দেশ্য কী?', 'written', 1, NULL, NULL, 'তথ্য ভাগ করা, সমস্যা আলোচনা করা, সিদ্ধান্ত নেওয়া এবং দলের কাজে সমন্বয় করা মিটিংয়ের মূল উদ্দেশ্য।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
(2261, 464, 102, 'কর্মক্ষেত্রে রিপোর্ট লেখার উদ্দেশ্য কী?', 'written', 1, NULL, NULL, 'কাজের অগ্রগতি ও ফলাফল রেকর্ড করতে, সুপারভাইজারকে জানাতে এবং ভবিষ্যৎ রেফারেন্সের জন্য রিপোর্ট লেখা হয়।', 0, '2026-05-27 06:46:52', '2026-05-27 06:46:52'),
