(2831, 456, 249, 'টিমওয়ার্ক কী?', 'written', 1, 'কর্মক্ষেত্রে টিমওয়ার্ক কাজের মান উন্নত করে এবং লক্ষ্য দ্রুত অর্জন করতে সাহায্য করে।', NULL, 'টিমওয়ার্ক হলো একটি দলের সদস্যরা একটি সাধারণ লক্ষ্য অর্জনের জন্য মিলেমিশে ও সহযোগিতা করে কাজ করার প্রক্রিয়া।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2832, 456, 249, '5S কী? 5S-এর পাঁচটি ধাপ উল্লেখ কর।', 'written', 1, '5S পদ্ধতি অনুসরণ করলে কর্মক্ষেত্র সুশৃঙ্খল থাকে এবং উৎপাদনশীলতা বাড়ে।', NULL, '5S হলো কর্মক্ষেত্র সংগঠনের পদ্ধতি। ধাপ: ১. Sort (বাছাই) ২. Set in Order (সাজানো) ৩. Shine (পরিষ্কার) ৪. Standardize (মানদণ্ড) ৫. Sustain (বজায় রাখা)।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2833, 456, 249, 'একজন ভালো টিম মেম্বারের কী কী গুণ থাকা প্রয়োজন?', 'written', 1, 'এই গুণগুলো দলের কাজকে কার্যকর ও সফল করতে সাহায্য করে।', NULL, 'সহযোগিতা, যোগাযোগ দক্ষতা, দায়িত্বশীলতা, ইতিবাচক মনোভাব, সময়মতো কাজ সম্পন্ন করার ক্ষমতা।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2834, 456, 249, 'দলনেতার ভূমিকা কী?', 'written', 1, 'সঠিক নেতৃত্ব ছাড়া দল কার্যকরভাবে কাজ করতে পারে না।', NULL, 'দলনেতা কাজ পরিকল্পনা করেন, সদস্যদের নির্দেশনা দেন, সমস্যা সমাধান করেন এবং দলের সমন্বয় বজায় রাখেন।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2835, 456, 249, 'SOP কী? কেন ব্যবহার করা হয়?', 'written', 1, 'SOP অনুসরণ করলে ভুল ও দুর্ঘটনা কমে এবং কাজের মান বজায় থাকে।', NULL, 'SOP (Standard Operating Procedure) হলো কাজ সঠিক ও নিরাপদভাবে করার নির্দিষ্ট নির্দেশিকা। এটি ব্যবহার করলে কাজের মান এবং সুরক্ষা নিশ্চিত হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2836, 457, 249, 'কর্মক্ষেত্রে কমিউনিকেশন কী?', 'written', 1, 'সঠিক যোগাযোগ ভুল বোঝাবুঝি কমায় এবং কর্মদক্ষতা বাড়ায়।', NULL, 'কর্মক্ষেত্রে কমিউনিকেশন হলো কাজের তথ্য, নির্দেশনা এবং মতামত কর্মীদের মধ্যে আদান-প্রদান করার প্রক্রিয়া।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2837, 457, 249, 'যোগাযোগের তিনটি পদ্ধতি কী কী?', 'written', 1, 'বিভিন্ন পরিস্থিতিতে বিভিন্ন পদ্ধতির যোগাযোগ ব্যবহার করা হয়।', NULL, 'মৌখিক (verbal), লিখিত (written) এবং অঙ্গভঙ্গি (non-verbal) — এই তিনটি পদ্ধতিতে যোগাযোগ করা হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2838, 457, 249, 'Soft skill কী? উদাহরণ দাও।', 'written', 1, 'Soft skill পেশাগত উন্নয়নে গুরুত্বপূর্ণ ভূমিকা পালন করে।', NULL, 'Soft skill হলো এমন ব্যক্তিগত দক্ষতা যা মানুষের সাথে মিলেমিশে কাজ করতে সাহায্য করে। যেমন: যোগাযোগ, নেতৃত্ব, সমস্যা সমাধান।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2839, 457, 249, 'কর্মক্ষেত্রে রিপোর্ট লেখার উদ্দেশ্য কী?', 'written', 1, 'সঠিক রিপোর্টিং কর্মক্ষেত্রে স্বচ্ছতা ও জবাবদিহিতা নিশ্চিত করে।', NULL, 'কাজের অগ্রগতি ও ফলাফল রেকর্ড করতে, সুপারভাইজারকে জানাতে এবং ভবিষ্যৎ রেফারেন্সের জন্য রিপোর্ট লেখা হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2840, 458, 249, 'PPE কী? তিনটি PPE-এর নাম লিখ।', 'written', 1, 'PPE কর্মীর শরীরকে সম্ভাব্য বিপদ থেকে রক্ষা করে।', NULL, 'PPE (Personal Protective Equipment) হলো ব্যক্তিগত সুরক্ষা সরঞ্জাম। যেমন: হেলমেট, গ্লাভস, এপ্রন।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2841, 458, 249, 'প্লাম্বিং কাজে কোন কোন PPE ব্যবহার করতে হয়?', 'written', 1, 'প্লাম্বিং কাজে বিভিন্ন ধরনের বিপদ থাকে তাই সঠিক PPE ব্যবহার আবশ্যক।', NULL, 'হেলমেট, সেফটি গ্লাভস, নিরাপত্তা বুট, গোগলস এবং এপ্রন ব্যবহার করতে হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2842, 458, 249, 'কাজের আগে নিরাপত্তা পরীক্ষা কেন গুরুত্বপূর্ণ?', 'written', 1, 'নিরাপত্তা পরীক্ষা ছাড়া কাজ শুরু করলে দুর্ঘটনার ঝুঁকি বাড়ে।', NULL, 'নিরাপত্তা পরীক্ষা দুর্ঘটনা প্রতিরোধ করে, সরঞ্জামের ত্রুটি শনাক্ত করে এবং কাজের পরিবেশ নিরাপদ রাখে।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2843, 458, 249, 'সেফটি সাইন কী? তিনটি উদাহরণ দাও।', 'written', 1, 'কর্মক্ষেত্রে সেফটি সাইন দেখে কর্মীরা বিপদ সম্পর্কে সচেতন হতে পারেন।', NULL, 'নিরাপত্তা চিহ্ন যা বিপদ সম্পর্কে সতর্ক করে। যেমন: সতর্কতা চিহ্ন, নিষেধাজ্ঞা চিহ্ন, বাধ্যতামূলক সরঞ্জাম ব্যবহারের চিহ্ন।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2844, 458, 249, '১ মিটার কত ইঞ্চি? ১ ফুট কত ইঞ্চি?', 'written', 1, 'পরিমাপের রূপান্তর প্লাম্বিং লেআউটে অপরিহার্য।', NULL, '১ মিটার = ৩৯.৩৭ ইঞ্চি। ১ ফুট = ১২ ইঞ্চি।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2845, 458, 249, 'পরিমাপের পদ্ধতি কত প্রকার ও কী কী?', 'written', 1, 'প্লাম্বিং কাজে উভয় পদ্ধতির পরিমাপ ব্যবহার হয়।', NULL, '২ প্রকার — মেট্রিক পদ্ধতি (মিটার, সেন্টিমিটার) এবং ইম্পেরিয়াল পদ্ধতি (ইঞ্চি, ফুট)।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2846, 458, 249, 'হ্যাকস ব্লেডের TPI কীভাবে নির্বাচন করতে হয়?', 'written', 1, 'সঠিক TPI বাছাই না করলে কাটার মান খারাপ হয় ও ব্লেড নষ্ট হয়।', NULL, 'নরম পদার্থের জন্য কম TPI এবং শক্ত পদার্থের জন্য বেশি TPI বিশিষ্ট ব্লেড ব্যবহার করতে হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2847, 459, 249, 'প্লাম্বিং লেআউট বলতে কী বোঝায়?', 'written', 1, 'সঠিক লেআউট ছাড়া প্লাম্বিং কাজ সুষ্ঠুভাবে করা সম্ভব নয়।', NULL, 'প্লাম্বিং লেআউট হলো পাইপ লাইনের পরিকল্পিত রেখাচিত্র যেখানে পানি সরবরাহ ও নিষ্কাশনের পথ নির্দেশ করা থাকে।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2848, 459, 249, 'জি.আই পাইপের সুবিধা কী কী?', 'written', 1, 'জি.আই পাইপ পানি সরবরাহ ব্যবস্থায় সবচেয়ে বেশি ব্যবহৃত হয়।', NULL, 'টেকসই, মরিচা প্রতিরোধী (জিংক প্রলেপ), উচ্চ চাপ সহনশীল এবং দীর্ঘস্থায়ী।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2849, 459, 249, 'ডাইস্টক দিয়ে থ্রেড কাটার পদ্ধতি কী?', 'written', 1, 'থ্রেড কাটার সময় লুব্রিকেন্ট ব্যবহার করলে ডাই ভালো থাকে ও কাটা মসৃণ হয়।', NULL, 'পাইপ ভাইসে পাইপ আটকে, ডাইস্টকে সঠিক ডাই লাগিয়ে, কাটিং অয়েল দিয়ে পাইপের মাথায় ঘড়ির কাঁটার দিকে ঘুরিয়ে থ্রেড কাটতে হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2850, 459, 249, 'পাইপের সাইজ কীভাবে নির্ণয় করা হয়?', 'written', 1, 'সঠিক সাইজের পাইপ না বাছলে লেআউটে সমস্যা হয়।', NULL, 'পাইপের ভেতরের ব্যাস (internal diameter) দিয়ে পাইপের নমিনাল সাইজ নির্ধারণ করা হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2851, 459, 249, 'পিপিআর পাইপের সুবিধা কী?', 'written', 1, 'PPR পাইপ আধুনিক গৃহস্থালি ও বাণিজ্যিক স্থাপনায় জনপ্রিয়।', NULL, 'তাপ সহনশীল, মরিচা ধরে না, হালকা, এবং গরম ও ঠান্ডা উভয় পানির লাইনে ব্যবহার করা যায়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2852, 459, 249, 'পাইপ জয়েন্টে টেফলন টেপ কেন ব্যবহার করা হয়?', 'written', 1, 'টেফলন টেপ ছাড়া থ্রেডেড জয়েন্টে লিক হওয়ার সম্ভাবনা থাকে।', NULL, 'থ্রেডেড জয়েন্টকে লিক-প্রুফ করতে এবং টাইট করতে টেফলন টেপ ব্যবহার করা হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2853, 459, 249, 'পাইপ কাটার সময় কী কী সতর্কতা মানতে হয়?', 'written', 1, 'সতর্কতা না মানলে দুর্ঘটনা ও মানহীন কাজ হতে পারে।', NULL, 'পাইপ ভালোভাবে ধরে রাখতে হবে, সঠিক গতিতে টুল চালাতে হবে, PPE ব্যবহার করতে হবে এবং কাটার পর বার (burr) রিমার দিয়ে পরিষ্কার করতে হবে।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2854, 460, 249, 'পিপিআর পাইপ কীভাবে জোড়া দেওয়া হয়?', 'written', 1, 'তাপমাত্রা ও সময় সঠিক না হলে জোড়া দুর্বল হয়।', NULL, 'পিপিআর পাইপ হিট ওয়েল্ডিং পদ্ধতিতে জোড়া দেওয়া হয় — PPR ওয়েল্ডিং মেশিনে পাইপের মুখ গরম করে চাপ দিয়ে জোড়া দেওয়া হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2855, 460, 249, 'পিভিসি পাইপ জোড়ার জন্য কী ব্যবহার করা হয়?', 'written', 1, 'সলভেন্ট সিমেন্ট পাইপের পৃষ্ঠ গলিয়ে মজবুত জোড়া তৈরি করে।', NULL, 'পিভিসি পাইপ জোড়ার জন্য সলভেন্ট সিমেন্ট (PVC solvent cement) ব্যবহার করা হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2856, 460, 249, 'চেক ভালভের কাজ কী?', 'written', 1, 'পাম্পের সাকশন লাইনে চেক ভালভ না থাকলে পাম্প বন্ধ হলে পানি ফিরে আসে।', NULL, 'চেক ভালভ শুধুমাত্র এক দিকে পানি প্রবাহিত করতে দেয় এবং বিপরীত দিকে পানি ফিরে আসতে বাধা দেয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2857, 460, 249, 'গেট ভালভ ও বল ভালভের পার্থক্য কী?', 'written', 1, 'দ্রুত বন্ধ প্রয়োজনে বল ভালভ এবং ফ্লো নিয়ন্ত্রণে গেট ভালভ বেশি কার্যকর।', NULL, 'গেট ভালভ ধীরে ধীরে খোলে ও বন্ধ হয়। বল ভালভ ৯০° ঘুরিয়ে দ্রুত খোলা-বন্ধ করা যায়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2858, 460, 249, 'রিডিউসার কেন ব্যবহার করা হয়?', 'written', 1, 'রিডিউসার ব্যবহার করলে দুটি ভিন্ন সাইজের পাইপ সংযুক্ত করা সম্ভব হয়।', NULL, 'বড় ব্যাসের পাইপ থেকে ছোট ব্যাসের পাইপে সংযোগ দেওয়ার জন্য রিডিউসার ব্যবহার করা হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2859, 460, 249, 'এলবো কী? কত ডিগ্রির এলবো পাওয়া যায়?', 'written', 1, 'পাইপের দিক পরিবর্তনে সঠিক কোণের এলবো নির্বাচন করা জরুরি।', NULL, 'পাইপ লাইনের বাঁক পরিবর্তনের জন্য এলবো ব্যবহার হয়। সাধারণত ৪৫° এবং ৯০° এলবো পাওয়া যায়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2860, 460, 249, 'ইউনিয়ন ফিটিংস কেন ব্যবহার করা হয়?', 'written', 1, 'মেরামত বা পরিদর্শনের জন্য ইউনিয়ন অত্যন্ত কাজের।', NULL, 'ইউনিয়ন ব্যবহার করলে পাইপ লাইন সহজে খোলা ও বন্ধ করা যায় — পাইপ না কেটেই সংযোগ বিচ্ছিন্ন করা যায়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2861, 460, 249, 'সকেট কোথায় ব্যবহার হয়?', 'written', 1, 'একই ব্যাসের পাইপ একটানা লম্বা করতে সকেট লাগানো হয়।', NULL, 'সোজা পাইপ লাইন বাড়ানোর জন্য একই ব্যাসের দুটি পাইপ জোড়া দিতে সকেট ব্যবহার হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2862, 460, 249, 'UPVC পাইপের বৈশিষ্ট্য কী কী?', 'written', 1, 'UPVC পাইপ ড্রেনেজ ও ঠান্ডা পানির সাপ্লাইয়ে বহুল ব্যবহৃত।', NULL, 'মরিচা ধরে না, হালকা, সস্তা, সহজে কাটা ও জোড়া দেওয়া যায়, রাসায়নিক প্রতিরোধী।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2863, 460, 249, 'গ্লোব ভালভ ও গেট ভালভের পার্থক্য কী?', 'written', 1, 'দুটি ভালভের গঠন ভিন্ন বলে ব্যবহারের ক্ষেত্রও আলাদা।', NULL, 'গ্লোব ভালভ ফ্লো নিয়ন্ত্রণে (থ্রোটলিং) বেশি কার্যকর। গেট ভালভ সম্পূর্ণ খোলা বা বন্ধের জন্য ব্যবহার হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2864, 460, 249, 'পাইপ লাইনে টি-ফিটিংস কখন ব্যবহার হয়?', 'written', 1, 'একই সাইজের জন্য ইকুয়াল টি এবং ভিন্ন সাইজের জন্য রিডিউসিং টি ব্যবহার হয়।', NULL, 'এক লাইন থেকে আরেকটি লাইন শাখা করে নিতে টি-ফিটিংস ব্যবহার হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2865, 460, 249, 'পাইপ জয়েন্টের লিক কীভাবে পরীক্ষা করা হয়?', 'written', 1, 'জয়েন্ট লিক পরীক্ষা ছাড়া পাইপ লাইন চালু করা উচিত নয়।', NULL, 'পানি দিয়ে হাইড্রোলিক টেস্ট করে বা সাবান পানি লাগিয়ে বুদবুদ দেখে লিক পরীক্ষা করা হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2866, 461, 249, 'প্লাম্বিং ফিক্সচার বলতে কী বোঝায়?', 'written', 1, 'ফিক্সচার ইনস্টলে সঠিক প্লাম্বিং কানেকশন অপরিহার্য।', NULL, 'যে সব সরঞ্জাম সরাসরি পানি ব্যবহারের জন্য ব্যবহৃত হয় তাকে প্লাম্বিং ফিক্সচার বলে। যেমন: বেসিন, কমোড, বাথটাব।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2867, 461, 249, 'বেসিন ইনস্টল করার পদ্ধতি কী?', 'written', 1, 'প্রতিটি ধাপে সঠিকভাবে কাজ না করলে লিক বা অকার্যকারিতার সমস্যা হয়।', NULL, 'দেওয়ালে সাপোর্ট বোল্ট লাগানো, পি-ট্র্যাপ ওয়েস্ট পাইপে সংযোগ, সাপ্লাই পাইপে স্টপ কক লাগানো এবং লিক পরীক্ষা করা।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2868, 461, 249, 'কমোড ইনস্টল করার সময় কোন কোন বিষয় খেয়াল রাখতে হয়?', 'written', 1, 'কমোড সঠিকভাবে বসালে দুর্গন্ধ ও লিক রোধ করা যায়।', NULL, 'ফ্লোর ফ্ল্যাঞ্জের সাথে সঠিক সংযোগ, সিলিং রিং লাগানো, ফ্লাশ সিস্টার্নের সাথে সংযোগ এবং লিক পরীক্ষা করা।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2869, 461, 249, 'ফ্লাশ সিস্টার্নের কাজ কী?', 'written', 1, 'সিস্টার্ন সঠিকভাবে কাজ না করলে ফ্লাশিং ব্যর্থ হয়।', NULL, 'কমোড ফ্লাশ করার জন্য পানি সংরক্ষণ করে এবং প্রয়োজন মতো পানি ছেড়ে দেওয়া।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2870, 461, 249, 'পিলার কক কোথায় ব্যবহার হয়?', 'written', 1, 'পিলার কক বেসিনে পানির সরবরাহ ও বন্ধ করার কাজ করে।', NULL, 'বেসিন বা সিঙ্কের উপরে পানির কল হিসেবে ব্যবহার হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2871, 461, 249, 'শাওয়ার সিস্টেম কীভাবে ইনস্টল করতে হয়?', 'written', 1, 'শাওয়ার ইনস্টলে ঠান্ডা ও গরম পানির লাইন আলাদাভাবে সংযুক্ত করতে হয়।', NULL, 'শাওয়ার মিক্সার দেওয়ালে লাগানো, শাওয়ার রোজ সংযুক্ত করা, সাপ্লাই লাইন সংযোগ এবং ড্রেন লাইন ঠিক করা।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2872, 461, 249, 'পি-ট্র্যাপ কেন ব্যবহার করা হয়?', 'written', 1, 'পি-ট্র্যাপে পানির সিল দুর্গন্ধ আসতে বাধা দেয়।', NULL, 'ড্রেন লাইনের দুর্গন্ধ ও বিষাক্ত গ্যাস বেসিন বা সিঙ্কের মাধ্যমে ঘরে প্রবেশ রোধ করতে পি-ট্র্যাপ ব্যবহার করা হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2873, 461, 249, 'লো-ডাউন সিস্টার্ন কী?', 'written', 1, 'লো-ডাউন সিস্টার্ন আধুনিক বাথরুমে বেশি ব্যবহৃত।', NULL, 'কমোডের পেছনে সরাসরি লাগানো নিচু সিস্টার্ন। এটি হাই-লেভেল সিস্টার্নের তুলনায় কম উচ্চতায় থাকে।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2874, 461, 249, 'কনসিল্ড স্টপ কক কী?', 'written', 1, 'সারফেস স্টপ কক দেখা যায়, কনসিল্ড স্টপ কক দেয়ালের ভেতরে থাকে।', NULL, 'দেওয়ালের ভেতরে লুকানো স্টপ কক যা দেওয়ালের ভেতর থেকে পানি বন্ধ করতে পারে।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2875, 461, 249, 'বাথটাব ইনস্টলে কী কী নিশ্চিত করতে হয়?', 'written', 1, 'বাথটাব সমতল না হলে পানি একদিকে জমা হয়।', NULL, 'বাথটাব সমতলভাবে বসানো, ওয়েস্ট পাইপ ও ওভারফ্লো সংযোগ, সাপ্লাই মিক্সার সংযোগ এবং লিক টেস্ট।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2876, 461, 249, 'ফ্লোর ট্র্যাপ কোথায় ও কেন ব্যবহার হয়?', 'written', 1, 'ফ্লোর ট্র্যাপ মেঝেকে শুকনো ও পরিষ্কার রাখতে সাহায্য করে।', NULL, 'বাথরুম মেঝেতে বসানো হয় যাতে মেঝের পানি দ্রুত নিষ্কাশিত হয় এবং দুর্গন্ধ প্রতিরোধ হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2877, 461, 249, 'মিক্সার ট্যাপ কী?', 'written', 1, 'মিক্সার ট্যাপ শাওয়ার, বাথটাব ও বেসিনে ব্যবহার হয়।', NULL, 'একটি ট্যাপ যার মধ্য দিয়ে ঠান্ডা ও গরম পানি মিশিয়ে কাঙ্ক্ষিত তাপমাত্রায় পানি পাওয়া যায়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2878, 461, 249, 'সিঙ্ক কোথায় ব্যবহার হয় ও এর কাজ কী?', 'written', 1, 'রান্নাঘরের সিঙ্কে গরম পানির সংযোগও দেওয়া হয়।', NULL, 'রান্নাঘরে বাসন ধোয়া ও পানি ব্যবহারের জন্য সিঙ্ক ব্যবহার হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2879, 461, 249, 'ওভারফ্লো পাইপ কেন লাগানো হয়?', 'written', 1, 'ওভারফ্লো না থাকলে ট্যাংক উপচে পানি পড়তে পারে।', NULL, 'সিস্টার্ন বা ট্যাংক পূর্ণ হলে অতিরিক্ত পানি বের হয়ে যাওয়ার জন্য ওভারফ্লো পাইপ লাগানো হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2880, 461, 249, 'বেসিনে ওয়েস্ট কাপলিং কেন ব্যবহার হয়?', 'written', 1, 'ওয়েস্ট কাপলিং না থাকলে বেসিন থেকে পানি নিষ্কাশন সম্ভব নয়।', NULL, 'বেসিনের ছিদ্র (waste hole) ও ওয়েস্ট পাইপের মধ্যে সংযোগ দিতে এবং পানি নিষ্কাশনের জন্য।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2881, 461, 249, 'শাওয়ার ট্রে কী?', 'written', 1, 'শাওয়ার ট্রে বাথরুমের মেঝেকে পানি থেকে রক্ষা করে।', NULL, 'শাওয়ারের নিচে মেঝেতে ব্যবহৃত বেসিনের মতো প্ল্যাটফর্ম যা পানি সংগ্রহ করে ড্রেনে পাঠায়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2882, 461, 249, 'ইউরিনালের কাজ কী?', 'written', 1, 'ইউরিনাল সরাসরি ড্রেনেজ লাইনের সাথে সংযুক্ত থাকে।', NULL, 'পুরুষদের প্রস্রাবের জন্য ব্যবহৃত স্যানিটারি ফিক্সচার।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2883, 461, 249, 'বেসিনের ওভারফ্লো হোলের কাজ কী?', 'written', 1, 'ওভারফ্লো হোল বেসিনের পানি উপচে পড়া ও অপচয় রোধ করে।', NULL, 'বেসিন পূর্ণ হলে অতিরিক্ত পানি ওভারফ্লো হোলের মাধ্যমে নিষ্কাশিত হয় এবং উপচে পড়া রোধ করে।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2884, 461, 249, 'ওয়াশ বেসিন ইনস্টলের পর কোন কোন পরীক্ষা করতে হয়?', 'written', 1, 'পরীক্ষা না করলে পরে লিক বা ড্রেন ব্লকের সমস্যা হতে পারে।', NULL, 'পানি সরবরাহ ও নিষ্কাশনে লিক পরীক্ষা, ড্রেন ফ্লো পরীক্ষা এবং ট্র্যাপ সিল পরীক্ষা।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2885, 462, 249, 'বর্জ্য পানি নিষ্কাশন সিস্টেম বলতে কী বোঝায়?', 'written', 1, 'সঠিক নিষ্কাশন সিস্টেম পরিবেশ ও স্বাস্থ্য রক্ষায় গুরুত্বপূর্ণ।', NULL, 'গৃহস্থালি ও ব্যবহৃত পানি নিষ্কাশনের জন্য পাইপ, ট্র্যাপ, ম্যানহোল ও সেপটিক ট্যাংক নিয়ে গঠিত সিস্টেমকে বর্জ্য পানি নিষ্কাশন সিস্টেম বলে।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2886, 462, 249, 'সীল ট্র্যাপ কী? কীভাবে কাজ করে?', 'written', 1, 'ট্র্যাপে পানি না থাকলে সিল ভেঙে যায় এবং দুর্গন্ধ ঢুকতে পারে।', NULL, 'সীল ট্র্যাপ ড্রেন লাইনে পানি ধরে রেখে সিল তৈরি করে যা বর্জ্য পাইপের দুর্গন্ধ ও গ্যাস ঘরে প্রবেশ করতে দেয় না।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2887, 462, 249, 'ভেন্ট পাইপের কাজ কী?', 'written', 1, 'ভেন্ট পাইপ ছাড়া নিষ্কাশনে এয়ার লক হতে পারে।', NULL, 'ভেন্ট পাইপ নিষ্কাশন সিস্টেমে বায়ু চলাচল নিশ্চিত করে, ট্র্যাপের সিল রক্ষা করে এবং দুর্গন্ধ বাইরে বের করে দেয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2888, 462, 249, 'ম্যানহোল কী? কেন তৈরি করা হয়?', 'written', 1, 'ম্যানহোল ছাড়া মাটির নিচের পাইপ পরিষ্কার ও পরিদর্শন করা কঠিন।', NULL, 'মাটির নিচে তৈরি একটি পরিদর্শন কক্ষ যা দিয়ে ড্রেনেজ লাইন পরিষ্কার ও মেরামত করা যায়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2889, 462, 249, 'সয়েল পাইপ কোথায় ব্যবহার হয়?', 'written', 1, 'সয়েল পাইপের ব্যাস বড় হয় কারণ এটি ঘন বর্জ্য বহন করে।', NULL, 'কমোড ও ইউরিনাল থেকে বর্জ্য পানি (মলমূত্র সহ) নিষ্কাশনে সয়েল পাইপ ব্যবহার হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2890, 462, 249, 'ড্রেনেজ পাইপে ঢাল কত রাখতে হয়?', 'written', 1, 'ঢাল কম হলে পাইপে পলি জমে এবং বেশি হলে গ্যাস বের হয়ে ট্র্যাপ খালি হয়।', NULL, 'সাধারণত ১:৪০ (২.৫%) ঢাল রাখা হয় যাতে মাধ্যাকর্ষণ বলে পানি প্রবাহিত হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2891, 462, 249, 'পি-ট্র্যাপ ও এস-ট্র্যাপের পার্থক্য কী?', 'written', 1, 'সংযোগের অবস্থান অনুযায়ী সঠিক ট্র্যাপ নির্বাচন করতে হয়।', NULL, 'পি-ট্র্যাপ দেওয়ালে সংযুক্ত হয় এবং এস-ট্র্যাপ মেঝেতে/নিচে সংযুক্ত হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2892, 462, 249, 'সেপটিক ট্যাংক কীভাবে কাজ করে?', 'written', 1, 'সেপটিক ট্যাংক পরিষ্কার রাখতে নিয়মিত পরিদর্শন করতে হয়।', NULL, 'গৃহস্থালির বর্জ্য সেপটিক ট্যাংকে জমা হয়, ব্যাকটেরিয়া দ্বারা পচন হয় এবং তরল অংশ সোক পিটে চলে যায়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2893, 462, 249, 'ম্যাজিক পাইপ কোথায় ব্যবহার হয়?', 'written', 1, 'ম্যাজিক পাইপ বাঁকানো যায় তাই সহজে লাগানো যায়।', NULL, 'সিঙ্কের ওয়েস্ট পাইপে নমনীয় সংযোগ হিসেবে এবং বর্জ্য পানির লাইনে ব্যবহার হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2894, 462, 249, 'ড্রেন রড দিয়ে কী কাজ করা হয়?', 'written', 1, 'ড্রেন রড না থাকলে আটকে যাওয়া পাইপ পরিষ্কার করা কঠিন।', NULL, 'বন্ধ বা আটকানো ড্রেন পাইপ পরিষ্কার করতে ড্রেন রড ব্যবহার হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2895, 462, 249, 'ফ্লোর ড্রেন কেন দেওয়া হয়?', 'written', 1, 'ফ্লোর ড্রেন না থাকলে মেঝেতে পানি জমে থাকে।', NULL, 'বাথরুম, রান্নাঘর বা ব্যালকনির মেঝে থেকে পানি দ্রুত সরিয়ে নেওয়ার জন্য ফ্লোর ড্রেন দেওয়া হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2896, 462, 249, 'ড্রেনেজ সিস্টেমের দুটি মূল উপাদান কী কী?', 'written', 1, 'দুটি উপাদান একসাথে সঠিকভাবে কাজ করলে নিষ্কাশন সুষ্ঠু হয়।', NULL, 'সয়েল/ওয়েস্ট পাইপ এবং ভেন্ট পাইপ — এই দুটি ড্রেনেজ সিস্টেমের মূল উপাদান।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2897, 462, 249, 'গৃহে দূষিত গ্যাস প্রবেশ কীভাবে রোধ করা যায়?', 'written', 1, 'ট্র্যাপের পানি শুকিয়ে গেলে দুর্গন্ধ ঢুকতে পারে, তাই নিয়মিত পানি দেওয়া দরকার।', NULL, 'সীল ট্র্যাপ ও ভেন্ট পাইপের মাধ্যমে গৃহে দূষিত গ্যাস প্রবেশ রোধ করা যায়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2898, 462, 249, 'ইউপিভিসি পাইপ ড্রেনেজ কাজে বেশি ব্যবহারের কারণ কী?', 'written', 1, 'ইউপিভিসি পাইপের দীর্ঘ আয়ু এটিকে ড্রেনেজে জনপ্রিয় করেছে।', NULL, 'টেকসই, মরিচা ধরে না, রাসায়নিক প্রতিরোধী, হালকা এবং সহজে ইনস্টল করা যায়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
(2899, 462, 249, 'ড্রেনেজ পাইপ ইনস্টলের পর পরীক্ষার পদ্ধতি কী?', 'written', 1, 'ইনস্টলের পরে লিক পরীক্ষা না করলে ভবিষ্যতে বড় সমস্যা হতে পারে।', NULL, 'পানি দিয়ে হাইড্রোলিক টেস্ট করে অথবা ধোঁয়া পরীক্ষায় লিক সনাক্ত করা হয়।', 0, '2026-05-27 06:50:19', '2026-05-27 06:50:19'),
