(3033, 494, 302, 'সোলার প্যানেল দুপুরের তীব্র রোদে ঠান্ডা পানি দিয়ে ধুলে কী সমস্যা হতে পারে?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3034, 494, 302, 'ব্যাটারির চারপাশের পরিবেশ কেমন হওয়া উচিত যাতে ব্যাটারির আয়ু বেশি থাকে?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3035, 494, 302, 'মাল্টিমিটারে তারের দুই প্রান্তের রোধ (Resistance) পরিমাপ করার সময় যদি মান অতি উচ্চ বা অসীম (Infinity) দেখায়, তবে তারটি কেমন?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3036, 494, 302, 'সোলার স্ট্রিট লাইট দিনেও জ্বলজ্বল করে জ্বলছে, এর সম্ভাব্য কারণ কী?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3037, 494, 302, 'ব্যাটারির প্লেটে শক্ত সাদা সালফেশনের আস্তরণ পড়ে যাওয়ার ঘটনাকে কী বলা হয়?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3038, 494, 302, 'সোলার সিস্টেমে শর্ট সার্কিট জনিত অতিরিক্ত কারেন্ট প্রবাহিত হলে ডিভাইস রক্ষা করে কোনটি?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3039, 494, 302, 'চার্জ কন্ট্রোলারে চার্জিং নির্দেশক লাইট (LED) ব্লিঙ্ক করছে না বা জ্বলছে না, এর প্রাথমিক পরীক্ষা কোনটি হওয়া উচিত?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3040, 494, 302, 'সোলার সিস্টেমে ব্যাটারির ভোল্টেজ ঠিক আছে কিন্তু লোড চলছে না, এর সম্ভাব্য কারণ কোনটি?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3041, 494, 302, 'সোলার সিস্টেমে রক্ষণাবেক্ষণের সময় প্যানেলের ভোল্টেজ মাপার আগে কী পরীক্ষা করা উচিত?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3042, 494, 302, 'চার্জ কন্ট্রোলার স্থাপনের উপযুক্ত স্থান কোনটি?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3043, 494, 302, 'সোলার প্যানেলের কাচ ফাটলে বা সেল ক্ষতিগ্রস্ত হলে কী করা উচিত?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3044, 494, 302, 'সোলার সিস্টেমে রুটিন রক্ষণাবেক্ষণ (Routine Maintenance) কেন প্রয়োজন?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3045, 494, 302, 'সোলার স্ট্রিট লাইটের লুমিনারি (LED) হালকা হালকা জ্বলছে কিন্তু পূর্ণ আলো দিচ্ছে না, এর কারণ কী?', 'mcq', 1, NULL, NULL, NULL, 0, '2026-06-02 23:00:17', '2026-06-02 23:00:17'),
(3046, 485, 302, '১ মি * ১মি = কত ফিট২?', 'written', 1, '১ মিটার প্রায় ৩.২৮ ফুট হওয়ায় ১ বর্গমিটার সমান ১০.৭৬ বর্গফুট (বা ১০.৭৫ ফিট২) হিসাব করা হয়।', NULL, '১০.৭৫ ফিট২ (প্রায়)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3047, 485, 302, 'সোলার সিস্টেমে দক্ষতা (Efficiency) কীভাবে শতকরা (Percentage) হিসাবে প্রকাশ করা হয়?', 'written', 1, 'উৎপন্ন বিদ্যুতের মোট শক্তি ও প্রাপ্ত সূর্যালোকের মোট শক্তির অনুপাতই হলো সোলার প্যানেলের দক্ষতা।', NULL, 'সোলার প্যানেল বা সিস্টেমের দক্ষতা = (আউটপুট পাওয়ার ÷ ইনপুট পাওয়ার) × ১০০%।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3048, 485, 302, 'একটি ১২ ভোল্টের (12V) ১০০ অ্যাম্পিয়ার-আওয়ার (100Ah) ব্যাটারির মোট শক্তি কত ওয়াট-ঘণ্টা (Wh)?', 'written', 1, 'ভোল্টেজ ও অ্যাম্পিয়ার-আওয়ার গুণ করলে ব্যাটারির মোট সঞ্চিত শক্তি ওয়াট-ঘণ্টায় পাওয়া যায়।', NULL, '১২ ভোল্ট × ১০০ Ah = ১২০০ ওয়াট-ঘণ্টা (Wh)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3049, 485, 302, '৩টি সোলার প্যানেল সমান্তরাল সংযোগে থাকলে প্রতিটি প্যানেল ৮ অ্যাম্পিয়ার কারেন্ট দিলে মোট কারেন্ট কত হবে?', 'written', 1, 'সমান্তরাল সংযোগে কারেন্ট যোগ হয় কিন্তু ভোল্টেজ সমান থাকে।', NULL, 'মোট কারেন্ট = ৮ + ৮ + ৮ = ২৪ অ্যাম্পিয়ার।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3050, 485, 302, '১ ইঞ্চি সমান কত সেন্টিমিটার (cm) এবং কত মিলিমিটার (mm)?', 'written', 1, 'পরিমাপ পদ্ধতিতে ইঞ্চি ও মিলিমিটারের মধ্যে এটি একটি প্রমাণ রূপান্তর মান।', NULL, '১ ইঞ্চি = ২.৫৪ সেন্টিমিটার (cm) এবং ২৫.৪ মিলিমিটার (mm)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3051, 486, 302, 'PPE কি? কয়েকটি PPE এর নাম লিখ।', 'written', 1, 'PPE হলো Personal Protective Equipment বা ব্যক্তিগত সুরক্ষা সরঞ্জাম। সোলার কাজে ব্যবহৃত কয়েকটি PPE হলো: এপ্রোন, সেফটি জুতো, গগলস, সেফটি বেল্ট ও হ্যান্ড গ্লোভস।', NULL, 'PPE মানে Personal Protective Equipment (ব্যক্তিগত সুরক্ষা সরঞ্জাম)। কয়েকটি PPE হলো: এপ্রোন, সেফটি সু, সেফটি গগলস, সেফটি বেল্ট, এয়ার প্লাগ ও হ্যান্ড গ্লোভস।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3052, 486, 302, 'ফিজিক্যাল হ্যাজার্ড কি?', 'written', 1, 'কর্মক্ষেত্রে পিচ্ছিল মেঝে, পর্যাপ্ত আলোর অভাব বা অসমান তলের কারণে পা পিছলে পড়ে গিয়ে যে শারীরিক আঘাতের সম্ভাবনা থাকে তাকে ফিজিক্যাল হ্যাজার্ড বলে।', NULL, 'পিচ্ছিল মেঝে, উঁচু-নিচু মেঝে বা অল্প আলোতে কাজ করার কারণে যে সকল দুর্ঘটনা ঘটার সম্ভাবনা থাকে তাকে ফিজিক্যাল হ্যাজার্ড বলে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3053, 486, 302, 'দাহ্য পদার্থ কি?', 'written', 1, 'যেসব পদার্থ খুব কম তাপমাত্রায় বাতাসে সহজেই আগুন ধরে যায় এবং পুড়ে ধ্বংস হয় তাদের দাহ্য পদার্থ বলে, যেমন: পেট্রোল, গ্যাসোলিন ও কেরোসিন।', NULL, 'যেসব পদার্থে খুব সহজে আগুন ধরে যায় তাদের দাহ্য পদার্থ বলে, যেমন: পেট্রোল, অক্টেন ও কেরোসিন তেল।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3054, 486, 302, 'ব্যাটারী কেন বিপদজনক?', 'written', 1, 'ব্যাটারির ভেতরে ক্ষতিকর এসিড থাকে, চার্জিংয়ের সময় দাহ্য হাইড্রোজেন গ্যাস নির্গত হয় এবং এতে উচ্চ শর্ট-সার্কিট কারেন্ট থাকায় এটি অত্যন্ত ঝুঁকিপূর্ণ।', NULL, 'কারণ ব্যাটারিতে এসিড থাকে, চার্জিংয়ের সময় হাইড্রোজেন গ্যাস উৎপন্ন হয় যা বিস্ফোরক এবং এতে উচ্চ শক্তির শর্ট সার্কিট কারেন্ট থাকে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3055, 486, 302, 'ওশ (OSH) পলিসির প্রধান উদ্দেশ্য কী?', 'written', 1, 'নিরাপদ কর্মপরিবেশ নিশ্চিত করার জন্য ওশ বা পেশাগত নিরাপত্তা আইন অত্যন্ত গুরুত্বপূর্ণ ভূমিকা পালন করে।', NULL, 'কর্মক্ষেত্রে শ্রমিকদের পেশাগত স্বাস্থ্য ও নিরাপত্তা নিশ্চিত করা এবং সব ধরনের কাজের ঝুঁকি ও দুর্ঘটনা হ্রাস করা।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3056, 487, 302, 'নবায়নযোগ্য শক্তি কাকে বলে? উদাহরণ দাও।', 'written', 1, 'যে সকল শক্তির উৎস প্রাকৃতিক এবং ব্যবহারের ফলে কখনো শেষ হয়ে যায় না, বরং প্রাকৃতিকভাবেই বারবার নতুন করে তৈরি হয়, তাকে নবায়নযোগ্য শক্তি বলে। উদাহরণ: সৌরশক্তি, বায়ুশক্তি ও জলশক্তি।', NULL, 'যে সকল প্রাকৃতিক শক্তি পুনরায় ব্যবহার করা যায় তাকে নবায়নযোগ্য শক্তি বলে। যেমন: সৌর শক্তি, বায়ু শক্তি, জোয়ার ভাটা, জল শক্তি।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3057, 487, 302, 'শক্তি কত প্রকার ও কি কি?', 'written', 1, 'শক্তির উৎস প্রধানত দুই প্রকার। ১) নবায়নযোগ্য শক্তি (যা কখনো ফুরিয়ে যায় না) ২) অনবায়নযোগ্য শক্তি (যেমন কয়লা, তেল, যা ব্যবহারের ফলে একসময় শেষ হয়ে যাবে)।', NULL, 'দুই প্রকার। ১) নবায়নযোগ্য শক্তি ২) অনবায়নযোগ্য শক্তি।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3058, 487, 302, 'সৌর কোষ কি?', 'written', 1, 'সৌর কোষ বা সোলার সেল হলো একটি ক্ষুদ্র অর্ধপরিবাহী (Semiconductor) ডিভাইস যা ফোটোভোলটাইক প্রক্রিয়ায় সূর্যের আলোক শক্তিকে সরাসরি ডিসি (DC) বিদ্যুৎ শক্তিতে রূপান্তর করে।', NULL, 'সৌর কোষ এমন একটি ডিভাইস যা আলোক শক্তিকে বিদ্যুৎ শক্তিতে রূপান্তর করে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3059, 487, 302, 'একটি মডিউল সূর্যের কোন শক্তি ব্যবহার করে বিদ্যুৎ উৎপন্ন করে?', 'written', 1, 'সোলার মডিউল সূর্যের আলোর মধ্যে থাকা ক্ষুদ্র শক্তির কণা \'ফোটন\' (Photon) শোষণ করে এবং অর্ধপরিবাহীর ইলেকট্রনকে সচল করে বিদ্যুৎ তৈরি করে।', NULL, 'ফোটন কণা।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3060, 487, 302, 'সূর্যের আলোর কোন কণার সাহায্যে সোলার প্যানেল বিদ্যুৎ উৎপন্ন করে?', 'written', 1, 'সূর্যের আলোর মধ্যে থাকা শক্তি কণা যাকে ফোটন (Photon) বলা হয়, তা সোলার সেলের উপর পড়লে ইলেকট্রন মুক্ত হয়ে বিদ্যুৎ প্রবাহের সৃষ্টি করে।', NULL, 'ফোটন কণা।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3061, 488, 302, 'একটি সেলে কত ভোল্টেজ থাকে?', 'written', 1, 'একটি আদর্শ সৌর কোষ বা সেলে আলো পড়লে তা থেকে সাধারণত ০.৫ ভোল্ট (0.5V) বিদ্যুৎ উৎপন্ন হয়।', NULL, '০.৫ ভোল্ট।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3062, 488, 302, 'সোলার প্যানেল থেকে কোন ধরনের ভোল্টেজ পাওয়া যায়?', 'written', 1, 'সোলার প্যানেল সূর্যালোক থেকে সরাসরি ডিসি বা একমুখী প্রবাহের (Direct Current) ভোল্টেজ ও কারেন্ট উৎপাদন করে।', NULL, 'ডিসি (DC) ভোল্টেজ।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3063, 488, 302, 'সেল কি?', 'written', 1, 'সেল হলো এমন একটি একক উপাদান যার অভ্যন্তরে রাসায়নিক বিক্রিয়ার মাধ্যমে অথবা আলোর প্রভাবে ইলেকট্রন সচল হয়ে বৈদ্যুতিক শক্তি বা কারেন্ট উৎপন্ন হয়।', NULL, 'যে জিনিসের ভিতর রাসায়নিক দ্রব্য সঞ্চিত থাকার ফলে বিদ্যুৎ উৎপন্ন হয়, তাকে সেল বলে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3064, 488, 302, 'ইলেক্ট্রোলাইট কি?', 'written', 1, 'ইলেক্ট্রোলাইট হলো এমন একটি তরল দ্রবণ (যেমন ব্যাটারিতে সালফিউরিক এসিড ও পানির মিশ্রণ) যা পানিতে আয়নিত হয়ে বিদ্যুৎ পরিবাহী হিসেবে কাজ করে।', NULL, 'যদি কোন দ্রাবক পানির সাথে মিশে নিজে নিজেই আয়নাইজড হয়ে যায়, তাকে ইলেক্ট্রোলাইট বলে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3065, 488, 302, 'ব্যাটারী কি?', 'written', 1, 'ব্যাটারি হলো একাধিক রাসায়নিক সেলের সমন্বয় যা রাসায়নিক শক্তিকে ডিসি (DC) বিদ্যুৎ শক্তি হিসেবে জমা রাখে এবং প্রয়োজনে সরবরাহ করে।', NULL, 'কতগুলি সেলের সমন্বয় বা সমষ্টিকে ব্যাটারি বলে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3066, 488, 302, 'ব্যাটারীর কারেন্ট রেটিং / AH কি?', 'written', 1, 'AH মানে Ampere-Hour যা নির্দেশ করে একটি ব্যাটারি নির্দিষ্ট ভোল্টেজে কত অ্যাম্পিয়ার কারেন্ট কত ঘণ্টা ধরে লোডে সরবরাহ করতে পারবে (যেমন ১০০Ah ব্যাটারি ১০ ঘণ্টা ১০ অ্যাম্পিয়ার দিতে পারে)।', NULL, 'একটি নির্দিষ্ট সময়ে (ঘণ্টা) ব্যাটারি থেকে যে পরিমাণ কারেন্ট (অ্যাম্পিয়ার) ডিসচার্জ হয় তাকে অ্যাম্পিয়ার-আওয়ার (AH) বলে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3067, 488, 302, 'ইনভার্টার কাকে বলে?', 'written', 1, 'ইনভার্টার হলো একটি পাওয়ার ইলেকট্রনিক্স ডিভাইস যা সোলার প্যানেল বা ব্যাটারির ডিসি (DC) বিদ্যুৎকে গৃহস্থালির যন্ত্রপাতি চালানোর উপযোগী অল্টারনেটিং কারেন্ট বা এসি (AC) বিদ্যুতে রূপান্তর করে।', NULL, 'যে ডিভাইস ডিসি (DC) বিদ্যুৎকে এসি (AC) বিদ্যুতে রূপান্তরিত করে তাকে ইনভার্টার বলে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3068, 488, 302, 'ইনভার্টারের ক্ষমতা কোন একক দ্বারা প্রকাশ করা হয়?', 'written', 1, 'ইনভার্টারের আউটপুট ক্ষমতা সাধারণ ওয়াট (Watt), কিলোওয়াট (kW) অথবা ভোল্ট-অ্যাম্পিয়ার (VA) এককে প্রকাশ করা হয়।', NULL, 'ওয়াট (W) বা ভোল্ট-অ্যাম্পিয়ার (VA)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3069, 488, 302, 'ইনভার্টার কেন ব্যবহার করা হয়?', 'written', 1, 'যেহেতু সোলার প্যানেল ও ব্যাটারি ডিসি বিদ্যুৎ দেয়, কিন্তু আমাদের ঘরের ফ্যান, লাইট, টিভি এসি বিদ্যুতে চলে, তাই এসি লোড সচল রাখতে ইনভার্টার ব্যবহার করা হয়।', NULL, 'সোলার সিস্টেমের ডিসি বিদ্যুৎকে গৃহস্থালির এসি লোড চালানোর উপযোগী এসি বিদ্যুতে রূপান্তরের জন্য।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3070, 488, 302, 'সাধারণ বাতির তুলনায় CFL বাতি কি পরিমাণ বিদ্যুৎ সাশ্রয়ী?', 'written', 1, 'একটি ঐতিহ্যবাহী ভাস্বর বা ফিলামেন্ট বাল্বের তুলনায় সমপরিমাণ আলো দিতে সিএফএল বাতি প্রায় ৮০% বিদ্যুৎ সাশ্রয় করে।', NULL, 'প্রায় ৮০% বিদ্যুৎ সাশ্রয়ী।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3071, 489, 302, 'সোলার হোম সিস্টেমের অটোমি (Autonomy) কত দিন ধরা হয়?', 'written', 1, 'সোলার হোম সিস্টেম ডিজাইনের সময় সূর্যালোক ছাড়া ব্যাটারি ব্যাকআপ দেওয়ার সক্ষমতা বা অটোনমি সাধারণত ৩ দিন ধরা হয়।', NULL, 'সাধারণত ৩ দিন।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3072, 489, 302, 'সিস্টেম ডিজাইন করতে কি প্রয়োজন?', 'written', 1, 'গ্রাহকের সোলার সিস্টেম ডিজাইনের জন্য প্রথমে সব লোডের ক্ষমতা ও তা দৈনিক কত সময় চলবে তার নির্ভুল হিসাব বা লোড ক্যালকুলেশন প্রয়োজন।', NULL, 'গ্রাহকের দৈনিক মোট লোড ক্যালকুলেশন এবং ব্যবহারের সময়কাল নির্ধারণ করা প্রয়োজন।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3073, 489, 302, 'দৈনিক ওয়াট-ঘণ্টা (Wh) কীভাবে হিসাব করা হয়?', 'written', 1, 'লোড এস্টিমেশন করার সময় প্রতিটি লোডের ক্ষমতা ও তা চলার সময় গুণ করে দৈনিক শক্তি চাহিদা বের করা হয়।', NULL, 'দৈনিক ওয়াট-ঘণ্টা = সরঞ্জামের মোট ক্ষমতা (ওয়াট) × দৈনিক ব্যবহারের সময় (ঘণ্টা)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3074, 489, 302, 'অফ-গ্রিড সোলার সিস্টেমে ব্যাটারির সাইজ নির্ধারণে কোন বিষয়গুলো বিবেচনা করতে হয়?', 'written', 1, 'সঠিক সাইজের ব্যাটারি নির্বাচন করলে সিস্টেমটি দীর্ঘ সময় ধরে কোনো সূর্যালোক ছাড়া লোড সচল রাখতে পারে।', NULL, 'দৈনিক মোট লোডের চাহিদা (Wh), ব্যাটারির ভোল্টেজ (V), অটোনমি দিন (Autonomy Days) এবং ডিসচার্জ গভীরতা (DOD)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3075, 489, 302, 'পাওয়ার লস এবং ইনভার্টারের লস সহ সোলার সিস্টেম ডিজাইনে বাড়তি কত শতাংশ নিরাপত্তা মার্জিন যোগ করা হয়?', 'written', 1, 'সিস্টেমের দক্ষতা শতভাগ না হওয়ায় এই বাড়তি লোড হিসাব করে প্যানেল ও ব্যাটারির আকার বাড়ানো হয়।', NULL, 'সাধারণত ১৫% থেকে ২৫% বাড়তি লোড নিরাপত্তা মার্জিন বা লস ফ্যাক্টর হিসেবে যোগ করা হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3076, 490, 302, 'সিস্টেম স্থাপনে কোনটি প্রয়োজন?', 'written', 1, 'সঠিকভাবে প্যানেলের মুখ দক্ষিণ দিকে বসানোর জায়গা, ছাদ বা জমির ছায়ামুক্ত স্থান এবং তারের রুট যাচাই করতে সাইট ভিজিট (Site Visit) প্রয়োজন।', NULL, 'সঠিকভাবে মাউন্টিং দিক, ছায়া মুক্ত স্থান ও ওয়্যারিং রুট নির্ধারণের জন্য সাইট ভিজিট (Site Visit) প্রয়োজন।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3077, 490, 302, 'সোলার ওয়্যারিং ডায়াগ্রামের (Wiring Diagram) প্রধান কাজ কী?', 'written', 1, 'ইনস্টলেশনের সময় টেকনিশিয়ানরা এই ওয়্যারিং ডায়াগ্রাম দেখে নিখুঁত সংযোগ নিশ্চিত করেন।', NULL, 'সিস্টেমের বিভিন্ন উপাদানের (প্যানেল, কন্ট্রোলার, ব্যাটারি, লোড) মধ্যে তারের সংযোগ পথ ও টার্মিনালগুলোর সঠিক অবস্থান প্রদর্শন করা।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3078, 490, 302, 'সোলার মাউন্টিং স্ট্রাকচার ড্রয়িং কেন প্রয়োজন?', 'written', 1, 'সঠিক স্ট্রাকচার ড্রয়িং অনুসরণ করলে ঝড় বা বাতাসে প্যানেল ভেঙে যাওয়ার ঝুঁকি থাকে না।', NULL, 'প্যানেলটি ছাদ বা পোলের উপর কত কোণে এবং কীভাবে বসানো হবে তার সঠিক মাপ ও দিক নির্দেশনা জানার জন্য মাউন্টিং ড্রয়িং প্রয়োজন।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3079, 490, 302, 'সিঙ্গেল লাইন ডায়াগ্রাম (SLD) বলতে কী বোঝায়?', 'written', 1, 'এসএলডি এর মাধ্যমে পুরো সিস্টেমের বিদ্যুৎ প্রবাহের রুট সহজে বোঝা যায়।', NULL, 'সোলার সিস্টেমের জটিল ইলেকট্রিক্যাল সার্কিটকে সহজভাবে একটি মাত্র লাইনের মাধ্যমে প্রদর্শন করার ডায়াগ্রামকে সিঙ্গেল লাইন ডায়াগ্রাম বলে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3080, 490, 302, 'সোলার ড্রয়িংয়ে আর্থিং (Earthing/Grounding) এর প্রতীক চিহ্নটি কেমন থাকে?', 'written', 1, 'আর্থিং চিহ্নটি সিস্টেমে অতিরিক্ত বিদ্যুৎ মাটিতে নিরাপদে সরিয়ে নেওয়ার ওয়্যারিং নির্দেশ করে।', NULL, 'একটি খাড়া রেখার নিচে অনুভূমিকভাবে ক্রমশ ছোট হয়ে যাওয়া ৩টি সমান্তরাল রেখা দিয়ে আর্থিং নির্দেশ করা হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3081, 490, 302, 'সোলার লেআউট ড্রয়িংয়ে \"PV Module\" এর চিহ্নটি কেমন দেখায়?', 'written', 1, 'সোলার ড্রয়িংয়ে সহজেই প্যানেল চেনার জন্য এই গ্রিড আকৃতির প্রতীকটি ব্যবহার করা হয়।', NULL, 'একটি আয়তক্ষেত্রের ভেতরে কয়েকটি ছোট ছোট বর্গাকার ঘর বা গ্রিড এঁকে পিভি মডিউল বা প্যানেল নির্দেশ করা হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3082, 490, 302, 'সোলার স্ট্রিট লাইটের লেআউটে ব্যাটারি বক্সটি সাধারণত কোথায় বসানোর নিয়ম থাকে?', 'written', 1, 'নিরাপত্তা ও ওজন ভারসাম্যের জন্য ব্যাটারিকে পোলের নিচের দিকে স্থাপন করাই ড্রয়িংয়ের নিয়ম।', NULL, 'লেআউট অনুযায়ী ব্যাটারি বক্সটি পোলের গোড়ার মাটির নিচে বা পোলের নিচের দিকে ধাতব বক্সে বসানো হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3083, 490, 302, 'ড্রয়িংয়ে ফিউজ (Fuse) এর প্রতীক চিহ্নটি কীরূপ হয়?', 'written', 1, 'ফিউজের প্রতীকটি সার্কিটকে ওভার কারেন্ট থেকে রক্ষা করার সুরক্ষামূলক উপাদান নির্দেশ করে।', NULL, 'একটি আয়তক্ষেত্রের মাঝখান দিয়ে একটি সরলরেখা চলে গেলে বা এস (S) আকৃতির ঢেউ খেলানো রেখা দিয়ে ফিউজ নির্দেশ করা হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3084, 490, 302, 'সোলার সিস্টেমে সাইট ভিজিট (Site Visit) করে ড্রয়িং ডিজাইন করার সময় কোন বিষয়টি সবচেয়ে বেশি খেয়াল রাখতে হয়?', 'written', 1, 'ছায়ামুক্ত স্থান ও সঠিক দিক নির্বাচন করতে পারলে প্যানেলের বিদ্যুৎ উৎপাদন সর্বোচ্চ পর্যায়ে পৌঁছায়।', NULL, 'প্যানেল স্থাপন স্থানে গাছ বা ভবনের কোনো ছায়া পড়ে কিনা (Shadow-free area) এবং প্যানেলের মুখ দক্ষিণ দিকে রাখা যায় কিনা।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3085, 490, 302, 'সোলার ডায়াগ্রামে ইনভার্টারের ইনপুট ও আউটপুট চিহ্ন কীভাবে দেখানো হয়?', 'written', 1, 'এটি নির্দেশ করে যে ইনভার্টার ডিসি ভোল্টেজকে পরিবর্তনশীল এসি ভোল্টেজে রূপান্তর করছে।', NULL, 'ইনপুটের দিকে ডিসি (=) চিহ্ন এবং আউটপুটের দিকে এসি (~) চিহ্ন দিয়ে ইনভার্টার ব্লক নির্দেশ করা হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3086, 490, 302, 'তারের ড্রয়িং লেআউটে সংযোগ বিন্দু (Connection Point) এবং ক্রস ওভার (Cross over) কীভাবে বোঝানো হয়?', 'written', 1, 'এটি ওয়্যারিংয়ে কোন দুটি তারের মধ্যে শর্ট কানেকশন আছে এবং কোনটি বিচ্ছিন্ন তা বুঝতে সাহায্য করে।', NULL, 'সংযুক্ত তারের সংযোগস্থলে একটি ভরাট বৃত্ত (ডট) থাকে এবং সংযোগহীন তারের ক্রসিংয়ের সময় একটি তার ওপর দিয়ে লুপ করে চলে যায়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3087, 490, 302, 'সোলার স্ট্রিট লাইট ইন্সটলেশন ড্রয়িংয়ে পোলের ভিতরের তারের রুট কীভাবে দেখানো হয়?', 'written', 1, 'পোলের ভেতর দিয়ে তার টানার রুট প্রদর্শন করলে ওয়্যারিং সুরক্ষিত ও পরিষ্কার হয়।', NULL, 'পোলের কেন্দ্র বরাবর ডটেড বা ড্যাশ রেখা দিয়ে কন্ডুইট ও তারের রুট দেখানো হয় যা প্যানেল থেকে ব্যাটারি বক্সে যায়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3088, 490, 302, 'সোলার সিস্টেমে সার্কিট ব্রেকার (MCB) এর ড্রয়িং প্রতীকটি কেমন হয়?', 'written', 1, 'সার্কিট ব্রেকারের প্রতীকটি অতিরিক্ত কারেন্ট প্রবাহে স্বয়ংক্রিয়ভাবে সার্কিট খোলার কাজ নির্দেশ করে।', NULL, 'একটি সুইচের প্রতীকের মতো কিন্তু তার ওপর একটি ছোট অর্ধবৃত্ত বা হুক চিহ্ন দিয়ে সার্কিট ব্রেকার নির্দেশ করা হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3089, 490, 302, 'সোলার ওয়্যারিংয়ে তারের সাইজ এবং কন্ডুইটের ব্যাস কোথায় লেখা থাকে?', 'written', 1, 'স্পেসিফিকেশন টেবিলে মেটেরিয়ালের সঠিক পরিমাপ ও ধরন উল্লেখ করা থাকে যা ইনস্টলারদের সহায়ক হয়।', NULL, 'লেআউট ড্রয়িংয়ের স্পেসিফিকেশন টেবিল বা লিজেন্ডে (Legend) তারের সাইজ এবং কন্ডুইটের ব্যাস লেখা থাকে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3090, 490, 302, 'সোলার প্যানেলের মাউন্টিং লেআউটে \"Wind Load\" স্পেসিফিকেশন বলতে কী বোঝায়?', 'written', 1, 'বাতাসের গতিবেগ বিবেচনা করে মাউন্টিং ফ্রেমের বোল্ট এবং ভিত্তির সাইজ নির্ধারণ করা হয়।', NULL, 'মাউন্টিং স্ট্রাকচারটি সর্বোচ্চ কত বেগে বয়ে যাওয়া বাতাস বা ঝড়ের চাপ সহ্য করতে পারবে তার হিসাব।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3091, 491, 302, 'ব্যাটারীর সাধারন দুইটি পরীক্ষার নাম লিখ।', 'written', 1, '১) ভোল্টমিটারের সাহায্যে ব্যাটারির টার্মিনাল ভোল্টেজ পরীক্ষা এবং ২) হাইড্রোমিটারের সাহায্যে ইলেক্ট্রোলাইটের আপেক্ষিক গুরুত্ব বা ঘনত্ব পরীক্ষা।', NULL, '১) ভোল্টমিটারের সাহায্যে ব্যাটারির টার্মিনাল ভোল্টেজ পরীক্ষা ২) হাইড্রোমিটারের সাহায্যে ইলেক্ট্রোলাইটের আপেক্ষিক গুরুত্ব পরীক্ষা।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3092, 491, 302, 'ব্যাটারীর ইলেক্ট্রোলাইটের আপেক্ষিক গুরুত্ব কিসের সাহায্যে পরিমাপ করা হয়?', 'written', 1, 'ব্যাটারির ভেতরের ইলেক্ট্রোলাইটের আপেক্ষিক গুরুত্ব হাইড্রোমিটার নামক একটি বিশেষ কাচের টেস্ট টুলের সাহায্যে পরিমাপ করা হয়।', NULL, 'হাইড্রোমিটারের সাহায্যে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3093, 491, 302, 'তারের উপরের ইনসুলেশন উঠানোর জন্য কি টুলস ব্যবহার করা হয়?', 'written', 1, 'তারের তামার পরিবাহীকে অক্ষত রেখে ওপরের প্লাস্টিক আবরণটি সুন্দরভাবে সরাতে ওয়্যার স্ট্রিপার (Wire Stripper) ব্যবহার করা হয়।', NULL, 'ওয়্যার স্ট্রিপার (Wire Stripper)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3094, 491, 302, 'কয়েকটি মেজারিং ইন্সট্রুমেন্টের নাম লিখ।', 'written', 1, 'সোলার কাজে ব্যবহৃত কয়েকটি পরিমাপক যন্ত্র হলো: এভোমিটার (মাল্টিমিটার), হাইড্রোমিটার, অ্যামিটার, ভোল্টমিটার এবং ওয়াটমিটার।', NULL, 'এভোমিটার (মাল্টিমিটার), হাইড্রোমিটার, অ্যামিটার, ভোল্টমিটার, ওয়াটমিটার ও এনার্জিমিটার।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3095, 491, 302, 'সোলার সিস্টেমে ব্যবহৃত টুলসের নাম লিখ।', 'written', 1, 'ব্যবহৃত প্রধান হ্যান্ড টুলসগুলো হলো: স্ক্রু-ড্রাইভার, কম্বিনেশন প্লায়ার্স, ক্যাবল কাটার, ওয়্যার স্ট্রিপার, ইলেকট্রিশিয়ান নাইফ, ফাইল ও হ্যামার।', NULL, 'প্লায়ার্স, স্ক্রু-ড্রাইভার, হ্যাক-স, ওয়্যার স্ট্রিপার, ইলেকট্রিশিয়ান নাইফ, ফাইল, হ্যামার ও ট্রাই স্কয়ার।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3096, 491, 302, 'সোলার তারের মাথায় লাকস (Lugs) লাগানোর জন্য কোন টুলটি ব্যবহৃত হয় এবং কেন?', 'written', 1, 'সঠিকভাবে ক্রিপিং করলে সংযোগস্থলে রেজিস্ট্যান্স বা লুজ কানেকশন হওয়ার সম্ভাবনা থাকে না।', NULL, 'ক্রিপিং টুল (Crimping Tool) ব্যবহৃত হয় তারের মাথায় লাকস বা কানেক্টর শক্তভাবে চেপে আটকানোর জন্য।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3097, 491, 302, 'মাল্টিমিটার (Multimeter) এর সাহায্যে সোলার সিস্টেমে কী কী পরিমাপ করা যায়?', 'written', 1, 'এটি সোলার সিস্টেমের ওয়্যারিং ও কম্পোনেন্ট পরীক্ষা করার একটি বহুমুখী পরিমাপক যন্ত্র।', NULL, 'মাল্টিমিটারের সাহায্যে সোলার প্যানেল বা ব্যাটারির ভোল্টেজ (DC/AC), সার্কিটের কারেন্ট (Ampere) এবং রোধ (Resistance) পরিমাপ করা যায়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3098, 491, 302, 'ইলেকট্রিক হ্যামার ড্রিল (Hammer Drill) সোলার সিস্টেমে কোন কাজে ব্যবহৃত হয়?', 'written', 1, 'হ্যামার ড্রিল শক্ত কংক্রিটে দ্রুত ছিদ্র করার জন্য অতিরিক্ত হাতুড়ির মতো আঘাত প্রয়োগ করে কাজ করে।', NULL, 'কংক্রিটের ছাদ বা দেয়ালে মাউন্টিং ফ্রেম ও চার্জ কন্ট্রোলার মাউন্ট করার জন্য গর্ত করতে হ্যামার ড্রিল ব্যবহৃত হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3099, 491, 302, 'স্পিরিট লেভেল (Spirit Level) সোলার প্যানেল স্থাপনে কেন ব্যবহার করা হয়?', 'written', 1, 'সমতল লেভেল ঠিক থাকলে প্যানেলগুলো সুন্দরভাবে বসে এবং সব প্যানেল সমান সূর্যের আলো পায়।', NULL, 'সোলার প্যানেল মাউন্টিং স্ট্রাকচারটির অনুভূমিক ও উল্লম্ব সমতলতা বা লেভেল ঠিক আছে কিনা তা পরীক্ষা করতে স্পিরিট লেভেল ব্যবহার করা হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3100, 491, 302, 'সেন্টার পাঞ্চ (Center Punch) এর কাজ কী?', 'written', 1, 'হ্যামার দিয়ে সেন্টার পাঞ্চে আঘাত করলে ধাতব পাতে ছোট টোল পড়ে যা ড্রিলিংয়ের জন্য নিখুঁত স্থান নির্দেশ করে।', NULL, 'লোহার বা অ্যালুমিনিয়ামের ফ্রেমে ড্রিল করার আগে ড্রিল বিটের অগ্রভাগকে পিছলে যাওয়া থেকে বাঁচাতে ছিদ্রের কেন্দ্রে দাগ দিতে সেন্টার পাঞ্চ ব্যবহৃত হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3101, 491, 302, 'অ্যালেন কি (Allen Key) সোলার সিস্টেমে কী কাজে লাগে?', 'written', 1, 'এল (L) আকৃতির এই ধাতব চাবিগুলো সাধারণত সোলার ক্ল্যাম্প শক্ত করতে ব্যবহৃত হয়।', NULL, 'সোলার মাউন্টিং স্ট্রাকচারের কিছু বিশেষ হেক্সাগোনাল (ছয় কোণ বিশিষ্ট) স্ক্রু বা বোল্ট টাইট দেওয়া বা খোলার কাজে অ্যালেন কি ব্যবহৃত হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3102, 491, 302, 'নিয়ন টেস্টার (Neon Tester) ব্যবহারের নিয়ম কী?', 'written', 1, 'নিয়ন টেস্টার কেবল এসি ২২০ ভোল্ট বা লাইভ লাইন সনাক্ত করতে ব্যবহৃত হয়, ব্যাটারির ডিসি লাইনে এটি জ্বলে না।', NULL, 'টেস্টারের অগ্রভাগ পরিবাহকের গায়ে ঠেকিয়ে পেছনের ধাতব ক্যাপে আঙুল স্পর্শ করলে ভেতরের নিয়ন বাল্ব জ্বলে লাইভ তার নির্দেশ করে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3103, 491, 302, 'তার কাটার জন্য কোন প্লায়ার্স সবচেয়ে বেশি ব্যবহৃত হয়?', 'written', 1, 'এই প্লায়ার্সের ধারালো চোয়াল তারের ভেতরের তামা সহজে কাটতে পারে।', NULL, 'ডায়াগোনাল কাটিং প্লায়ার্স বা ক্যাবল কাটার তার কাটার কাজে সবচেয়ে বেশি ব্যবহৃত হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3104, 491, 302, 'হ্যান্ড পাঞ্চ (Hand Punch) সোলার ওয়্যারিং বোর্ডে কী কাজে ব্যবহৃত হয়?', 'written', 1, 'হ্যান্ড পাঞ্চ ব্যবহার করলে ছিদ্রের চারপাশ অত্যন্ত মসৃণ ও গোলাকার হয়।', NULL, 'প্লাস্টিকের বোর্ড বা পাতলা ধাতব পাতে কন্ডুইট পাইপ বা তার ঢোকানোর জন্য গোল ছিদ্র তৈরি করতে হ্যান্ড পাঞ্চ ব্যবহার করা হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3105, 491, 302, 'টর্ক রেঞ্চ (Torque Wrench) সোলার স্ট্রাকচার ইনস্টলেশনে কেন ব্যবহার করা উচিত?', 'written', 1, 'অতিরিক্ত টাইট দিলে প্যানেলের কাচ বা ফ্রেম ভেঙে যেতে পারে এবং কম টাইট দিলে প্যানেল আলগা হয়ে উড়ে যেতে পারে।', NULL, 'প্যানেলের মাউন্টিং ফ্রেমের নাট-বোল্টগুলোকে স্পেসিফিকেশন অনুযায়ী নির্দিষ্ট টাইটনেস বা টর্কে টাইট দিতে টর্ক রেঞ্চ ব্যবহৃত হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3106, 492, 302, 'সোলার প্যানেল কোন দিকে স্থাপন করা হয়?', 'written', 1, 'সোলার প্যানেল সর্বদা দক্ষিণ দিকে মুখ করে স্থাপন করা হয় কারণ বাংলাদেশ উত্তর গোলার্ধে অবস্থিত হওয়ায় দক্ষিণ দিক থেকে সারা বছর সবচেয়ে বেশি সূর্যালোক পাওয়া যায়।', NULL, 'দক্ষিণ দিকে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3107, 492, 302, 'সোলার সিস্টেম কি?', 'written', 1, 'সূর্যের আলোকে সোলার প্যানেলের মাধ্যমে বিদ্যুৎ শক্তিতে রূপান্তর করে ব্যাটারি চার্জ করা এবং বিভিন্ন লোড বা যন্ত্রপাতি চালানোর সামগ্রিক স্বয়ংক্রিয় পদ্ধতিকে সোলার সিস্টেম বলে।', NULL, 'সৌর কোষ থেকে বিদ্যুৎ উৎপন্ন হয়ে ব্যাটারি চার্জ করা থেকে লোড চালানো পর্যন্ত সমগ্র ব্যবস্থাকে সোলার সিস্টেম বলে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3108, 492, 302, 'মডিউল কি?', 'written', 1, 'নির্দিষ্ট পরিমাণ ভোল্টেজ ও কারেন্ট পাওয়ার জন্য একাধিক সৌর কোষকে একসাথে সিরিজে সংযুক্ত করে যে প্যানেল আকৃতির ইউনিট তৈরি করা হয়, তাকে সোলার মডিউল বলে।', NULL, 'দুই বা তার বেশি সৌর কোষকে সিরিজে সংযুক্ত করলে তখন তাকে মডিউল বলে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3109, 492, 302, 'সাধারণত ১২ ভোল্টের ব্যাটারী চার্জ করার জন্য কতগুলি সেলের সমন্বয়ে একটি মডিউল তৈরী হয়?', 'written', 1, 'একটি ১২ ভোল্টের ব্যাটারি চার্জ করতে সাধারণত ১৫ থেকে ১৮ ভোল্টের প্রয়োজন হয়, যা পাওয়ার জন্য মডিউলে ৩৬টি সেল সিরিজে যুক্ত করা হয়।', NULL, '৩৬টি সেল।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3110, 492, 302, 'সাধারণত ২৪ ভোল্টের ব্যাটারী চার্জ করার জন্য কতগুলি সেলের সমন্বয়ে একটি মডিউল তৈরী হয়?', 'written', 1, '২৪ ভোল্টের ব্যাটারি চার্জ করার জন্য প্রায় ৩০ থেকে ৩৬ ভোল্ট আউটপুটের প্রয়োজন হয়, যা ৩৬ সেলের দুটি মডিউল বা ৭২টি সেল সিরিজে যুক্ত করে পাওয়া যায়।', NULL, '৭২টি সেল।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3111, 492, 302, 'একটি মডিউল থেকে কত ভোল্টেজ পাওয়া যায়?', 'written', 1, 'একটি আদর্শ ১২ ভোল্ট রেটিংয়ের সোলার মডিউল থেকে সাধারণত ১৫ থেকে ১৮ ভোল্ট (ওপেন সার্কিট অবস্থায় ২১ ভোল্ট পর্যন্ত) পাওয়া যায়।', NULL, '১৫ থেকে ১৮ ভোল্ট।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3112, 492, 302, 'প্যানেল কি?', 'written', 1, 'এক বা একাধিক সোলার মডিউলকে ফ্রেমের মধ্যে নির্দিষ্ট বিন্যাসে (সিরিজ বা প্যারালালে) সংযুক্ত করে যে একক কাঠামো তৈরি করা হয়, তাকে সোলার প্যানেল বলে।', NULL, 'অনেকগুলি মডিউল একত্রে সংযুক্ত করলে তখন তাকে প্যানেল বলে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3113, 492, 302, 'অ্যারে কি?', 'written', 1, 'বৃহত্তর ভোল্টেজ বা কারেন্টের চাহিদা মেটানোর জন্য একাধিক সোলার প্যানেলকে সিরিজে ও সমান্তরালে সংযুক্ত করে যে বিশাল প্যানেল সমষ্টি তৈরি করা হয়, তাকে সোলার অ্যারে বলে।', NULL, 'অনেকগুলি প্যানেল একত্রে সংযুক্ত করলে তখন তাকে অ্যারে বলে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3114, 492, 302, 'সোলার সিস্টেমের সুবিধা গুলি কি?', 'written', 1, 'সৌর বিদ্যুৎ একটি পরিবেশবান্ধব উৎস যার জন্য কোনো জ্বালানি খরচ নেই, এটি ব্যবহারের ফলে কোনো দূষণ হয় না এবং সোলার প্যানেলের আয়ুষ্কাল প্রায় ২০ বছর পর্যন্ত হয়ে থাকে।', NULL, 'বিদ্যুৎ উৎপাদনের জন্য জ্বালানির প্রয়োজন হয় না। প্যানেলের আয়ু প্রায় ২০ বছর। বিদ্যুৎ বিল লাগে না। নিরবিচ্ছিন্ন বিদ্যুৎ পাওয়া যায়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3115, 492, 302, 'সোলার সিস্টেমের অসুবিধা গুলি কি?', 'written', 1, 'সোলার সিস্টেম স্থাপনের প্রাথমিক খরচ অনেক বেশি, এটি সম্পূর্ণভাবে সূর্যের আলোর উপর নির্ভরশীল হওয়ায় মেঘলা দিনে বা রাতে সরাসরি বিদ্যুৎ উৎপাদন করতে পারে না।', NULL, 'স্থাপন ব্যয় অনেক বেশি। মেঘলা বা বৃষ্টির দিনে বিদ্যুৎ উৎপাদন হয় না। নির্দিষ্ট সময় পর্যন্ত বিদ্যুৎ ব্যবহার করা যায়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3116, 492, 302, 'সোলার সিস্টেমের বিভিন্ন অংশগুলির নাম লিখ।', 'written', 1, 'সোলার হোম সিস্টেমের প্রধান উপাদানগুলো হলো: সোলার প্যানেল (উৎপাদক), চার্জ কন্ট্রোলার (নিয়ন্ত্রক), ব্যাটারি (সঞ্চয়ক), ইনভার্টার (রূপান্তরক) এবং ডিসি/এসি লোড।', NULL, 'মডিউল, ব্যাটারি, চার্জ কন্ট্রোলার ও লোড।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3117, 492, 302, 'সোলার সিলিকন সেল কত প্রকার ও কি কি?', 'written', 1, 'সিলিকন সোলার সেল প্রধানত তিন প্রকার: ১) মনো ক্রিস্টালাইন সিলিকন সেল (উচ্চ দক্ষ), ২) পলি ক্রিস্টালাইন সিলিকন সেল (মাঝারি দক্ষ) এবং ৩) অ্যামোরফাস সিলিকন সেল (থিন ফিল্ম)।', NULL, 'তিন প্রকার। ১) মনো ক্রিস্টালাইন সেল ২) পলি ক্রিস্টালাইন সেল ৩) অ্যামোরফাস সিলিকন সেল।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3118, 492, 302, 'পলি ক্রিস্টালাইন সেল ও মনো ক্রিস্টালাইন সেলের মধ্যে পার্থক্য লিখ।', 'written', 1, 'মনো ক্রিস্টালাইন সেল একক সিলিকন ক্রিস্টাল দিয়ে তৈরি যা দেখতে গাঢ় কালো এবং এর দক্ষতা বেশি। পলি ক্রিস্টালাইন সেল একাধিক ক্রিস্টাল দিয়ে তৈরি যা নীল রঙের দেখায় এবং এর দক্ষতা মনোর চেয়ে কিছুটা কম।', NULL, 'পলি ক্রিস্টালাইন সেলের তুলনায় মনো ক্রিস্টালাইন সেলের রঙের গাঢ়ত্ব বেশি এবং দক্ষতাও বেশি হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3119, 492, 302, 'ফটো ভোল্টিক মডিউলের এর প্যারামিটার গুলি কি কি?', 'written', 1, 'প্রধান প্যারামিটারগুলো হলো: ওপেন সার্কিট ভোল্টেজ (Voc), শর্ট সার্কিট কারেন্ট (Isc), সর্বোচ্চ পাওয়ার পয়েন্ট ভোল্টেজ (Vmp), সর্বোচ্চ কারেন্ট (Imp) এবং ওয়াট পিক (Pmax)।', NULL, '১) ওপেন সার্কিট ভোল্টেজ (Voc) ২) শর্ট সার্কিট কারেন্ট (Isc) ৩) ম্যাক্সিমাম পাওয়ার ভোল্টেজ (Vmp) ৪) ম্যাক্সিমাম পাওয়ার কারেন্ট (Imp) ৫) ম্যাক্সিমাম পাওয়ার (Pmax) ।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3120, 492, 302, 'সোলার মডিউলের ক্ষেত্রে আদর্শ টেস্ট কন্ডিশন কি কি?', 'written', 1, 'আদর্শ টেস্ট কন্ডিশন (STC) হলো: ১০০০ ওয়াট/বর্গমিটার সৌর বিকিরণ, ২৫ ডিগ্রি সেলসিয়াস সেল তাপমাত্রা এবং এয়ার মাস (AM) ১.৫।', NULL, '১) সৌর বিকিরণ: ১০০০ ওয়াট/মি২ ২) সৌর সেল তাপমাত্রা: ২৫ ডিগ্রী সেঃ ৩) এয়ার মাস (AM): ১.৫।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3121, 493, 302, 'সোলার প্যানেল থেকে চার্জ কন্ট্রোলারের দূরত্ব কতটুকু হওয়া ভালো?', 'written', 1, 'সোলার প্যানেল থেকে চার্জ কন্ট্রোলারের দূরত্ব ২৫ ফুটের মধ্যে রাখা ভালো, যাতে ডিসি লাইনের রেজিস্ট্যান্স ও ভোল্টেজ ড্রপ সর্বনিম্ন থাকে।', NULL, '২৫ ফুট।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3122, 493, 302, 'লাইটিং সার্কিটে সাধারনত কি তার ব্যবহার করা হয়?', 'written', 1, 'সোলার সিস্টেমে ঘরের ভেতরের এলইডি বাল্ব বা লাইটিং ওয়্যারিং সার্কিটের জন্য সাধারণত ১.৫ আরএম (1.5 RM) সাইজের কপার তার ব্যবহার করা হয়।', NULL, '১.৫ আরএম (1.5 RM) তার।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3123, 493, 302, 'মেঝে থেকে সুইচ বোর্ডের উচ্চতা কত?', 'written', 1, 'ওয়ার্কশপ বা ঘরের মেঝে থেকে সুইচ বোর্ড স্থাপন করার আদর্শ উচ্চতা হলো ১.৫ মিটার (বা ৫ ফুট)।', NULL, '১.৫ মিটার (বা ৫ ফুট)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3124, 493, 302, 'সোলার সিস্টেমে ব্যবহৃত তার সমূহের সাইজের নাম লিখ।', 'written', 1, 'সোলার ওয়্যারিংয়ে তারের বহুল ব্যবহৃত সাইজগুলো হলো: ৩/০.০২৯, ৩/০.০৩৬, ৭/০.০২৯, ৭/০.০৩৬ এবং ৭০/০.০০৭৬ ইত্যাদি।', NULL, '৩/০.০২৯, ৩/০.০৩৬, ৭/০.০২৯, ৭/০.০৩৬, ৪০/০.০০৭৬, ৭০/০.০০৭৬।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3125, 493, 302, 'সোলার হোম সিস্টেমের ব্লক ডায়াগ্রাম অঙ্কন কর।', 'written', 1, 'সিস্টেমের ফ্লো ডায়াগ্রাম হলো: সোলার প্যানেল -> চার্জ কন্ট্রোলার -> ব্যাটারি -> ইনভার্টার -> এসি লোড। চার্জ কন্ট্রোলার থেকে ডিসি লোড সরাসরি যুক্ত থাকে।', NULL, 'সোলার প্যানেল -> চার্জ কন্ট্রোলার -> ব্যাটারি -> ইনভার্টার -> এসি লোড। (চার্জ কন্ট্রোলার থেকে সরাসরি ডিসি লোডও যুক্ত থাকে)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3126, 493, 302, 'সোলার সিস্টেমে তারের ভোল্টেজ ড্রপ (Voltage Drop) কেন ক্ষতিকর?', 'written', 1, 'ডিসি ওয়্যারিংয়ে অতিরিক্ত ভোল্টেজ ড্রপ সিস্টেমকে অকার্যকর করে তোলে।', NULL, 'তারের ভোল্টেজ ড্রপ হলে ব্যাটারি পূর্ণ ভোল্টেজে চার্জ হতে পারে না এবং বিদ্যুৎ শক্তির অপচয় ঘটে সিস্টেমের কার্যক্ষমতা কমে যায়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3127, 493, 302, 'সোলার প্যানেলে সমান্তরাল (Parallel) সংযোগের ওয়্যারিং নিয়ম কী?', 'written', 1, 'সমান্তরাল ওয়্যারিংয়ে ভোল্টেজ অপরিবর্তিত থাকে কিন্তু মোট কারেন্ট বৃদ্ধি পায়।', NULL, 'সব প্যানেলের পজিটিভ (+) টার্মিনাল একসাথে এবং সব নেগেটিভ (-) টার্মিনাল একসাথে যুক্ত করার ওয়্যারিংই সমান্তরাল সংযোগ।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3128, 493, 302, 'সোলার প্যানেলে সিরিজ (Series) সংযোগের ওয়্যারিং নিয়ম কী?', 'written', 1, 'সিরিজ ওয়্যারিংয়ে কারেন্ট অপরিবর্তিত থাকে কিন্তু মোট ভোল্টেজ বৃদ্ধি পায়।', NULL, 'একটি প্যানেলের পজিটিভ (+) টার্মিনালের সাথে পরবর্তী প্যানেলের নেগেটিভ (-) টার্মিনাল পর্যায়ক্রমে যুক্ত করার ওয়্যারিংই সিরিজ সংযোগ।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3129, 493, 302, 'ইউভি প্রতিরোধী সোলার কেবল (UV Resistant Solar Cable) কেন ব্যবহার করা হয়?', 'written', 1, 'সাধারণ তার রোদে কয়েক বছরের মধ্যে ফেটে শর্ট সার্কিটের ঝুঁকি তৈরি করে, সোলার তার তা করে না।', NULL, 'সোলার প্যানেলের তারগুলো উন্মুক্ত ছাদে থাকে। সূর্যের অতিবেগুনী রশ্মিতে (UV) যাতে তারের প্লাস্টিক ইনসুলেশন নষ্ট না হয় সেজন্য ইউভি রেজিস্ট্যান্ট কেবল ব্যবহৃত হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3130, 493, 302, 'তারের সংযোগস্থলে লাকস (Lugs) ব্যবহার করার প্রয়োজনীয়তা কী?', 'written', 1, 'লাকস ছাড়া খোলা তার টার্মিনালে আটকালে কারেন্ট স্পার্ক করতে পারে।', NULL, 'লাকস ব্যবহার করলে তারের প্রতিটি স্ট্র্যান্ড একসাথে সুরক্ষিত থাকে এবং স্ক্রু টার্মিনালের সাথে অত্যন্ত শক্ত ও নিখুঁত বৈদুতিক সংযোগ তৈরি হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3131, 493, 302, 'পিভিসি কন্ডুইট (PVC Conduit) পাইপ ওয়্যারিং করার সময় কীভাবে সাপোর্ট দিতে হয়?', 'written', 1, 'স্যাডল পাইপকে দেয়ালের সাথে শক্তভাবে আটকে রাখে যাতে ঝুলে না পড়ে।', NULL, 'দেয়ালে বা ছাদে কন্ডুইট পাইপ সোজা রাখার জন্য নির্দিষ্ট দূরত্ব পর পর স্যাডল (Saddle) বা ক্লিপ ব্যবহার করে সাপোর্ট দিতে হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3132, 493, 302, 'সোলার সিস্টেমে ব্যাটারি ব্যাংকের সমান্তরাল ওয়্যারিংয়ের সময় কী সতর্কতা প্রয়োজন?', 'written', 1, 'তারের দৈর্ঘ্য অসমান হলে কোনো ব্যাটারি কম চার্জ পাবে এবং কোনোটি বেশি লোড বহন করে নষ্ট হবে।', NULL, 'সংযোগকারী ক্যাবলগুলোর দৈর্ঘ্য ও ব্যাস সমান হতে হবে এবং সংযোগগুলো ভালোমতো টাইট থাকতে হবে যাতে সব ব্যাটারি সমানভাবে চার্জ/ডিসচার্জ হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3133, 493, 302, 'সোলার ওয়্যারিং ডায়াগ্রামে পোলারিটি (Polarity) বলতে কী বোঝায়?', 'written', 1, 'ডিসি সিস্টেমে পোলারিটি উল্টো হলে কম্পোনেন্ট পুড়ে নষ্ট হয়ে যাবে।', NULL, 'ডিসি ওয়্যারিংয়ের পজিটিভ বা ধনাত্মক (+) এবং নেগেটিভ বা ঋণাত্মক (-) চিহ্ন ও তার সঠিক সংযোগকে পোলারিটি বলে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3134, 493, 302, 'সোলার সিস্টেমে ফিউজ (Fuse) সর্বদা কোন তারে সংযোগ করতে হয়?', 'written', 1, 'পজিটিভ তারে ফিউজ বসালে শর্ট সার্কিট হলে বিদ্যুৎ সংযোগ বিচ্ছিন্ন হয়ে সুরক্ষামূলক ডিভাইস ও তার পুড়ে যাওয়া থেকে বাঁচে।', NULL, 'ফিউজ সর্বদা পজিটিভ (+) বা লাইভ লাইনের তারের সাথে সিরিজে সংযোগ করতে হয়।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3135, 493, 302, 'ওয়্যারিং সম্পন্ন করার পর সংযোগগুলো পরীক্ষা করার সঠিক ধাপ কোনটি?', 'written', 1, 'ধাপে ধাপে চেক করলে কোনো ভুল সংযোগ থাকলে তা সচল করার আগেই ধরা পড়ে এবং দুর্ঘটনা এড়ানো যায়।', NULL, 'সংযোগগুলো ফিজিক্যালি চেক করা, মাল্টিমিটার দিয়ে শর্ট সার্কিট ও কন্টিনিউটি পরীক্ষা করা এবং সবশেষে ডিভাইস অন করে ভোল্টেজ পরীক্ষা করা।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3136, 494, 302, 'চার্জ কন্ট্রোলারের কাজ কি?', 'written', 1, 'চার্জ কন্ট্রোলার ব্যাটারিতে অতিরিক্ত বিদ্যুৎ প্রবেশ (Overcharging) রোধ করে এবং ব্যাটারির চার্জ অতিমাত্রায় কমে যাওয়া (Deep discharging) থেকে ব্যাটারিকে রক্ষা করে।', NULL, 'ব্যাটারি ফুল চার্জ হয়ে গেলে প্যানেল থেকে ব্যাটারি বিচ্ছিন্ন করা এবং ব্যাটারি ফুল ডিসচার্জ হয়ে গেলে লোড থেকে ব্যাটারি বিচ্ছিন্ন করা।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3137, 494, 302, 'ব্যাটারী ডিসচার্জ হয়ে গেলে কেন দ্রুত চার্জ করা উচিত?', 'written', 1, 'ব্যাটারি ডিসচার্জ অবস্থায় দীর্ঘক্ষণ থাকলে প্লেটগুলোতে শক্ত লেড সালফেট (Lead Sulfate) জমা হয়, যা ব্যাটারির ধারণক্ষমতা স্থায়ীভাবে নষ্ট করে দেয়।', NULL, 'ডিসচার্জ অবস্থায় প্লেটে আরো বেশি সাদা সালফেট (Lead Sulfate) জমে প্লেটের স্থায়ী ক্ষতি করতে পারে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3138, 494, 302, 'ব্যাটারীর টার্মিনালে কেন গ্রীজ বা ভ্যাসলিন লাগানো উচিত?', 'written', 1, 'টার্মিনালগুলো বাতাসে থাকা আর্দ্রতা ও ব্যাটারির গ্যাসের সংস্পর্শে এসে যাতে কপার সালফেট বা অক্সাইডের সাদা মরিচা না জমে সেজন্য গ্রীজ বা ভ্যাসলিন ব্যবহার করা হয়।', NULL, 'যাতে টার্মিনালে অক্সাইডের গুড়া (মরিচা বা ক্ষয়) না জমে।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3139, 494, 302, 'একটি ১২ ভোল্টের ব্যাটারীতে কয়টি সেল থাকে?', 'written', 1, 'একটি ১২ ভোল্টের লেড-এসিড ব্যাটারির ভেতরে সিরিজে সংযুক্ত মোট ৬টি সেল থাকে, যেখানে প্রতিটি সেলের ভোল্টেজ প্রায় ২.১ ভোল্ট।', NULL, '৬টি সেল।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3140, 494, 302, 'একটি পূর্ণ চার্জিত ব্যাটারীর ইলেক্ট্রোলাইটের ঘনত্ব কত হওয়া উচিত?', 'written', 1, 'একটি পূর্ণ চার্জিত ভালো মানের ব্যাটারির ইলেক্ট্রোলাইটের আপেক্ষিক গুরুত্ব হাইড্রোমিটারে সাধারণত ১.২৬৫ (১২৫০ থেকে ১২৭০) রিডিং দেখায়।', NULL, '১.২৬৫ (১২৫০-১২৭০)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3141, 494, 302, 'HVD কি?', 'written', 1, 'HVD মানে High Voltage Disconnect। চার্জ কন্ট্রোলারের এই প্রোটেকশন ফিচারটি ব্যাটারি সম্পূর্ণ চার্জ হলে প্যানেল থেকে ব্যাটারির সংযোগ বিচ্ছিন্ন করে দেয়।', NULL, 'HVD মানে High Voltage Disconnect (ব্যাটারি ফুল চার্জ হলে চার্জ কন্ট্রোলার প্যানেল থেকে ব্যাটারির সংযোগ বিচ্ছিন্ন করে দেয়, সাধারণত ১৪.৫V)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3142, 494, 302, 'LVD কি?', 'written', 1, 'LVD মানে Low Voltage Disconnect। চার্জ কন্ট্রোলারের এই সুরক্ষা ফিচারটি ব্যাটারির চার্জ অতিরিক্ত কমে গেলে ব্যাটারিকে রক্ষা করতে লোডের সংযোগ বিচ্ছিন্ন করে দেয়।', NULL, 'LVD মানে Low Voltage Disconnect (ব্যাটারির ভোল্টেজ অতিমাত্রায় কমে গেলে লোডকে বিচ্ছিন্ন করে দেয়, সাধারণত ১১.৫V)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3143, 494, 302, 'LRV কি?', 'written', 1, 'LRV মানে Load Reconnect Voltage। ব্যাটারি ভোল্টেজ LVD এর নিচে নেমে লোড কাটার পর ব্যাটারি পুনরায় চার্জ হয়ে যে ভোল্টেজে পৌঁছালে লোড সংযোগ পায়, তাকে LRV বলে।', NULL, 'LRV মানে Load Reconnect Voltage (ডিসকানেক্ট হওয়া লোড ব্যাটারি চার্জ হওয়ার পর কত ভোল্টেজে পুনরায় সংযোগ পাবে, সাধারণত ১২.৭V)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3144, 494, 302, '১২ ভোল্টের ব্যাটারীর ক্ষেত্রে সর্বোচ্চ কত ভোল্টেজে প্যানেল থেকে ব্যাটারী ডিসকানেক্ট করতে হবে?', 'written', 1, '১২ ভোল্টের ব্যাটারির অতিরিক্ত চার্জিং এড়াতে সাধারণত ১৪.৫ ভোল্ট (HVD সেট পয়েন্ট) এ পৌঁছালে প্যানেল থেকে সংযোগ বিচ্ছিন্ন করতে হবে।', NULL, '১৪.৫ ভোল্ট।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3145, 494, 302, '১২ ভোল্টের ব্যাটারীর ক্ষেত্রে সর্বনিম্ন কত ভোল্টেজে প্যানেলের সাথে ব্যাটারী রিকানেক্ট করতে হবে?', 'written', 1, 'ব্যাটারি ভোল্টেজ ব্যবহারের ফলে বা সেল স্বতঃস্ফূর্ত ডিসচার্জের কারণে ১৩.৫ বা ১৩.৭ ভোল্টে নেমে এলে প্যানেলের সাথে চার্জিং পুনরায় রিকানেক্ট করতে হবে।', NULL, '১৩.৫ ভোল্ট বা ১৩.৭ ভোল্ট। (Note: If image had a specific number, let\'s check: 13.5V/13.7V is standard. We can write 13.7V or 13.5V)', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3146, 494, 302, '১২ ভোল্টের ব্যাটারীর ক্ষেত্রে সর্বনিম্ন কত ভোল্টেজে লোড থেকে ব্যাটারী ডিসকানেক্ট করতে হবে?', 'written', 1, 'ব্যাটারিকে ডিপ ডিসচার্জের হাত থেকে রক্ষা করতে ভোল্টেজ ১১.৫ ভোল্ট (LVD সেট পয়েন্ট) এ নেমে আসলে লোড ডিসকানেক্ট করতে হবে।', NULL, '১১.৫ ভোল্ট।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3147, 494, 302, '১২ ভোল্টের ব্যাটারীর ক্ষেত্রে কত ভোল্টেজে লোডের সাথে ব্যাটারী রিকানেক্ট করতে হবে?', 'written', 1, 'ব্যাটারি পুনরায় চার্জ হয়ে ভোল্টেজ ১২.৭ ভোল্ট (LRV সেট পয়েন্ট) এ পৌঁছালে লোডের সংযোগ স্বয়ংক্রিয়ভাবে পুনরায় চালু করতে হবে।', NULL, '১২.৭ ভোল্ট।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3148, 494, 302, 'চার্জ কন্ট্রোলারের কয়টি টার্মিনাল থাকে?', 'written', 1, 'একটি স্ট্যান্ডার্ড চার্জ কন্ট্রোলারে সাধারণত ৬টি ওয়্যারিং টার্মিনাল থাকে—২টি সোলার ইনপুট, ২টি ব্যাটারি পোর্ট এবং ২টি ডিসি লোড আউটপুট পোর্ট।', NULL, '৬টি বা ৮টি টার্মিনাল থাকে (সাধারণত ৬টি টার্মিনাল)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3149, 494, 302, 'চার্জ কন্ট্রোলার নির্ধারণের সময় কি কি খেয়াল রাখতে হয়?', 'written', 1, 'সিস্টেম ভোল্টেজ (১২V/২৪V), সোলার প্যানেলের সর্বোচ্চ ওপেন সার্কিট ভোল্টেজ এবং প্যানেল থেকে আসা সর্বোচ্চ কারেন্ট রেটিং (অ্যাম্পিয়ার) খেয়াল রাখতে হয়।', NULL, 'সিস্টেম ভোল্টেজ (১২V/২৪V) এবং সর্বোচ্চ কারেন্ট রেটিং (অ্যাম্পিয়ার)।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
(3150, 494, 302, 'ব্যাটারীর টার্মিনাল ভোল্টেজ কত হলে চার্জ কন্ট্রোলার লোড হতে সরবরাহ বিচ্ছিন্ন করে দিবে?', 'written', 1, 'ব্যাটারির টার্মিনাল ভোল্টেজ ১১.৫ ভোল্টের নিচে নেমে গেলে চার্জ কন্ট্রোলার ডিসি লোড সাইডের সংযোগ কেটে দেয়।', NULL, '১১.৫ ভোল্ট।', 0, '2026-06-02 23:00:26', '2026-06-02 23:00:26'),
