(3436, 483, 30, 'ড্রাই এয়ার ক্লিনার এর এয়ার ফিল্টার এলিমেন্ট পুড়ে যাওয়া বা পোড়া দাগ হওয়ার কারণ কি ?', 'written', 1, NULL, NULL, 'ইঞ্জিনে ব্যাক ফায়ার হওয়ার জন্য ।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3437, 478, 30, 'নিরাপদ ভ্রমনের জন্য ইঞ্জিন স্টার্ট করে ৫-১০ গজের মধ্যে অবশ্যই কি চেক করতে হবে ?', 'written', 1, NULL, NULL, 'ব্রেক পেডেলে চাপ প্রয়োগ করে ব্রেকের কার্যক্ষমতা সঠিক আছে কি না ।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
