(3441, 478, 30, 'অটোশপে কোন ধরনের রেঞ্জ বেশি ব্যবহৃত হয় ?', 'written', 1, NULL, NULL, 'অ্যাডজাস্টেবল রেঞ্জ ও সকেট রেঞ্জ ।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3442, 480, 30, 'কুলিং ফ্যানের কাজ কী ?', 'written', 1, NULL, NULL, 'রেডিয়েটরের ভেতর দিয়ে বাতাস প্রবাহিত করা এবং গরম পানিকে ঠান্ডা করা।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3443, 480, 30, 'এয়ার কুলিং সিস্টেমে ইঞ্জিন কিভাবে ঠান্ডা হয় ?', 'written', 1, NULL, NULL, 'ইঞ্জিন সিলিন্ডার ও হেডের চতুর্দিকে বেশ কিছু পাতলা লোহার পাত (ফিন) থাকে। বাতাসের সংস্পর্শে এই পাতলা লোহার পাতসমূহ ঠান্ডা হয়ে ইঞ্জিনকে ঠান্ডা রাখে। যেমনঃ মোটরসাইকেল, অটোরিক্সা ইত্যাদি গাড়িতে এয়ার কুলিং সিস্টেম দেখা যায়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3444, 479, 30, 'স্ট্যাবিলাইজার বারের কাজ কি ?', 'written', 1, NULL, NULL, 'মোড় ঘোরার সময় গাড়ির রোলিং প্রবণতা কমানো ।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3445, 474, 30, 'মোটরযান কাকে বলে ?', 'written', 1, NULL, NULL, 'মোটরযান আইনে মোটরযান অর্থ কোনো যন্ত্রচালিত যান, যার চালিকাশক্তি বাইরের বা ভিতরের কোনো উৎস হতে সরবরাহ হয়ে থাকে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3446, 474, 30, 'গাড়ি চালনাকালে কী কী কাগজপত্র গাড়ির সঙ্গে রাখতে হয় ?', 'written', 1, NULL, NULL, 'ড্রাইভিং লাইসেন্স রেজিস্ট্রেশন সার্টিফিকেট (ব্লু-বুক) ট্যাক্সটোকেন ইনসিওরেন্স সার্টিফিকেট ফিটনেস সার্টিফিকেট (মোটরসাইকেলের ক্ষেত্রে প্রযোজ্য নয়) রুটপারমিট (মোটরসাইকেল এবং চালক ব্যতীত সর্বোচ্চ ৭ আসন বিশিষ্ট ব্যক্তিগত যাত্রীবাহী গাড়ির ক্ষেত্রে প্রযোজ্য নয়)।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3447, 478, 30, 'গাড়ি চালনার আগে করণীয় কাজ কী কী ?', 'written', 1, NULL, NULL, 'গাড়িতে জ্বালানি আছে কি না পরীক্ষা করা, না থাকলে পরিমাণ মতো নেওয়া। রেডিয়েটর ও ব্যাটারিতে পানি আছে কি না পরীক্ষা করা, না থাকলে পরিমাণ মতো নেওয়া। ব্যাটারি কানেকশন পরীক্ষা করা। লুব/ইঞ্জিন অয়েলের লেবেল ও ঘনত্ব পরীক্ষা করা, কম থাকলে পরিমাণ মতো নেওয়া। মাস্টার সিলিন্ডারের ব্রেকফ্লুইড, ব্রেকঅয়েল পরীক্ষা করা, কম থাকলে নেওয়া। গাড়ির ইঞ্জিন, লাইটিং সিস্টেম, ব্যাটারি, স্টিয়ারিং ইত্যাদি সঠিকভাবে কাজ করছে কি না, নাট-বোল্ট টাইট আছে কি না অর্থাৎ সার্বিকভাবে মোটরযানটি ত্রুটিমুক্ত আছে কি না পরীক্ষা করা। ব্রেক ও ক্লাচের কার্যকারিতা পরীক্ষা করা। অগ্নিনির্বাপকযন্ত্র এবং ফাস্টএইড বক্স গাড়িতে রাখা। গাড়ির বাইরের এবং ভিতরের বাতির অবস্থা, ঢাকা (টায়ার কন্ডিশন/হাওয়া/নাট/এলাইমেন্ট/রোটেশন/স্পেয়ার চাকা) পরীক্ষা করা।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3448, 473, 30, 'সার্ভিসিং বলতে কী বুঝায় এবং গাড়ি সার্ভিসিংয়ে কী কী কাজ করা হয় ?', 'written', 1, NULL, NULL, 'মোটরযানের ইঞ্জিন ও বিভিন্ন যন্ত্রাংশের কার্যক্ষমতাকে দীর্ঘস্থায়ী করার জন্য নির্দিষ্ট সময় পরপর যে-কাজগুলো করা হয়, তাকে সার্ভিসিং বলে। গাড়ি সার্ভিসিংয়ে করণীয় কাজ ইঞ্জিনের পুরাতন লুবঅয়েল (মবিল) ফেলে দিয়ে নতুন লুবঅয়েল দেওয়া। নতুন লুবঅয়েল দেওয়ার আগে ফ্লাশিং অয়েল দ্বারা ফ্লাশ করা। ইঞ্জিন ও রেডিয়েটরের পানি ড্রেন আউট করে ডিটারজেন্ট ও ফ্লাশিংগান দিয়ে পরিষ্কার করা, অতঃপর পরিষ্কার পানি দিয়ে পূর্ণ করা। ভারী মোটরযানের ক্ষেত্রে বিভিন্ন থ্রিজিং পয়েন্টে গ্রিজগান দিয়ে নতুন গ্রিজ দেওয়া। গাড়ির স্পেয়ার হুইলসহ প্রতিটি চাকাতে পরিমাণমতো হাওয়া দেওয়া। লুবঅয়েল (মবিল) ফিল্টার, ফুয়েল ফিল্টার ও এয়ারক্লিনার পরিবর্তন করা।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3449, 474, 30, 'রাস্তায় গাড়ির কাগজপত্র কে কে চেক করতে পারেন/ কোন কোন ক্ষমতাপ্রাপ্ত ব্যক্তিগণকে গাড়ির কাগজ দেখাতে বাধ্য ?', 'written', 1, NULL, NULL, 'সার্জেন্ট বা সাব-ইনসপেক্টরের নিচে নয় এমন পুলিশ কর্মকর্তা, মোটরযান পরিদর্শকসহ বিআরটিএর কর্মকর্তা এবং মোবাইলকোর্টের কর্মকর্তা।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3450, 471, 30, 'মোটরসাইকেলে হেলমেট পরিধান ও আরোহী বহন সম্পর্কে আইন কী ?', 'written', 1, NULL, NULL, 'মোটরসাইকেলে চালক ব্যতীত ১ জন আরোহী বহন করা যাবে এবং উভয়কেই হেলমেট পরিধান করতে হবে (মোটরযান', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3451, 478, 30, 'ডিফারেন্সিয়াল গিয়ারে বক্সে ঘড় ঘড় শব্দ হওয়ার কারণ কি ?', 'written', 1, NULL, NULL, 'ম্যাশিং গিয়ারগুলির দাঁতের ফাঁক (ব্যাকলাশ) বেড়ে যাওয়া ।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3452, 478, 30, 'লাল, সবুজ ও হলুদ বাতি কী নির্দেশনা প্রদর্শন করে ?', 'written', 1, NULL, NULL, 'লালবাতি জ্বললে গাড়িকে ‘থামুনলাইন’ এর পেছনে থামায়ে অপেক্ষা করতে হবে, সুবজবাতি জ্বললে গাড়ি নিয়ে অগ্রসর হওয়া যাবে এবং হলুদবাতি জ্বললে গাড়িকে থামানোর জন্য প্রস্তুতি নিতে হবে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3453, 474, 30, 'নিরাপদ দূরত্ব বলতে কী বুঝায়?', 'written', 1, NULL, NULL, 'সামনের গাড়ির সাথে সংঘর্ষ এড়াতে পেছনের গাড়িকে নিরাপদে থামানোর জন্য যে পরিমাণ দূরত্ব বজায় রেখে গাড়ি চালাতে হয় সেই পরিমাণ নিরাপদ দূরত্ব বলে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3454, 471, 30, 'PPE (পিপিই) বলতে কী বোঝায়? দুটি উদাহরণ দাও।', 'written', 1, 'PPE পরা কর্মীদের দুর্ঘটনাজনিত আঘাত থেকে রক্ষা করে। সকল অটোশপ কর্মীর PPE পরা বাধ্যতামূলক।', NULL, 'PPE মানে Personal Protective Equipment অর্থাৎ ব্যক্তিগত সুরক্ষামূলক সরঞ্জাম। উদাহরণ: হেলমেট ও সেফটি বুট।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3455, 471, 30, 'অটোশপে আগুন লাগলে কী ধরনের ফায়ার এক্সটিংগুইশার ব্যবহার করা উচিত?', 'written', 1, 'ABC টাইপ এক্সটিংগুইশার পেট্রোল, বৈদ্যুতিক ও সাধারণ আগুন নেভাতে পারে।', NULL, 'অটোশপে পাউডার টাইপ (ABC টাইপ) ফায়ার এক্সটিংগুইশার ব্যবহার করা উচিত।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3456, 471, 30, 'কর্মক্ষেত্রে বায়োলজিক্যাল হ্যাজার্ড কাকে বলে?', 'written', 1, 'বায়োলজিক্যাল হ্যাজার্ড থেকে রক্ষায় মাস্ক ও গ্লাভস ব্যবহার করতে হয়।', NULL, 'ব্যাকটেরিয়া, ভাইরাস বা অন্যান্য জীবাণু দ্বারা স্বাস্থ্য বিপদকে বায়োলজিক্যাল হ্যাজার্ড বলে। যেমন: করোনা ভাইরাস।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3457, 472, 30, 'FPS পদ্ধতির পূর্ণনাম কী? এতে দৈর্ঘ্য, ভর ও সময়ের একক কী?', 'written', 1, 'FPS পদ্ধতি পুরানো ব্রিটিশ পদ্ধতি যা কিছু দেশে এখনো ব্যবহৃত হয়।', NULL, 'FPS = Foot Pound Second পদ্ধতি। দৈর্ঘ্য: ফুট, ভর: পাউন্ড, সময়: সেকেন্ড।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3458, 472, 30, '৮৫ ডিগ্রি সেলসিয়াস সমান কত ডিগ্রি ফারেনহাইট?', 'written', 1, 'তাপমাত্রা রূপান্তরের সূত্র: °F = (°C × ৯/৫) + ৩২।', NULL, '°F = (°C × ১.৮) + ৩২ = (৮৫ × ১.৮) + ৩২ = ১৫৩ + ৩২ = ১৮৫ ডিগ্রি ফারেনহাইট।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3459, 473, 30, '5S পদ্ধতির পাঁচটি ধাপ কী কী?', 'written', 1, '5S পদ্ধতি কর্মক্ষেত্র পরিষ্কার ও সংগঠিত রাখে, উৎপাদনশীলতা ও নিরাপত্তা বাড়ায়।', NULL, '5S: Sort (বাছাই), Set in Order (সাজানো), Shine (পরিষ্কার), Standardize (মানদণ্ড), Sustain (ধরে রাখা)।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3460, 473, 30, 'সার্ভিসিং বলতে কী বোঝায়?', 'written', 1, 'সার্ভিসিং-এ ইঞ্জিন অয়েল পরিবর্তন, ফিল্টার পরিবর্তন, পানি চেক ইত্যাদি অন্তর্ভুক্ত।', NULL, 'মোটরযানের ইঞ্জিন ও বিভিন্ন যন্ত্রাংশের কার্যক্ষমতা দীর্ঘস্থায়ী রাখতে নির্দিষ্ট সময় পরপর যে কাজগুলো করা হয় তাকে সার্ভিসিং বলে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3461, 473, 30, 'অটোশপের মেঝেতে তেল পড়লে কী করতে হবে?', 'written', 1, 'মেঝেতে তেল পড়লে পিছলে পড়ে দুর্ঘটনা ঘটতে পারে, তাই দ্রুত পরিষ্কার করা জরুরি।', NULL, 'অবিলম্বে ড্রাই ক্লিনিং পাউডার বা শোষক উপকরণ দিয়ে তেল শোষণ করে সরিয়ে ফেলতে হবে এবং মেঝে পরিষ্কার করতে হবে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3462, 473, 30, 'টুলবক্স কী এবং এতে কী কী রাখা হয়?', 'written', 1, 'টুলবক্সে সব টুলস সুশৃঙ্খলভাবে রাখলে কাজের সময় দ্রুত খুঁজে পাওয়া যায়।', NULL, 'টুলবক্স হচ্ছে যন্ত্রপাতির বাক্স। এতে গাড়ি মেরামতের জন্য প্রয়োজনীয় রেঞ্চ, স্ক্রুড্রাইভার, প্লায়ার্স, হ্যামার ইত্যাদি রাখা হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3463, 474, 30, 'গাড়ি চালনার সময় চালককে কোন কোন কাগজপত্র সাথে রাখতে হয়?', 'written', 1, 'এসব কাগজপত্র না থাকলে ট্রাফিক পুলিশ মামলা দিতে পারেন।', NULL, 'ড্রাইভিং লাইসেন্স, রেজিস্ট্রেশন সার্টিফিকেট (ব্লু-বুক), ট্যাক্স টোকেন, ইনসিওরেন্স সার্টিফিকেট, ফিটনেস সার্টিফিকেট ও রুটপারমিট (প্রযোজ্য ক্ষেত্রে) রাখতে হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3464, 475, 30, 'OBD স্ক্যানার কী? এটি কোন কাজে ব্যবহার হয়?', 'written', 1, 'আধুনিক অটোশপে OBD স্ক্যানার ছাড়া দ্রুত ডায়াগনসিস সম্ভব নয়।', NULL, 'OBD (On-Board Diagnostics) স্ক্যানার একটি ডিভাইস যা গাড়ির ECU থেকে ফল্ট কোড পড়ে ইঞ্জিন ও বৈদ্যুতিক ত্রুটি সনাক্ত করে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3465, 475, 30, 'গাড়ির ECU (ইসিইউ) কী?', 'written', 1, 'আধুনিক গাড়িতে ECU ছাড়া ইঞ্জিন ঠিকমতো চালানো সম্ভব নয়।', NULL, 'ECU মানে Engine Control Unit। এটি গাড়ির কম্পিউটার যা ইগনিশন টাইমিং, জ্বালানি সরবরাহ, এমিশন সিস্টেম ইত্যাদি নিয়ন্ত্রণ করে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3466, 475, 30, 'কম্পিউটারের সাহায্যে গাড়ির কোন কোন সমস্যা চিহ্নিত করা যায়?', 'written', 1, 'ডিজিটাল ডায়াগনসিস সময় ও অর্থ সাশ্রয় করে।', NULL, 'OBD স্ক্যানার বা ডায়াগনস্টিক সফটওয়্যার ব্যবহার করে ইঞ্জিন ফল্ট, সেন্সর ত্রুটি, ট্রান্সমিশন সমস্যা ও এমিশন ফল্ট চিহ্নিত করা যায়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3467, 475, 30, 'ইন্টারনেটের মাধ্যমে অটোমোবাইল টেকনিশিয়ান কীভাবে সাহায্য পেতে পারেন?', 'written', 1, 'ইন্টারনেট ব্যবহারে আধুনিক গাড়ির জটিল সমস্যা সমাধান সহজ হয়।', NULL, 'অনলাইন ওয়ার্কশপ ম্যানুয়াল, ভিডিও টিউটোরিয়াল, সার্ভিস ফোরাম ও প্রস্তুতকারকের ওয়েবসাইট থেকে প্রযুক্তিগত তথ্য পেতে পারেন।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3468, 475, 30, 'ডিজিটাল টর্ক রেঞ্চ ও সাধারণ টর্ক রেঞ্চের মধ্যে পার্থক্য কী?', 'written', 1, 'ডিজিটাল টর্ক রেঞ্চ বেশি নির্ভুল ও ব্যবহারে সুবিধাজনক।', NULL, 'ডিজিটাল টর্ক রেঞ্চ ডিজিটাল ডিসপ্লেতে সঠিক টর্ক মান দেখায় ও প্রোগ্রামযোগ্য। সাধারণ টর্ক রেঞ্চে ক্লিক সিগনালে নির্ধারিত টর্কে পৌঁছানো বোঝা যায়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3469, 476, 30, 'ওয়ার্কশপ ম্যানুয়াল কী? এটি কোন কাজে লাগে?', 'written', 1, 'ম্যানুয়াল ছাড়া সঠিক টর্ক স্পেসিফিকেশন বা পার্টস নম্বর জানা কঠিন।', NULL, 'ওয়ার্কশপ ম্যানুয়াল হলো গাড়ির প্রস্তুতকারকের দেওয়া সার্ভিসিং ও মেরামতের নির্দেশিকা পুস্তক। সঠিক সার্ভিসিং পদ্ধতি ও স্পেসিফিকেশন জানতে এটি ব্যবহার হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3470, 476, 30, 'টলারেন্স কী? এবং ক্লিয়ারেন্স কী?', 'written', 1, 'টলারেন্সের বাইরে গেলে যন্ত্রাংশ পরিবর্তন করতে হয়।', NULL, 'ক্লিয়ারেন্স হলো দুটি যন্ত্রাংশের মধ্যবর্তী ফাঁক। টলারেন্স হলো সেই ক্লিয়ারেন্সের গ্রহণযোগ্য সীমার পরিধি।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3471, 476, 30, 'প্রকৌশল ড্রয়িং-এ বিভিন্ন ধরনের লাইনের ব্যবহার কী?', 'written', 1, 'ড্রয়িং-এর লাইন কোড বুঝলে যেকোনো ইঞ্জিনিয়ারিং ডিজাইন পড়া সম্ভব।', NULL, 'কঠিন লাইন দৃশ্যমান অংশ দেখায়, ড্যাশড লাইন লুকানো অংশ, সেন্টার লাইন অক্ষ বা কেন্দ্র, আর সরু লাইন মাত্রা বা টীকা দেখায়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3472, 476, 30, 'Parts Catalog কী? এটি কোন কাজে ব্যবহার হয়?', 'written', 1, 'ভুল পার্টস অর্ডার এড়াতে Parts Catalog খুবই গুরুত্বপূর্ণ।', NULL, 'Parts Catalog হলো গাড়ির প্রতিটি যন্ত্রাংশের চিত্র ও পার্ট নম্বরসহ তালিকা। সঠিক পার্টস অর্ডার ও সনাক্ত করতে এটি ব্যবহার হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3473, 476, 30, 'স্কেচ ও ড্রয়িং-এর পার্থক্য কী?', 'written', 1, 'স্কেচ দ্রুত ধারণা বোঝাতে, ড্রয়িং উৎপাদনের জন্য ব্যবহার হয়।', NULL, 'স্কেচ হাতে আঁকা মোটামুটি চিত্র যা স্কেল মেনে চলে না। ড্রয়িং সঠিক স্কেল ও মানদণ্ড মেনে তৈরি প্রকৌশল চিত্র।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3474, 476, 30, 'ভালভ ক্লিয়ারেন্স মাপার পদ্ধতি কী?', 'written', 1, 'সঠিক ভালভ ক্লিয়ারেন্স না থাকলে ইঞ্জিনের শক্তি কমে ও শব্দ বাড়ে।', NULL, 'ফিলার গেজ ব্যবহার করে ভালভ ক্লোজড অবস্থায় রোকার আর্ম ও ভালভ স্টেমের মধ্যবর্তী গ্যাপ মাপা হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3475, 476, 30, 'সিলিন্ডার বোর মাপতে কোন যন্ত্র ব্যবহার হয়?', 'written', 1, 'নির্দিষ্ট সীমার বেশি পরিধান হলে সিলিন্ডার রিবোর করতে হয়।', NULL, 'সিলিন্ডার বোর গেজ বা ডায়াল গেজ ব্যবহার করে সিলিন্ডারের অভ্যন্তরীণ ব্যাস মাপা হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3476, 476, 30, 'ইঞ্জিন স্পেসিফিকেশন শিট কেন গুরুত্বপূর্ণ?', 'written', 1, 'স্পেসিফিকেশন না মেনে সার্ভিসিং করলে ইঞ্জিন ক্ষতিগ্রস্ত হতে পারে।', NULL, 'ইঞ্জিন স্পেসিফিকেশন শিটে টর্ক মান, ক্লিয়ারেন্স, বোর ও স্ট্রোক, অয়েল গ্রেড ইত্যাদি সঠিক তথ্য থাকে যা সার্ভিসিং-এ অপরিহার্য।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3477, 477, 30, 'স্পেশাল সার্ভিস টুলস (SST) কী?', 'written', 1, 'SST ছাড়া কিছু কাজ করা কঠিন বা অসম্ভব এবং যন্ত্রাংশ ক্ষতিগ্রস্ত হতে পারে।', NULL, 'গাড়ি প্রস্তুতকারক বিশেষ কাজের জন্য যে বিশেষ টুলস তৈরি করে তাকে SST বলে। যেমন: ভালভ স্প্রিং কম্প্রেসর, পিস্টন রিং কম্প্রেসর।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3478, 477, 30, 'পুলার কী কাজে ব্যবহার হয়?', 'written', 1, 'পুলার ছাড়া বিয়ারিং খুলতে হ্যামার দিয়ে আঘাত করলে শ্যাফট ক্ষতিগ্রস্ত হতে পারে।', NULL, 'শ্যাফটের সাথে আটকে থাকা বিয়ারিং, গিয়ার বা পুলি খুলতে পুলার ব্যবহার হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3479, 477, 30, 'ভার্নিয়ার ক্যালিপার কোন কাজে ব্যবহার হয়?', 'written', 1, 'ভার্নিয়ার ক্যালিপার ০.০২ মি.মি. পর্যন্ত সূক্ষ্মভাবে মাপতে পারে।', NULL, 'সূক্ষ্মভাবে দৈর্ঘ্য, ব্যাস (ভেতর ও বাহির) এবং গভীরতা মাপতে ভার্নিয়ার ক্যালিপার ব্যবহার হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3480, 477, 30, 'নিউমেটিক টুলস কী? একটি উদাহরণ দাও।', 'written', 1, 'নিউমেটিক টুলস দ্রুত ও কম ক্লান্তিকর কারণ হাতের বদলে বায়ু শক্তি ব্যবহার হয়।', NULL, 'সংকুচিত বায়ুর সাহায্যে যেসব টুলস পরিচালিত হয় তাদের নিউমেটিক টুলস বলে। উদাহরণ: এয়ার রেঞ্চ।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3481, 477, 30, 'অটোশপে কোন ধরনের রেঞ্চ বেশি ব্যবহৃত হয়?', 'written', 1, 'সকেট রেঞ্চ দ্রুত বোল্ট খোলা-লাগানোর জন্য সবচেয়ে কার্যকর।', NULL, 'অ্যাডজাস্টেবল রেঞ্চ, সকেট রেঞ্চ ও কম্বিনেশন রেঞ্চ অটোশপে বেশি ব্যবহৃত হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3482, 477, 30, 'ড্রিল মেশিন কোন ধরনের টুলস এবং এটি কীভাবে ব্যবহার হয়?', 'written', 1, 'সঠিক ড্রিল বিট ও গতি না বেছে নিলে উপকরণ নষ্ট হতে পারে।', NULL, 'ড্রিল মেশিন একটি পাওয়ার টুলস। বৈদ্যুতিক বা বায়ুচালিত ড্রিল বিট ঘুরিয়ে ধাতু বা অন্য উপকরণে ছিদ্র করতে ব্যবহার হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3483, 477, 30, 'টর্ক রেঞ্চ কেন ব্যবহার করা হয়?', 'written', 1, 'অতিরিক্ত বা কম টর্কে বোল্ট টাইট করলে যন্ত্রাংশ ক্ষতিগ্রস্ত হতে পারে।', NULL, 'সিলিন্ডার হেড বোল্ট, হাব নাট ইত্যাদিকে প্রস্তুতকারকের নির্দেশিত টর্কে টাইট করতে টর্ক রেঞ্চ ব্যবহার হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3484, 479, 30, 'সাসপেনশন সিস্টেমের প্রধান কাজ কী?', 'written', 1, 'সাসপেনশন ছাড়া গাড়ি চালানো অসম্ভব; এটি স্টিয়ারিং নিয়ন্ত্রণেও সাহায্য করে।', NULL, 'সাসপেনশন সিস্টেম রাস্তার ধাক্কা শোষণ করে গাড়ির যাত্রী ও যন্ত্রাংশ সুরক্ষিত রাখে এবং চাকার সাথে রাস্তার সংযোগ নিশ্চিত করে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3485, 479, 30, 'হুইল অ্যালাইনমেন্ট ও হুইল ব্যালেন্সিং-এর পার্থক্য কী?', 'written', 1, 'অ্যালাইনমেন্ট ও ব্যালেন্সিং না করালে টায়ার অসমানভাবে ক্ষয় হয় ও স্টিয়ারিং কাঁপে।', NULL, 'হুইল অ্যালাইনমেন্ট মানে চাকার কোণ (ক্যামবার, টো, ক্যাস্টার) সঠিক রাখা। হুইল ব্যালেন্সিং মানে চাকার ওজন সমানভাবে বিতরণ করা।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3486, 479, 30, 'শক অ্যাবজরবার নষ্ট হলে গাড়িতে কী সমস্যা হয়?', 'written', 1, 'শক অ্যাবজরবার নষ্ট হলে দ্রুত পরিবর্তন করা উচিত।', NULL, 'গাড়ি বেশি ঝাঁকুনি খায়, ব্রেকিং দূরত্ব বাড়ে, টায়ার দ্রুত ক্ষয় হয় এবং যাত্রীর অস্বস্তি বাড়ে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3487, 479, 30, 'সিভি (CV) জয়েন্টের কাজ কী?', 'written', 1, 'CV জয়েন্ট ক্ষয় হলে মোড় নেওয়ার সময় খটখট শব্দ হয়।', NULL, 'সিভি জয়েন্ট ড্রাইভশ্যাফটের কোণ পরিবর্তনের সময়ও সমান গতিতে পাওয়ার সংক্রমণ নিশ্চিত করে। ফ্রন্ট-হুইল-ড্রাইভ গাড়িতে এটি অপরিহার্য।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3488, 479, 30, 'গাড়ি মোড় ঘুরলে ভেতরের ও বাইরের চাকার গতি ভিন্ন কেন?', 'written', 1, 'ডিফারেন্সিয়াল ছাড়া মোড়ে টায়ার স্লিপ করত।', NULL, 'মোড়ে বাইরের চাকা বেশি পথ অতিক্রম করে বলে তাকে দ্রুত ঘুরতে হয়। ডিফারেন্সিয়াল গিয়ার এই পার্থক্য নিশ্চিত করে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3489, 479, 30, 'লিফ স্প্রিং সার্ভিসিং কীভাবে করা হয়?', 'written', 1, 'নিয়মিত সার্ভিসিং না করলে স্প্রিং ক্রিক করে ও কার্যকারিতা কমে।', NULL, 'লিফ স্প্রিং পাতের মধ্যে গ্রাফাইট পাউডার বা স্পেশাল লুব্রিকেন্ট লাগানো হয় যাতে পাতের মধ্যে ঘর্ষণ কমে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3490, 479, 30, 'ক্যামবার অ্যাঙ্গেল কী? এটি ভুল হলে কী হয়?', 'written', 1, 'ক্যামবার ঠিক না থাকলে গাড়ি এক দিকে টান মারে।', NULL, 'উল্লম্বের সাথে চাকার হেলানো কোণকে ক্যামবার বলে। পজিটিভ ক্যামবার বাইরে হেলানো, নেগেটিভ ভেতরে। ভুল ক্যামবারে টায়ার এক পাশে দ্রুত ক্ষয় হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3491, 479, 30, 'স্টিয়ারিং হুইল কাঁপার সম্ভাব্য কারণ কী?', 'written', 1, 'স্টিয়ারিং কাঁপলে দ্রুত মেকানিক দেখানো উচিত।', NULL, 'চাকার ব্যালেন্সিং নেই, বল জয়েন্ট ক্ষয়, সাসপেনশন কম্পোনেন্ট ঢিলা বা টাই রড এন্ড ক্ষয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3492, 480, 30, 'ওয়াটার কুলিং সিস্টেম কীভাবে কাজ করে?', 'written', 1, 'থার্মোস্ট্যাট ইঞ্জিন গরম না হওয়া পর্যন্ত কুলেন্ট রেডিয়েটরে যেতে দেয় না।', NULL, 'ওয়াটার পাম্প কুলেন্ট সঞ্চালন করে। কুলেন্ট ইঞ্জিনের তাপ শোষণ করে রেডিয়েটরে যায়, সেখানে বাতাসে ঠান্ডা হয়ে পুনরায় ইঞ্জিনে ফেরে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3493, 480, 30, 'রেডিয়েটর প্রেশার ক্যাপের দুটি ভালভের নাম ও কাজ কী?', 'written', 1, 'প্রেশার ক্যাপের কারণে কুলিং সিস্টেম ১.১-১.৩ বার চাপে কাজ করে।', NULL, '১. প্রেশার রিলিজ ভালভ: অতিরিক্ত চাপে খুলে কুলেন্ট ওভারফ্লো ট্যাংকে পাঠায়। ২. ভ্যাকুয়াম ভালভ: ঠান্ডায় চাপ কমলে ওভারফ্লো ট্যাংক থেকে কুলেন্ট ফিরিয়ে আনে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3494, 480, 30, 'ইঞ্জিন ওভারহিটের কারণ কী কী?', 'written', 1, 'ওভারহিটে ইঞ্জিন বন্ধ না করলে হেড গ্যাসকেট পুড়ে বা ইঞ্জিন সিজ হতে পারে।', NULL, 'রেডিয়েটর লিক বা ব্লক, ফ্যানবেল্ট ছেঁড়া, থার্মোস্ট্যাট আটকানো, ওয়াটার পাম্প নষ্ট বা কুলেন্ট পরিমাণ কম।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3495, 480, 30, 'কুলিং ফ্যানের কাজ কী?', 'written', 1, 'ইলেকট্রিক ফ্যান থার্মোস্ট্যাটিক সুইচ দিয়ে নিয়ন্ত্রিত হয়।', NULL, 'রেডিয়েটরের মধ্য দিয়ে বাতাস প্রবাহিত করে গরম কুলেন্ট ঠান্ডা করা।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3496, 480, 30, 'এয়ার কুলিং ও ওয়াটার কুলিং সিস্টেমের পার্থক্য কী?', 'written', 1, 'ওয়াটার কুলিং বেশি কার্যকর ও ইঞ্জিন তাপমাত্রা নিয়ন্ত্রণযোগ্য।', NULL, 'এয়ার কুলিং: সিলিন্ডারের ফিনে বাতাস সরাসরি তাপ নেয় (মোটরসাইকেলে)। ওয়াটার কুলিং: কুলেন্ট মাধ্যমে তাপ রেডিয়েটরে নিয়ে ঠান্ডা করে (গাড়িতে)।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3497, 480, 30, 'থার্মোস্ট্যাট না থাকলে বা নষ্ট হলে কী হয়?', 'written', 1, 'থার্মোস্ট্যাট সাশ্রয়ী কিন্তু অত্যন্ত গুরুত্বপূর্ণ যন্ত্রাংশ।', NULL, 'থার্মোস্ট্যাট আটকে থাকলে কুলেন্ট সঞ্চালন বন্ধ হয়ে ইঞ্জিন অতিরিক্ত গরম হয়। খোলা আটকালে ইঞ্জিন স্বাভাবিক তাপমাত্রায় পৌঁছায় না।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3498, 480, 30, 'গরম রেডিয়েটরে ঠান্ডা পানি দেওয়া কেন বিপজ্জনক?', 'written', 1, 'ইঞ্জিন ঠান্ডা না হওয়া পর্যন্ত রেডিয়েটর ক্যাপ খোলা বিপজ্জনক।', NULL, 'হঠাৎ তাপমাত্রা পরিবর্তনে ইঞ্জিন ব্লক বা হেড ক্র্যাক হতে পারে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3499, 481, 30, 'ইঞ্জিন অয়েলের প্রধান কাজগুলো কী?', 'written', 1, 'মাল্টিফাংশনাল ইঞ্জিন অয়েল ছাড়া ইঞ্জিন টেকসই হয় না।', NULL, 'ঘর্ষণ কমানো, যন্ত্রাংশ ঠান্ডা রাখা, মরিচা রোধ করা, পরিষ্কার রাখা এবং সিলিং নিশ্চিত করা।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02');
INSERT INTO `questions` (`id`, `exam_id`, `course_id`, `question_text`, `question_type`, `marks`, `explanation`, `model_answer`, `answer`, `sort_order`, `created_at`, `updated_at`) VALUES
(3500, 481, 30, 'SAE গ্রেড সংখ্যার মানে কী?', 'written', 1, 'সঠিক SAE গ্রেড ব্যবহার না করলে ইঞ্জিন বা গিয়ারবক্স ক্ষতিগ্রস্ত হতে পারে।', NULL, 'SAE (Society of Automotive Engineers) গ্রেড তেলের ঘনত্ব (viscosity) প্রকাশ করে। বড় সংখ্যা = বেশি ঘন। যেমন SAE-30 মাঝারি, SAE-90 গিয়ার অয়েলের জন্য।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3501, 481, 30, 'ইঞ্জিন অয়েল কতদিন পর পরিবর্তন করতে হয়?', 'written', 1, 'নিয়মিত পরিবর্তন না করলে অয়েল ক্ষয়কারী হয়ে যায়।', NULL, 'প্রস্তুতকারকের নির্দেশ অনুযায়ী সাধারণত প্রতি ৫,০০০-১০,০০০ কিমিতে মিনারেল অয়েল ও ১৫,০০০-২০,০০০ কিমিতে ফুল সিন্থেটিক অয়েল পরিবর্তন করতে হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3502, 481, 30, 'অয়েল ফিল্টার কী করে?', 'written', 1, 'অয়েল পরিবর্তনের সময় ফিল্টারও পরিবর্তন করতে হয়।', NULL, 'ইঞ্জিন অয়েল থেকে ধুলো, ধাতব কণা ও অন্যান্য দূষণকারী পদার্থ আটকে তেল পরিষ্কার রাখে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3503, 481, 30, 'ডিফারেন্সিয়াল ঘড়ঘড় শব্দ হওয়ার কারণ কী?', 'written', 1, 'নিয়মিত গিয়ার অয়েল পরীক্ষা করে সময়মতো পরিবর্তন করতে হয়।', NULL, 'ম্যাশিং গিয়ারগুলির দাঁতের ফাঁক (ব্যাকলাশ) বেড়ে যাওয়া বা গিয়ার অয়েল শেষ হয়ে গেলে এই শব্দ হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3504, 481, 30, 'মাল্টিগ্রেড অয়েল (যেমন SAE 20W-50) এর সুবিধা কী?', 'written', 1, 'W = Winter। মাল্টিগ্রেড অয়েল আধুনিক গাড়িতে সবচেয়ে বেশি ব্যবহৃত।', NULL, 'এটি শীতে পাতলা (কোল্ড স্টার্টে ভালো) এবং গরমে ঘন (সুরক্ষা ভালো) থাকে, তাই সারাবছর একটি গ্রেডেই চলে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3505, 481, 30, 'ইঞ্জিন অয়েল লিক পরীক্ষা করার পদ্ধতি কী?', 'written', 1, 'তেল লিক দ্রুত মেরামত না করলে ইঞ্জিন সিজ হওয়ার ঝুঁকি থাকে।', NULL, 'ইঞ্জিনের নিচে ওয়েল/অয়েল দাগ পরীক্ষা করা, ডিপস্টিকে তেলের স্তর চেক করা এবং গ্যারেজে পার্ক করে মেঝে পরীক্ষা করা।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3506, 481, 30, 'অয়েল প্রেশার লো হলে কী কারণ হতে পারে?', 'written', 1, 'লো অয়েল প্রেশারে গাড়ি চালালে ইঞ্জিনে মারাত্মক ক্ষতি হতে পারে।', NULL, 'অয়েল লেভেল কম, অয়েল পাম্প নষ্ট, ক্লগড অয়েল ফিল্টার বা ইঞ্জিনের অভ্যন্তরীণ লিক।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3507, 481, 30, 'ইঞ্জিন অয়েলে পানি মিশলে কীভাবে বোঝা যায়?', 'written', 1, 'হেড গ্যাসকেট লিক বা ইঞ্জিন ব্লক ক্র্যাক হলে পানি অয়েলে মিশতে পারে।', NULL, 'অয়েল দুধের মতো সাদা বা হালকা বাদামি ফেনাযুক্ত হয়ে যায়। ডিপস্টিকে অয়েল মেয়োনিজের মতো দেখায়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3508, 482, 30, 'গাড়ির স্টার্টিং সিস্টেমের প্রধান উপাদানগুলো কী কী?', 'written', 1, 'সব উপাদান সঠিক না থাকলে ইঞ্জিন স্টার্ট নেয় না।', NULL, 'ব্যাটারি, ইগনিশন সুইচ, স্টার্টার মোটর, সোলেনয়েড, নিউট্রাল সেফটি সুইচ।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3509, 482, 30, 'লিড-অ্যাসিড ব্যাটারি কীভাবে চার্জ হয়?', 'written', 1, 'স্বল্প দূরত্বের যাত্রায় ব্যাটারি সম্পূর্ণ চার্জ নাও হতে পারে।', NULL, 'গাড়ি চলার সময় অল্টারনেটর বিদ্যুৎ উৎপন্ন করে ব্যাটারি চার্জ করে। রাসায়নিক বিক্রিয়ায় সীসার প্লেটে সালফেট পরিষ্কার হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3510, 482, 30, 'ব্যাটারির টার্মিনালে সাদা স্তর জমে কেন এবং পরিষ্কার করতে কী করতে হয়?', 'written', 1, 'নোংরা টার্মিনাল কানেকশন দুর্বল করে স্টার্টিং সমস্যা সৃষ্টি করে।', NULL, 'সালফিউরিক অ্যাসিডের বাষ্প লিড টার্মিনালে জমে সাদা লেড সালফেট তৈরি করে। বেকিং সোডা ও পানির মিশ্রণ দিয়ে পরিষ্কার করতে হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3511, 482, 30, 'অল্টারনেটর ও ডাইনামোর পার্থক্য কী?', 'written', 1, 'আধুনিক সব গাড়িতে অল্টারনেটর ব্যবহার হয়।', NULL, 'ডাইনামো DC উৎপন্ন করে এবং পুরানো প্রযুক্তি। অল্টারনেটর AC উৎপন্ন করে তারপর রেকটিফায়ার দিয়ে DC-তে পরিণত করে; বেশি কার্যকর।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3512, 482, 30, 'ব্যাটারি কেন ফুলে যায়?', 'written', 1, 'ফোলা ব্যাটারি বিস্ফোরণের ঝুঁকি থাকে, তাই দ্রুত পরিবর্তন করতে হবে।', NULL, 'অতিরিক্ত চার্জিং (ওভারচার্জিং) বা ত্রুটিযুক্ত ভোল্টেজ রেগুলেটরের কারণে ব্যাটারির ভেতরে গ্যাস জমে ফুলে যায়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3513, 482, 30, 'ইঞ্জিন স্টার্ট না হওয়ার কারণগুলো কী কী?', 'written', 1, 'পদ্ধতিগতভাবে প্রতিটি সিস্টেম চেক করে কারণ খুঁজে বের করতে হয়।', NULL, 'ব্যাটারি ডিসচার্জ, স্টার্টার মোটর নষ্ট, ইগনিশন সমস্যা, ফুয়েল না থাকা বা ইমোবিলাইজার সক্রিয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3514, 482, 30, 'জাম্প স্টার্ট কীভাবে দিতে হয়?', 'written', 1, 'ভুল সংযোগে স্পার্ক থেকে বিস্ফোরণ বা ইলেকট্রনিক্স ক্ষতি হতে পারে।', NULL, 'পজিটিভ টু পজিটিভ সংযোগ করুন, তারপর নেগেটিভ কেবল ভালো ব্যাটারির নেগেটিভে ও অপর প্রান্ত গাড়ির ফ্রেমে লাগান। ভালো ব্যাটারির গাড়ি স্টার্ট করে পরে দুর্বল গাড়ি স্টার্ট করুন।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3515, 482, 30, 'ভোল্টেজ রেগুলেটরের কাজ কী?', 'written', 1, 'ভোল্টেজ রেগুলেটর নষ্ট হলে ব্যাটারি অতিরিক্ত বা কম চার্জ হয়।', NULL, 'অল্টারনেটরের আউটপুট ভোল্টেজ (সাধারণত ১৩.৮-১৪.৪ ভোল্ট) নিয়ন্ত্রণ করে যাতে ব্যাটারি সঠিকভাবে চার্জ হয় ও বৈদ্যুতিক সরঞ্জাম ক্ষতিগ্রস্ত না হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3516, 482, 30, 'গাড়িতে ফিউজ কেন থাকে?', 'written', 1, 'ফিউজ গললে একই রেটিং-এর ফিউজ দিয়ে প্রতিস্থাপন করতে হবে।', NULL, 'বৈদ্যুতিক শর্ট সার্কিট বা অতিরিক্ত কারেন্টে সার্কিট পুড়ে যাওয়া ও আগুন লাগা রোধ করতে ফিউজ নিজে গলে সার্কিট বিচ্ছিন্ন করে দেয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
