(3518, 483, 30, 'ডিজেল ইঞ্জিন হঠাৎ বন্ধ হওয়ার কারণ কী কী?', 'written', 1, 'নিয়মিত ফুয়েল ফিল্টার পরিবর্তন করলে অনেক সমস্যা এড়ানো যায়।', NULL, 'ট্যাংকে জ্বালানি না থাকলে, ফুয়েল পাম্প কাজ না করলে, ফুয়েল ফিল্টার ব্লক হলে, ইনটেক বা এগজস্ট ভালভ কাজ না করলে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3519, 483, 30, 'টার্বোচার্জার কীভাবে ইঞ্জিনের শক্তি বাড়ায়?', 'written', 1, 'টার্বো গরম করতে ও ঠান্ডা করতে সময় দিতে হয়।', NULL, 'টার্বোচার্জার এগজস্ট গ্যাসের শক্তি ব্যবহার করে কম্প্রেসার চালায়। কম্প্রেসার অতিরিক্ত বায়ু ইনটেকে ঠেলে দেয়, যা বেশি জ্বালানি পোড়ানো ও বেশি শক্তি উৎপাদন নিশ্চিত করে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3520, 483, 30, 'ক্যাটালিটিক কনভার্টার কী করে?', 'written', 1, 'ক্যাটালিটিক কনভার্টার কার্যকর থাকলে গাড়ির এমিশন টেস্টে পাস সহজ হয়।', NULL, 'এটি এগজস্ট গ্যাসের CO, HC ও NOx-কে রাসায়নিকভাবে CO₂, H₂O ও N₂-তে রূপান্তর করে পরিবেশ দূষণ কমায়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3521, 483, 30, 'ফুয়েল ইনজেকশন সিস্টেম কার্বুরেটর সিস্টেমের চেয়ে ভালো কেন?', 'written', 1, 'কার্বুরেটর সহজ কিন্তু কম কার্যকর।', NULL, 'ফুয়েল ইনজেকশন সিস্টেম ECU-নিয়ন্ত্রিত হওয়ায় সঠিক পরিমাণ জ্বালানি ইনজেক্ট হয়। এতে জ্বালানি সাশ্রয়, দূষণ কম ও পারফরমেন্স বেশি।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3522, 483, 30, 'এয়ার ফিল্টার কেন নিয়মিত পরিবর্তন করতে হয়?', 'written', 1, 'প্রতি ১৫,০০০-৩০,০০০ কিমিতে এয়ার ফিল্টার পরিবর্তন করা উচিত।', NULL, 'নোংরা এয়ার ফিল্টার বায়ু প্রবাহ কমায়, ফলে রিচ মিশ্রণ তৈরি হয় যা জ্বালানি অপচয় করে ও কালো ধোঁয়া বের হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3523, 483, 30, 'অক্সিজেন সেন্সর কী তথ্য দেয় ও এটি কোথায় থাকে?', 'written', 1, 'অক্সিজেন সেন্সর নষ্ট হলে ইঞ্জিন বেশি জ্বালানি খায়।', NULL, 'এটি এগজস্ট মেনিফোল্ডে থাকে এবং এগজস্ট গ্যাসে অক্সিজেনের পরিমাণ মাপে। ECU এই তথ্য দিয়ে বায়ু-জ্বালানি অনুপাত নিয়ন্ত্রণ করে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3524, 483, 30, 'ট্যাংকে পানি ঢুকলে ইঞ্জিনে কী সমস্যা হয়?', 'written', 1, 'বিশ্বস্ত পেট্রোল পাম্প থেকে জ্বালানি নেওয়া উচিত।', NULL, 'পানি জ্বালানির সাথে মিশে কার্বুরেটর/ইনজেক্টর ব্লক করে, ইঞ্জিন মিসফায়ার ও বন্ধ হওয়ার সমস্যা সৃষ্টি করে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3525, 484, 30, 'ইগনিশন সিস্টেমের প্রধান অংশগুলো কী কী?', 'written', 1, 'আধুনিক গাড়িতে ডিস্ট্রিবিউটরহীন DIS বা কয়েল-অন-প্লাগ সিস্টেম ব্যবহার হয়।', NULL, 'ব্যাটারি, ইগনিশন কয়েল, ডিস্ট্রিবিউটর (পুরানো) বা ইসিইউ (আধুনিক), HT লিড ও স্পার্ক প্লাগ।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3526, 484, 30, 'স্পার্ক প্লাগ কীভাবে ইঞ্জিনে স্পার্ক দেয়?', 'written', 1, 'সঠিক গ্যাপ (০.৭-১.২ মি.মি.) না থাকলে স্পার্ক দুর্বল হয়।', NULL, 'ইগনিশন কয়েল থেকে উচ্চ ভোল্টেজ কারেন্ট HT লিড দিয়ে স্পার্ক প্লাগে আসে। প্লাগের ইলেকট্রোড গ্যাপে স্পার্ক তৈরি হয়ে বায়ু-জ্বালানি মিশ্রণ প্রজ্বলিত করে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3527, 484, 30, 'ইগনিশন কয়েলের কাজ কী?', 'written', 1, 'প্রাইমারি ওয়াইন্ডিং কম, সেকেন্ডারি বেশি পাক দেওয়া থাকে।', NULL, 'ব্যাটারির ১২ ভোল্টকে ট্রান্সফর্মার নীতিতে ৩০,০০০ ভোল্ট পর্যন্ত উচ্চ ভোল্টেজে রূপান্তর করে স্পার্ক প্লাগে স্পার্ক দেওয়ার উপযোগী করে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3528, 484, 30, 'ইগনিশন টাইমিং কী? এটি কেন সঠিক রাখা দরকার?', 'written', 1, 'টাইমিং ভুল হলে ইঞ্জিন নক করে বা শক্তি কমে।', NULL, 'ইগনিশন টাইমিং মানে পিস্টন কখন TDC-তে পৌঁছানোর আগে স্পার্ক দেওয়া হবে সেই সময়। সঠিক টাইমিংয়ে সর্বোচ্চ শক্তি ও দক্ষতা পাওয়া যায়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3529, 484, 30, 'ডিস্ট্রিবিউটরের কাজ কী?', 'written', 1, 'আধুনিক গাড়িতে ডিস্ট্রিবিউটরের পরিবর্তে ECU ও পৃথক কয়েল ব্যবহার হয়।', NULL, 'ইগনিশন কয়েল থেকে আসা উচ্চ ভোল্টেজকে সঠিক ফায়ারিং অর্ডারে প্রতিটি সিলিন্ডারের স্পার্ক প্লাগে পর্যায়ক্রমে পাঠানো।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3530, 484, 30, 'স্পার্ক প্লাগ পরিদর্শন করার সময় কী কী দেখতে হয়?', 'written', 1, 'স্পার্ক প্লাগের অবস্থা থেকে ইঞ্জিনের স্বাস্থ্য সম্পর্কে অনেক তথ্য জানা যায়।', NULL, 'ইলেকট্রোড ক্ষয়, কার্বন জমা, তেল পোড়ার চিহ্ন, ক্র্যাক এবং গ্যাপের পরিমাণ পরীক্ষা করতে হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3531, 484, 30, 'ডিজেল ইঞ্জিনে গ্লো প্লাগ কেন ব্যবহার হয়?', 'written', 1, 'গ্লো প্লাগ নষ্ট হলে ঠান্ডায় ইঞ্জিন স্টার্ট নিতে অসুবিধা হয়।', NULL, 'ঠান্ডা আবহাওয়ায় সিলিন্ডারের বায়ু গরম করে ডিজেলের স্বতঃ-প্রজ্বলন নিশ্চিত করতে গ্লো প্লাগ ব্যবহার হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3532, 484, 30, 'ইলেকট্রনিক ইগনিশন সিস্টেমের সুবিধা কী?', 'written', 1, 'ইলেকট্রনিক ইগনিশন নির্ভরযোগ্য ও দীর্ঘস্থায়ী।', NULL, 'ব্রেকার পয়েন্ট ও কনডেনসার না থাকায় রক্ষণাবেক্ষণ কম লাগে, টাইমিং আরো সঠিক হয় ও জ্বালানি সাশ্রয় হয়।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3533, 484, 30, 'নক সেন্সর কী করে?', 'written', 1, 'নক থেকে পিস্টন ও সিলিন্ডার হেড ক্ষতিগ্রস্ত হতে পারে।', NULL, 'ইঞ্জিন নক (অকালে দহন) শনাক্ত করে ECU-কে সংকেত পাঠায়। ECU তখন ইগনিশন টাইমিং রিটার্ড করে নক বন্ধ করে।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
(3534, 484, 30, 'স্পার্ক প্লাগের হিট রেঞ্জ বলতে কী বোঝায়?', 'written', 1, 'ভুল হিট রেঞ্জের প্লাগ ব্যবহারে প্রি-ইগনিশন বা ফাউলিং হয়।', NULL, 'স্পার্ক প্লাগের তাপ অপচয়ের ক্ষমতাকে হিট রেঞ্জ বলে। হট প্লাগ ধীরে তাপ ছাড়ে (কম চাপের ইঞ্জিন), কোল্ড প্লাগ দ্রুত তাপ ছাড়ে (হাই পারফরমেন্স ইঞ্জিন)।', 0, '2026-06-02 23:01:02', '2026-06-02 23:01:02'),
