('faq_1_a', 'প্ল্যাটফর্মে রেজিস্ট্রেশন করা সম্পূর্ণ ফ্রি। তবে যেকোনো কোর্সের প্রশ্ন ব্যাংক এবং মক টেস্টে অংশ নিতে মাসে ১০০ টাকা ফি দিয়ে সাবস্ক্রাইব করতে হবে।', '2026-05-18 11:57:42', '2026-05-18 11:57:42'),
('faq_1_q', 'রেজিস্ট্রেশন ফি কত?', '2026-05-18 11:57:42', '2026-05-18 11:57:42'),
('faq_2_a', 'আপনার রেফার কোড দিয়ে কাউকে ইনভাইট করলে সে প্রথম কোর্স কেনার সময় ১০% ডিসকাউন্ট পাবে এবং আপনার অ্যাকাউন্টে ১০ টাকা যোগ হবে।', '2026-05-18 11:57:42', '2026-05-18 11:57:42'),
('faq_2_q', 'রেফারেল সিস্টেম কিভাবে কাজ করে?', '2026-05-18 11:57:42', '2026-05-18 11:57:42'),
('faq_3_a', 'হ্যাঁ, অবশ্যই! আমাদের প্ল্যাটফর্মটি ১০০% মোবাইল ফ্রেন্ডলি।', '2026-05-18 11:57:42', '2026-05-18 11:57:42'),
('faq_3_q', 'আমি কি মোবাইল থেকে পরীক্ষা দিতে পারবো?', '2026-05-18 11:57:42', '2026-05-18 11:57:42'),
('footer_description', 'NSDA লেভেল অ্যাসেসমেন্ট পরীক্ষার জন্য বাংলাদেশের সবচেয়ে আধুনিক এবং কার্যকরী প্র্যাকটিস প্ল্যাটফর্ম।', '2026-05-18 11:57:42', '2026-05-18 11:57:42'),
('gateway_sandbox', '0', '2026-05-26 17:34:25', '2026-06-08 15:00:20'),
('gemini_api_key', 'AIzaSyB9eiaksnulNQUO6MK0lp_cENvQEqvz4gw', '2026-05-22 08:48:25', '2026-05-22 08:48:25'),
('hero_badge', '#1 NSDA Assessment Tools in BD', '2026-05-18 11:57:42', '2026-05-18 11:57:42'),
('hero_heading', 'বাংলাদেশের এক    নম্বর NSDA অ্যাসেসমেন্ট প্রস্তুতি প্ল্যাটফর্ম', '2026-05-23 20:53:37', '2026-05-23 21:11:03'),
('hero_student_count', '+1k', '2026-05-18 11:57:42', '2026-05-18 11:57:42'),
('hero_subtext', 'শুধু প্র্যাকটিক্যাল নয়, CS অনুযায়ী সম্পূর্ণ MCQ ও Written প্রশ্নব্যাংক প্র্যাকটিস করুন আপনার মোবাইলেই। নিজেকে আগে থেকেই যাচাই করে নিন এবং প্রথমবারেই \'Competent (C)\' সার্টিফিকেট অর্জন করুন।', '2026-05-23 20:53:37', '2026-05-23 21:10:41'),
('landing_comparison_image', 'uploads/landing/comparison_6a2946482fe7c.jpg', '2026-06-10 11:11:04', '2026-06-10 11:11:04'),
('landing_faqs', '[{\"q\":\"সব প্রশ্ন কি রিয়েল অ্যাসেসমেন্ট থেকে নেওয়া?\",\"a\":\"আমাদের প্রশ্নব্যাংক CS, UoC, অ্যাসেসমেন্ট প্যাটার্ন এবং এক্সপার্ট ট্রেইনারদের মতামতের ভিত্তিতে তৈরি। এগুলো শতভাগ রিয়েল না হলেও অ্যাসেসমেন্ট পাসের জন্য যথেষ্ট প্রস্তুতি দেয়।\"},{\"q\":\"এখানে কি প্র্যাকটিক্যাল ট্রেনিং করানো হয়?\",\"a\":\"না। AssessmentBD শুধুমাত্র Written ও MCQ প্রস্তুতির জন্য একটি ডিজিটাল প্ল্যাটফর্ম। কোনো প্র্যাকটিক্যাল ট্রেনিং প্রদান করা হয় না।\"},{\"q\":\"যেকোনো ডিভাইস থেকে ব্যবহার করা যাবে?\",\"a\":\"হ্যাঁ, যেকোনো স্মার্টফোন, ট্যাবলেট বা কম্পিউটার থেকে লগইন করে প্র্যাকটিস করা যাবে।\"},{\"q\":\"৫০% মানি-ব্যাক গ্যারান্টি কীভাবে কাজ করে?\",\"a\":\"Pro প্ল্যান নিয়ে ফাইনাল অ্যাসেসমেন্টে NYC হলে শর্তসাপেক্ষে ৫০% ক্যাশব্যাক পাবেন। বিস্তারিত আমাদের Refund Policy পেজে আছে।\"},{\"q\":\"পেমেন্ট করার পর কখন Access পাবো?\",\"a\":\"Online Gateway দিয়ে পেমেন্ট করলে সাথে সাথে। bKash\\/Nagad-এ করলে Admin Verify করার পর — সাধারণত ৩০ মিনিট থেকে কয়েক ঘণ্টার মধ্যে।\"}]', '2026-06-10 07:21:09', '2026-06-10 07:21:09'),
('landing_features', '[{\"title\":\"MCQ Question Bank\",\"desc\":\"CS ভিত্তিক পূর্ণাঙ্গ MCQ সেট — প্রতিটি Unit-এর জন্য\"},{\"title\":\"Written Question Bank\",\"desc\":\"গুরুত্বপূর্ণ লিখিত প্রশ্ন ও সাজেশন\"},{\"title\":\"উত্তর ও ব্যাখ্যা\",\"desc\":\"প্রতিটি প্রশ্নের সঠিক উত্তর ও বিস্তারিত ব্যাখ্যা\"},{\"title\":\"Model Assessment\",\"desc\":\"রিয়েল-টাইম মডেল পরীক্ষা — নিজেকে মূল্যায়ন করুন\"},{\"title\":\"Instant Result\",\"desc\":\"পরীক্ষা শেষে সাথে সাথেই স্বয়ংক্রিয় ফলাফল\"},{\"title\":\"Progress Dashboard\",\"desc\":\"দুর্বলতা চিহ্নিত করুন — উন্নতি ট্র্যাক করুন\"}]', '2026-06-10 07:21:09', '2026-06-10 07:21:09'),
('landing_hero_heading', 'NSDA Assessment Preparation<br><span style=\"color:var(--blue-700);\">এখন আরও সহজ</span>', '2026-06-10 07:21:09', '2026-06-10 07:21:09'),
('landing_hero_image', 'uploads/landing/hero_6a2a3c18b8148.png', '2026-06-10 16:38:03', '2026-06-11 04:39:52'),
('landing_hero_subtext', 'MCQ Question Bank, Written Question, উত্তর, ব্যাখ্যা এবং Model Assessment —<br class=\"hidden sm:block\"> <strong style=\"color:#1e3a5f;\">সব এক জায়গায়।</strong> হাজারো TVET Trainee-র পছন্দের প্ল্যাটফর্ম।', '2026-06-10 07:21:09', '2026-06-10 07:21:09'),
('landing_reviews', '[{\"name\":\"মো. রাহাত হোসেন\",\"role\":\"Level 3 Trainee — Computer Operation\",\"quote\":\"এখানে রেগুলার পরীক্ষা দিয়ে আমার কনফিডেন্স অনেক বেড়েছে। প্রশ্নগুলো সত্যিই স্ট্যান্ডার্ড।\"},{\"name\":\"তাসলিমা বেগম\",\"role\":\"Level 4 Trainee — Graphic Design\",\"quote\":\"ফাইনাল অ্যাসেসমেন্টের আগে মডেল টেস্ট দিয়ে নিজের ভুলগুলো ধরতে পেরেছিলাম। প্রথমবারেই পাস করলাম।\"},{\"name\":\"জুবায়ের আহমেদ\",\"role\":\"Level 3 Trainee — Electrical Installation\",\"quote\":\"লিখিত প্রশ্নের উত্তর ও ব্যাখ্যাগুলো খুব সুন্দর সাজানো। আমি প্রথমবারেই Competent হয়েছি।ok\"}]', '2026-06-10 07:21:09', '2026-06-10 07:21:09'),
