('site_address', 'Dhaka, Bangladesh', '2026-05-18 11:57:42', '2026-05-18 12:53:17'),
('site_email', 'assessmenttvet@gmail.com', '2026-05-18 11:57:42', '2026-06-06 14:10:43'),
('site_faqs', '[{\"section\":\"Home\",\"q\":\"AssessmentBD কী?\",\"a\":\"AssessmentBD হলো NSDA লেভেল অ্যাসেসমেন্ট পরীক্ষার প্রস্তুতির জন্য বাংলাদেশের একটি প্রিমিয়াম অনলাইন প্ল্যাটফর্ম।\"},{\"section\":\"Home\",\"q\":\"আমি কীভাবে পরীক্ষা দেওয়া শুরু করব?\",\"a\":\"প্রথমে একটি ফ্রি অ্যাকাউন্ট তৈরি করুন, এরপর আপনার কাঙ্ক্ষিত Occupation নির্বাচন করে প্যাকেজ সাবস্ক্রাইব করুন।\"},{\"section\":\"Home\",\"q\":\"Basic এবং Pro Plan এর মধ্যে পার্থক্য কী?\",\"a\":\"Basic প্ল্যানে আপনি ১ মাসের অ্যাক্সেস পাবেন, আর Pro প্ল্যানে ৩ মাসের অ্যাক্সেস, এক্সপার্ট সাপোর্ট এবং রিফান্ড পলিসি পাবেন।\"},{\"section\":\"Pricing\",\"q\":\"Assessment-এ NYC (Not Yet Competent) হলে refund কীভাবে পাব?\",\"a\":\"আপনি যদি Pro subscriber হন এবং আমাদের মডেল টেস্টগুলোতে পাস করার পরও মূল পরীক্ষায় NYC হন, তাহলে অফিসিয়াল রেজাল্ট শিট দেখালে আমরা ৫০% রিফান্ড করে দেব।\"},{\"section\":\"Pricing\",\"q\":\"পেমেন্ট কীভাবে করব?\",\"a\":\"আপনি বিকাশ, নগদ অথবা যেকোনো মোবাইল ব্যাংকিং এর মাধ্যমে খুব সহজেই পেমেন্ট করতে পারবেন।\"},{\"section\":\"Pricing\",\"q\":\"এক সাবস্ক্রিপশনে কি সব কোর্সের অ্যাক্সেস পাব?\",\"a\":\"না, আপনাকে আপনার নির্দিষ্ট Occupation বা কোর্সের জন্য আলাদাভাবে সাবস্ক্রাইব করতে হবে।\"},{\"section\":\"About\",\"q\":\"AssessmentBD কি NSDA-এর অফিসিয়াল সাইট?\",\"a\":\"না। AssessmentBD সম্পূর্ণ একটি বেসরকারি শিক্ষামূলক প্ল্যাটফর্ম এবং NSDA বা বাংলাদেশ কারিগরি শিক্ষা বোর্ডের সাথে সরাসরি অধিভুক্ত নয়। আমরা শুধু প্রস্তুতিতে সাহায্য করি।\"},{\"section\":\"About\",\"q\":\"কোর্সের মেয়াদ কতদিন থাকে?\",\"a\":\"আপনার কেনা প্যাকেজের ওপর ভিত্তি করে মেয়াদ ১ থেকে ৩ মাস পর্যন্ত হতে পারে।\"},{\"section\":\"About\",\"q\":\"আমি কি মোবাইল থেকে পরীক্ষা দিতে পারব?\",\"a\":\"হ্যাঁ! আমাদের প্ল্যাটফর্মটি ১০০% মোবাইল-বান্ধব, আপনি যেকোনো ডিভাইস (মোবাইল, ট্যাবলেট বা পিসি) থেকে খুব সহজেই পরীক্ষা দিতে পারবেন।\"}]', '2026-05-22 19:51:50', '2026-05-23 20:53:37'),
